def _bench_p27_orogenic_foreland_response_state() -> dict[str, Any]:
    grid = SphereGrid.fibonacci(2400, 6.371e6)
    spec = get_preset("earthlike")
    spec.grid_cells = grid.n
    world = WorldState(grid=grid, spec=spec, time_myr=4500.0)
    world.set_g("ocean.sea_level_m", 0.0)

    continent = (np.abs(grid.lat) < 36.0) & (grid.lon > -110.0) & (grid.lon < 110.0)
    collision_core = continent & (np.abs(grid.lon) < 7.0) & (np.abs(grid.lat) < 26.0)
    collision_shoulder = (
        continent
        & ~collision_core
        & (np.abs(grid.lon) < 15.0)
        & (np.abs(grid.lat) < 29.0)
    )
    foreland = continent & (grid.lon > 18.0) & (grid.lon < 56.0) & (np.abs(grid.lat) < 26.0)
    distal_platform = (
        continent
        & (grid.lon > 68.0)
        & (grid.lon < 105.0)
        & (np.abs(grid.lat) < 25.0)
    )
    stable_craton = (
        continent
        & (grid.lon < -62.0)
        & (grid.lon > -105.0)
        & (np.abs(grid.lat) < 25.0)
    )

    terrain = TerrainModule()
    ctype = np.where(continent, CONT, OCEAN).astype(np.float64)
    domain = np.where(continent, DOMAIN_CONTINENTAL_INTERIOR, DOMAIN_OCEANIC).astype(np.float64)
    domain[collision_core | collision_shoulder] = DOMAIN_SUTURE
    domain[stable_craton] = DOMAIN_CRATON
    stability = np.where(continent, 0.62, 0.0).astype(np.float64)
    stability[collision_core | collision_shoulder] = 0.34
    stability[foreland] = 0.50
    stability[stable_craton] = 0.90
    surface = np.where(continent, 900.0, -4400.0).astype(np.float64)
    surface[collision_core | collision_shoulder] = 2700.0
    surface[foreland] = 470.0
    surface[distal_platform] = 920.0
    surface[stable_craton] = 620.0
    thick = np.where(continent, CONT_THICK + 4000.0, OCEAN_THICK).astype(np.float64)
    thick[collision_core | collision_shoulder] = CONT_THICK + 15000.0
    thick[foreland] = CONT_THICK - 2500.0
    thick[stable_craton] = CONT_THICK + 2500.0
    orog_age = np.full(grid.n, -1.0, dtype=np.float64)
    orog_age[collision_core | collision_shoulder] = world.time_myr - 80.0
    intensity = np.zeros(grid.n, dtype=np.float64)
    style = np.zeros(grid.n, dtype=np.float64)
    intensity[collision_core] = 1.0
    style[collision_core] = DEFORM_COLLISION_CORE
    intensity[collision_shoulder] = 0.45
    style[collision_shoulder] = DEFORM_COLLISION_SHOULDER
    continent_id = np.full(grid.n, -1.0, dtype=np.float64)
    continent_id[continent] = 0.0

    world.set_field("terrain.elevation_m", surface)
    world.set_field("crust.type", ctype)
    world.set_field("crust.domain", domain)
    world.set_field("crust.stability", stability)
    world.set_field("crust.thickness_m", thick)
    world.set_field("crust.age_myr", np.where(continent, 1200.0, 80.0))
    world.set_field("tectonics.orogeny_age_myr", orog_age)
    world.set_field("tectonics.deformation_intensity", intensity)
    world.set_field("tectonics.deformation_style", style)
    world.set_field("tectonics.rift_potential", np.zeros(grid.n, dtype=np.float64))
    world.set_field("tectonics.continent_id", continent_id)
    world.objects["tectonics.deforming_networks"] = [
        {
            "id": "deforming_network:p27-collision-core",
            "kind": "collision_core",
            "style_code": int(DEFORM_COLLISION_CORE),
            "cells": np.where(collision_core)[0].astype(int).tolist(),
        },
        {
            "id": "deforming_network:p27-collision-shoulder",
            "kind": "collision_shoulder",
            "style_code": int(DEFORM_COLLISION_SHOULDER),
            "cells": np.where(collision_shoulder)[0].astype(int).tolist(),
        },
    ]
    world.objects["tectonics.sutures"] = [{
        "id": "suture:p27-collision",
        "kind": "collision",
        "cells": np.where(collision_core | collision_shoulder)[0].astype(int).tolist(),
    }]

    state = terrain._orogenic_response_state(
        world, surface, 0.0, ctype, domain, stability, orog_age=orog_age)
    flow = np.where(foreland, 8.0e8, 1.0e7).astype(np.float64)
    sediment = np.where(continent, 240.0, 60.0).astype(np.float64)
    sediment = terrain._regionalize_continental_sediment(
        world, sediment, surface, 0.0, ctype, domain, stability, orog_age, flow)
    detail = terrain._continental_detail_province(
        world, surface, 0.0, ctype, domain, np.zeros(grid.n), stability,
        orog_age=orog_age)
    objects = terrain._continental_landform_objects(
        world, surface, 0.0, ctype, domain, np.zeros(grid.n), stability,
        detail, sediment, orog_age=orog_age)
    foreland_objects = [
        obj for obj in objects
        if obj.get("kind") == "foreland_basin"
        and obj.get("parent_tectonic_object_ids")
    ]

    load = state["orogenic_load"]
    accommodation = state["foreland_accommodation"]
    foreland_detail_fraction = _p26_fraction(
        detail.astype(int) == CONT_DETAIL_BASIN, foreland)
    foreland_object_overlap = 0.0
    if foreland_objects:
        obj_cells = np.asarray(foreland_objects[0].get("cells", []), dtype=int)
        obj_cells = obj_cells[(0 <= obj_cells) & (obj_cells < grid.n)]
        foreland_object_overlap = (
            float(np.mean(foreland[obj_cells])) if obj_cells.size else 0.0
        )

    metrics = {
        "orogen_load_mean": _p26_mean(load[collision_core]),
        "foreland_load_mean": _p26_mean(load[foreland]),
        "distal_load_mean": _p26_mean(load[distal_platform]),
        "foreland_accommodation_mean": _p26_mean(accommodation[foreland]),
        "orogen_accommodation_mean": _p26_mean(accommodation[collision_core]),
        "distal_accommodation_mean": _p26_mean(accommodation[distal_platform]),
        "craton_accommodation_mean": _p26_mean(accommodation[stable_craton]),
        "foreland_basin_detail_fraction": float(foreland_detail_fraction),
        "foreland_basin_objects": int(len(foreland_objects)),
        "foreland_object_overlap_fraction": float(foreland_object_overlap),
        "foreland_mean_sediment_m": _p26_mean(sediment[foreland]),
        "distal_platform_mean_sediment_m": _p26_mean(sediment[distal_platform]),
        "orogen_mean_sediment_m": _p26_mean(sediment[collision_core]),
    }
    passed = (
        collision_core.any()
        and foreland.any()
        and distal_platform.any()
        and stable_craton.any()
        and metrics["orogen_load_mean"] > metrics["foreland_load_mean"] + 0.18
        and metrics["foreland_load_mean"] > metrics["distal_load_mean"] + 0.12
        and metrics["foreland_accommodation_mean"] > metrics["orogen_accommodation_mean"] + 0.08
        and metrics["foreland_accommodation_mean"] > metrics["distal_accommodation_mean"] + 0.08
        and metrics["foreland_accommodation_mean"] > metrics["craton_accommodation_mean"] + 0.08
        and metrics["foreland_basin_detail_fraction"] >= 0.35
        and metrics["foreland_basin_objects"] >= 1
        and metrics["foreland_object_overlap_fraction"] >= 0.20
        and metrics["foreland_mean_sediment_m"] > metrics["distal_platform_mean_sediment_m"] + 350.0
        and metrics["foreland_mean_sediment_m"] > metrics["orogen_mean_sediment_m"] + 450.0
    )
    return _result(
        "P27.orogenic_foreland_response_state",
        passed,
        metrics,
        "orogenic terrain response is not separating load-bearing mountain belts from adjacent flexural foreland depocenters",
    )


def run_p27_bench(root: Path = PROJECT_ROOT) -> dict[str, Any]:
    del root
    benchmarks = [_bench_p27_orogenic_foreland_response_state()]
    passed = all(b["passed"] for b in benchmarks)
    digest = _canonical_digest(benchmarks)
    return {
        "schema": "aevum.tectonics_bench.p27.v1",
        "suite": "P27",
        "status": "pass" if passed else "fail",
        "benchmarks": benchmarks,
        "determinism": {
            "summary_digest": digest,
            "passed": _canonical_digest(benchmarks) == digest,
        },
        "acceptance": {
            "all_microbenchmarks_pass": passed,
            "orogenic_foreland_response_state_available": benchmarks[0]["passed"],
        },
    }


def _p28_sediment_coupling_candidate(
    world: WorldState,
    surface: np.ndarray,
    sea_level: float,
    crust_type: np.ndarray,
    crust_domain: np.ndarray,
    crust_stability: np.ndarray,
    sediment: np.ndarray,
    orog_age: np.ndarray,
    flow_accumulation: np.ndarray,
) -> tuple[np.ndarray, dict[str, np.ndarray]]:
    """Diagnostic sediment transfer candidate for P28 gates.

    This is intentionally not used by production terrain.  It establishes the
    constraints a future production coupling must satisfy: sediment moves from
    bypass/source areas into foreland/passive-margin accommodation while
    preserving total sediment volume.
    """
    terrain = TerrainModule()
    grid = world.grid
    out = np.asarray(sediment, dtype=np.float64).copy()
    cont = np.asarray(crust_type, dtype=np.float64) == CONT
    if not cont.any():
        return out, {
            "accommodation": np.zeros(grid.n, dtype=np.float64),
            "source": np.zeros(grid.n, dtype=np.float64),
        }

    rel = np.asarray(surface, dtype=np.float64) - float(sea_level)
    response = terrain._orogenic_response_state(
        world, surface, sea_level, crust_type, crust_domain,
        crust_stability, orog_age=orog_age)
    passive_source = terrain._tectonic_process_mask(world, "passive_margin")
    passive_influence = terrain._band_influence(grid, passive_source, passes=5)
    margin = cont & (
        (crust_domain == DOMAIN_CONTINENTAL_MARGIN)
        | (passive_influence >= 0.22)
    )

    cont_rel = rel[cont]
    low_cut = max(250.0, float(np.percentile(cont_rel, 30)))
    high_cut = max(low_cut + 650.0, float(np.percentile(cont_rel, 70)))
    lowland = np.clip((high_cut - rel) / max(high_cut - low_cut, 1.0), 0.0, 1.0)
    passive_accommodation = (
        passive_influence
        * lowland
        * margin.astype(np.float64)
        * np.clip((0.96 - crust_stability) / 0.76, 0.0, 1.0)
    )
    accommodation = np.maximum(
        response["foreland_accommodation"],
        passive_accommodation,
    )

    accum = np.nan_to_num(
        np.asarray(flow_accumulation, dtype=np.float64),
        nan=0.0, posinf=0.0, neginf=0.0)
    if np.any(cont & (accum > 0.0)):
        log_acc = np.log1p(np.maximum(accum, 0.0))
        lo = float(np.percentile(log_acc[cont], 45))
        hi = max(lo + 1e-9, float(np.percentile(log_acc[cont], 95)))
        drainage = np.clip((log_acc - lo) / max(hi - lo, 1e-9), 0.0, 1.0)
    else:
        drainage = np.zeros(grid.n, dtype=np.float64)
    accommodation = np.clip(accommodation * (0.72 + 0.28 * drainage), 0.0, 1.0)

    bypass_relief = np.clip(
        (rel - low_cut) / max(high_cut - low_cut, 1.0), 0.0, 1.0)
    stable_high = (
        cont
        & (
            (bypass_relief > 0.25)
            | (crust_domain == DOMAIN_CRATON)
            | (response["orogen_core"] & (rel > 1200.0))
        )
    )
    source = np.clip(
        stable_high.astype(np.float64)
        * (0.35 + 0.65 * bypass_relief),
        0.0,
        1.0,
    )
    source[accommodation > 0.20] = 0.0

    area = grid.cell_area
    source_capacity = np.maximum(out - 160.0, 0.0) * source
    sediment_headroom = np.maximum(3000.0 - out, 0.0)
    submerged_headroom = np.where(
        rel < 0.0,
        np.maximum((-rel - 20.0) / 0.08, 0.0),
        sediment_headroom,
    )
    sink_capacity = np.minimum(sediment_headroom, submerged_headroom) * accommodation
    source_volume = source_capacity * area
    sink_volume = sink_capacity * area
    movable = min(float(source_volume.sum()) * 0.78, float(sink_volume.sum()))
    if movable <= 0.0:
        return out, {
            "accommodation": accommodation,
            "source": source,
        }

    remove_volume = movable * source_volume / max(float(source_volume.sum()), 1.0)
    add_volume = movable * sink_volume / max(float(sink_volume.sum()), 1.0)
    out -= remove_volume / area
    out += add_volume / area
    out[cont] = np.clip(out[cont], 40.0, 3800.0)
    out[~cont] = sediment[~cont]
    return out, {
        "accommodation": accommodation,
        "source": source,
        "passive_accommodation": passive_accommodation,
        "foreland_accommodation": response["foreland_accommodation"],
    }


def _p28_volume_change_fraction(
    grid: SphereGrid, before: np.ndarray, after: np.ndarray, mask: np.ndarray
) -> float:
    before_volume = float(np.sum(before[mask] * grid.cell_area[mask]))
    after_volume = float(np.sum(after[mask] * grid.cell_area[mask]))
    return abs(after_volume - before_volume) / max(abs(before_volume), 1.0)


def _p28_projected_land_change_fraction(
    grid: SphereGrid, surface: np.ndarray, sea_level: float,
    before_sediment: np.ndarray, after_sediment: np.ndarray,
) -> float:
    before_land = np.asarray(surface, dtype=np.float64) >= float(sea_level)
    projected = np.asarray(surface, dtype=np.float64) + 0.08 * (
        np.asarray(after_sediment, dtype=np.float64)
        - np.asarray(before_sediment, dtype=np.float64)
    )
    after_land = projected >= float(sea_level)
    changed = before_land != after_land
    return float(grid.cell_area[changed].sum() / max(float(grid.cell_area.sum()), 1.0))


def _bench_p28_foreland_sediment_coupling_gate() -> dict[str, Any]:
    grid = SphereGrid.fibonacci(2200, 6.371e6)
    spec = get_preset("earthlike")
    spec.grid_cells = grid.n
    world = WorldState(grid=grid, spec=spec, time_myr=4500.0)
    continent = (np.abs(grid.lat) < 38.0) & (grid.lon > -115.0) & (grid.lon < 112.0)
    orogen = continent & (np.abs(grid.lon) < 8.0) & (np.abs(grid.lat) < 28.0)
    shoulder = continent & ~orogen & (np.abs(grid.lon) < 16.0) & (np.abs(grid.lat) < 30.0)
    foreland = continent & (grid.lon > 20.0) & (grid.lon < 58.0) & (np.abs(grid.lat) < 27.0)
    distal = continent & (grid.lon > 70.0) & (grid.lon < 105.0) & (np.abs(grid.lat) < 26.0)
    craton = continent & (grid.lon < -65.0) & (grid.lon > -105.0) & (np.abs(grid.lat) < 24.0)

    ctype = np.where(continent, CONT, OCEAN).astype(np.float64)
    domain = np.where(continent, DOMAIN_CONTINENTAL_INTERIOR, DOMAIN_OCEANIC).astype(np.float64)
    domain[orogen | shoulder] = DOMAIN_SUTURE
    domain[craton] = DOMAIN_CRATON
    stability = np.where(continent, 0.62, 0.0).astype(np.float64)
    stability[orogen | shoulder] = 0.34
    stability[foreland] = 0.50
    stability[craton] = 0.90
    surface = np.where(continent, 920.0, -4300.0).astype(np.float64)
    surface[orogen | shoulder] = 2650.0
    surface[foreland] = 430.0
    surface[distal] = 980.0
    surface[craton] = 760.0
    orog_age = np.full(grid.n, -1.0, dtype=np.float64)
    orog_age[orogen | shoulder] = world.time_myr - 80.0
    intensity = np.zeros(grid.n, dtype=np.float64)
    style = np.zeros(grid.n, dtype=np.float64)
    intensity[orogen] = 1.0
    style[orogen] = DEFORM_COLLISION_CORE
    intensity[shoulder] = 0.45
    style[shoulder] = DEFORM_COLLISION_SHOULDER
    sediment = np.where(continent, 780.0, 60.0).astype(np.float64)
    sediment[foreland] = 150.0
    sediment[orogen | shoulder] = 1120.0
    sediment[craton] = 1040.0
    flow = np.where(foreland, 9.0e8, 2.0e7).astype(np.float64)

    world.set_field("tectonics.deformation_intensity", intensity)
    world.set_field("tectonics.deformation_style", style)
    world.set_field("tectonics.orogeny_age_myr", orog_age)
    world.objects["tectonics.deforming_networks"] = [
        {"id": "deforming_network:p28-foreland-core", "kind": "collision_core",
         "style_code": int(DEFORM_COLLISION_CORE), "cells": np.where(orogen)[0].tolist()},
        {"id": "deforming_network:p28-foreland-shoulder", "kind": "collision_shoulder",
         "style_code": int(DEFORM_COLLISION_SHOULDER), "cells": np.where(shoulder)[0].tolist()},
    ]
    candidate, fields = _p28_sediment_coupling_candidate(
        world, surface, 0.0, ctype, domain, stability, sediment, orog_age, flow)
    delta = candidate - sediment
    volume_change = _p28_volume_change_fraction(grid, sediment, candidate, continent)
    land_change = _p28_projected_land_change_fraction(
        grid, surface, 0.0, sediment, candidate)
    metrics = {
        "foreland_delta_mean_m": _p26_mean(delta[foreland]),
        "orogen_delta_mean_m": _p26_mean(delta[orogen]),
        "distal_delta_mean_m": _p26_mean(delta[distal]),
        "craton_delta_mean_m": _p26_mean(delta[craton]),
        "foreland_accommodation_mean": _p26_mean(fields["foreland_accommodation"][foreland]),
        "distal_accommodation_mean": _p26_mean(fields["accommodation"][distal]),
        "volume_change_fraction": float(volume_change),
        "projected_land_change_fraction": float(land_change),
    }
    passed = (
        metrics["foreland_delta_mean_m"] > 250.0
        and metrics["orogen_delta_mean_m"] < -80.0
        and metrics["foreland_delta_mean_m"] > metrics["distal_delta_mean_m"] + 240.0
        and metrics["foreland_delta_mean_m"] > metrics["craton_delta_mean_m"] + 240.0
        and metrics["foreland_accommodation_mean"] > metrics["distal_accommodation_mean"] + 0.08
        and metrics["volume_change_fraction"] < 0.002
        and metrics["projected_land_change_fraction"] < 0.01
    )
    return _result(
        "P28.foreland_sediment_budget_gate",
        passed,
        metrics,
        "foreland sediment coupling does not preserve mass or localize deposition to orogenic flexural accommodation",
    )


def _bench_p28_passive_margin_sediment_coupling_gate() -> dict[str, Any]:
    grid = SphereGrid.fibonacci(2200, 6.371e6)
    spec = get_preset("earthlike")
    spec.grid_cells = grid.n
    world = WorldState(grid=grid, spec=spec, time_myr=4500.0)
    continent = (np.abs(grid.lat) < 34.0) & (grid.lon > -120.0) & (grid.lon < 50.0)
    margin = continent & (grid.lon > 28.0) & (grid.lon < 50.0) & (np.abs(grid.lat) < 32.0)
    shelf = margin & (grid.lon > 38.0)
    interior = continent & (grid.lon < -15.0) & (grid.lon > -88.0) & (np.abs(grid.lat) < 27.0)
    craton = continent & (grid.lon < -82.0) & (np.abs(grid.lat) < 22.0)

    ctype = np.where(continent, CONT, OCEAN).astype(np.float64)
    domain = np.where(continent, DOMAIN_CONTINENTAL_INTERIOR, DOMAIN_OCEANIC).astype(np.float64)
    domain[margin] = DOMAIN_CONTINENTAL_MARGIN
    domain[craton] = DOMAIN_CRATON
    stability = np.where(continent, 0.64, 0.0).astype(np.float64)
    stability[margin] = 0.42
    stability[craton] = 0.90
    surface = np.where(continent, 820.0, -4200.0).astype(np.float64)
    surface[margin] = 260.0
    surface[shelf] = -120.0
    surface[interior] = 1320.0
    surface[craton] = 740.0
    sediment = np.where(continent, 1040.0, 60.0).astype(np.float64)
    sediment[margin] = 150.0
    sediment[shelf] = 110.0
    sediment[craton] = 1160.0
    orog_age = np.full(grid.n, -1.0, dtype=np.float64)
    flow = np.where(margin, 8.0e8, 2.5e8).astype(np.float64)
    world.objects["tectonics.passive_margins"] = [{
        "id": "passive_margin:p28-fixture",
        "kind": "passive_margin",
        "cells": np.where(margin)[0].astype(int).tolist(),
    }]

    candidate, fields = _p28_sediment_coupling_candidate(
        world, surface, 0.0, ctype, domain, stability, sediment, orog_age, flow)
    delta = candidate - sediment
    volume_change = _p28_volume_change_fraction(grid, sediment, candidate, continent)
    land_change = _p28_projected_land_change_fraction(
        grid, surface, 0.0, sediment, candidate)
    metrics = {
        "margin_delta_mean_m": _p26_mean(delta[margin]),
        "shelf_delta_mean_m": _p26_mean(delta[shelf]),
        "interior_delta_mean_m": _p26_mean(delta[interior]),
        "craton_delta_mean_m": _p26_mean(delta[craton]),
        "passive_accommodation_mean": _p26_mean(fields["passive_accommodation"][margin]),
        "interior_accommodation_mean": _p26_mean(fields["accommodation"][interior]),
        "volume_change_fraction": float(volume_change),
        "projected_land_change_fraction": float(land_change),
    }
    passed = (
        metrics["margin_delta_mean_m"] > 240.0
        and metrics["shelf_delta_mean_m"] > 180.0
        and metrics["interior_delta_mean_m"] < -40.0
        and metrics["craton_delta_mean_m"] < -40.0
        and metrics["passive_accommodation_mean"] > metrics["interior_accommodation_mean"] + 0.20
        and metrics["volume_change_fraction"] < 0.002
        and metrics["projected_land_change_fraction"] < 0.012
    )
    return _result(
        "P28.passive_margin_sediment_budget_gate",
        passed,
        metrics,
        "passive-margin sediment coupling does not preserve mass or build a localized margin/shelf wedge",
    )


def run_p28_bench(root: Path = PROJECT_ROOT) -> dict[str, Any]:
    del root
    benchmarks = [
        _bench_p28_foreland_sediment_coupling_gate(),
        _bench_p28_passive_margin_sediment_coupling_gate(),
    ]
    passed = all(b["passed"] for b in benchmarks)
    digest = _canonical_digest(benchmarks)
    return {
        "schema": "aevum.tectonics_bench.p28.v1",
        "suite": "P28",
        "status": "pass" if passed else "fail",
        "benchmarks": benchmarks,
        "determinism": {
            "summary_digest": digest,
            "passed": _canonical_digest(benchmarks) == digest,
        },
        "acceptance": {
            "all_microbenchmarks_pass": passed,
            "sediment_coupling_budget_gate_available": passed,
        },
    }


def _p29_inland_complexity_metrics(
    grid: SphereGrid,
    surface: np.ndarray,
    sea_level: float,
    continent: np.ndarray,
    detail: np.ndarray,
    objects: list[dict],
) -> dict[str, Any]:
    rel = np.asarray(surface, dtype=np.float64) - float(sea_level)
    continent = np.asarray(continent, dtype=bool)
    widths = TerrainModule()._mask_width_steps(grid, continent)
    inland = continent & (widths >= 3.0)
    if not inland.any():
        inland = continent
    obj_kinds = {
        str(obj.get("kind"))
        for obj in objects
        if obj.get("kind") and float(obj.get("area_fraction", 0.0)) > 0.0
    }
    detail_int = np.asarray(detail, dtype=np.float64).astype(int)
    inland_rel = rel[inland]
    relief_p90_p10 = (
        float(np.percentile(inland_rel, 90) - np.percentile(inland_rel, 10))
        if inland_rel.size else 0.0
    )
    relief_p95_p05 = (
        float(np.percentile(inland_rel, 95) - np.percentile(inland_rel, 5))
        if inland_rel.size else 0.0
    )
    relief_iqr = (
        float(np.percentile(inland_rel, 75) - np.percentile(inland_rel, 25))
        if inland_rel.size else 0.0
    )
    flat_lowland_fraction = (
        float(np.mean((inland_rel >= 100.0) & (inland_rel <= 1050.0)))
        if inland_rel.size else 0.0
    )
    highland_fraction = (
        float(np.mean(inland_rel >= 1600.0)) if inland_rel.size else 0.0
    )
    detail_diversity = int(np.unique(detail_int[inland]).size) if inland.any() else 0
    parented_kinds = {
        str(obj.get("kind"))
        for obj in objects
        if obj.get("kind") and obj.get("parent_tectonic_object_ids")
    }
    return {
        "inland_cell_count": int(inland.sum()),
        "inland_relief_p95_p05_m": relief_p95_p05,
        "inland_relief_p90_p10_m": relief_p90_p10,
        "inland_relief_iqr_m": relief_iqr,
        "inland_flat_lowland_fraction": flat_lowland_fraction,
        "inland_highland_fraction": highland_fraction,
        "inland_detail_diversity": detail_diversity,
        "object_kind_count": int(len(obj_kinds)),
        "object_kinds": sorted(obj_kinds),
        "shield_objects": int(sum(obj.get("kind") == "shield" for obj in objects)),
        "platform_objects": int(sum(obj.get("kind") == "platform" for obj in objects)),
        "interior_basin_objects": int(sum(obj.get("kind") == "interior_basin" for obj in objects)),
        "old_subdued_orogen_objects": int(sum(obj.get("kind") == "old_subdued_orogen" for obj in objects)),
        "rift_basin_objects": int(sum(obj.get("kind") == "rift_basin" for obj in objects)),
        "plateau_objects": int(sum(obj.get("kind") == "plateau" for obj in objects)),
        "parented_object_kind_count": int(len(parented_kinds)),
        "parented_object_kinds": sorted(parented_kinds),
        "parented_shield_objects": int(sum(
            obj.get("kind") == "shield"
            and bool(obj.get("parent_tectonic_object_ids"))
            for obj in objects)),
        "parented_old_subdued_orogen_objects": int(sum(
            obj.get("kind") == "old_subdued_orogen"
            and bool(obj.get("parent_tectonic_object_ids")) for obj in objects)),
        "parented_rift_basin_objects": int(sum(
            obj.get("kind") == "rift_basin"
            and bool(obj.get("parent_tectonic_object_ids"))
            for obj in objects)),
        "parented_plateau_objects": int(sum(
            obj.get("kind") == "plateau"
            and bool(obj.get("parent_tectonic_object_ids"))
            for obj in objects)),
    }


def _bench_p29_inland_mechanism_diversity_fixture() -> dict[str, Any]:
    grid = SphereGrid.fibonacci(3200, 6.371e6)
    spec = get_preset("earthlike")
    spec.grid_cells = grid.n
    world = WorldState(grid=grid, spec=spec, time_myr=4500.0)
    terrain = TerrainModule()

    continent = (np.abs(grid.lat) < 48.0) & (grid.lon > -135.0) & (grid.lon < 135.0)
    shield = _cap_mask(grid, 12.0, -82.0, 22.0) & continent
    interior_basin = _cap_mask(grid, -15.0, -28.0, 21.0) & continent
    old_orogen = (
        continent
        & (grid.lon > 18.0)
        & (grid.lon < 40.0)
        & (np.abs(grid.lat) < 34.0)
    )
    rift_belt = (
        continent
        & (grid.lon > 78.0)
        & (grid.lon < 91.0)
        & (np.abs(grid.lat) < 34.0)
    )
    plateau = _cap_mask(grid, 18.0, 58.0, 18.0) & continent

    ctype = np.where(continent, CONT, OCEAN).astype(np.float64)
    domain = np.where(continent, DOMAIN_CONTINENTAL_INTERIOR, DOMAIN_OCEANIC).astype(np.float64)
    domain[shield] = DOMAIN_CRATON
    domain[old_orogen] = DOMAIN_SUTURE
    domain[rift_belt] = DOMAIN_CONTINENTAL_MARGIN
    domain[plateau] = DOMAIN_LIP
    stability = np.where(continent, 0.66, 0.0).astype(np.float64)
    stability[shield] = 0.92
    stability[interior_basin] = 0.48
    stability[old_orogen] = 0.44
    stability[rift_belt] = 0.32
    stability[plateau] = 0.56
    age = np.where(continent, 1500.0, 80.0).astype(np.float64)
    age[shield] = 2700.0
    thick = np.where(continent, CONT_THICK + 3500.0, OCEAN_THICK).astype(np.float64)
    thick[interior_basin] = CONT_THICK - 4500.0
    thick[old_orogen] = CONT_THICK + 8500.0
    thick[plateau] = CONT_THICK + 17000.0
    surface = np.where(continent, 820.0, -4300.0).astype(np.float64)
    surface[shield] = 520.0
    surface[interior_basin] = 230.0
    surface[old_orogen] = 1320.0
    surface[rift_belt] = 360.0
    surface[plateau] = 2650.0
    sediment = np.where(continent, 520.0, 60.0).astype(np.float64)
    sediment[shield] = 180.0
    sediment[interior_basin] = 2350.0
    sediment[rift_belt] = 1700.0
    sediment[old_orogen] = 430.0
    orog_age = np.full(grid.n, -1.0, dtype=np.float64)
    orog_age[old_orogen] = world.time_myr - 1500.0
    rift_potential = np.zeros(grid.n, dtype=np.float64)
    rift_potential[rift_belt] = 0.88
    continent_id = np.full(grid.n, -1.0, dtype=np.float64)
    continent_id[continent] = 0.0

    world.set_field("crust.type", ctype)
    world.set_field("crust.domain", domain)
    world.set_field("crust.stability", stability)
    world.set_field("crust.age_myr", age)
    world.set_field("crust.thickness_m", thick)
    world.set_field("crust.origin", np.where(continent, ORIGIN_PRIMORDIAL, ORIGIN_RIDGE))
    world.set_field("tectonics.orogeny_age_myr", orog_age)
    world.set_field("tectonics.volcanism_age_myr", np.full(grid.n, -1.0))
    world.set_field("tectonics.rift_potential", rift_potential)
    world.set_field("tectonics.continent_id", continent_id)
    world.objects["tectonics.cratons"] = [
        {"id": "craton:p29-shield", "kind": "craton", "cells": np.where(shield)[0].tolist()}
    ]
    world.objects["tectonics.sutures"] = [
        {"id": "suture:p29-old-orogen", "kind": "collision", "cells": np.where(old_orogen)[0].tolist()}
    ]
    world.objects["tectonics.rift_systems"] = [
        {"id": "rift_system:p29-inland", "kind": "rift_system", "cells": np.where(rift_belt)[0].tolist()}
    ]
    world.objects["tectonics.lips"] = [
        {"id": "lip:p29-plateau", "kind": "large_igneous_province", "cells": np.where(plateau)[0].tolist()}
    ]

    detail = terrain._continental_detail_province(
        world, surface, 0.0, ctype, domain, np.zeros(grid.n), stability,
        orog_age=orog_age)
    objects = terrain._continental_landform_objects(
        world, surface, 0.0, ctype, domain, np.zeros(grid.n), stability,
        detail, sediment, orog_age=orog_age)
    metrics = _p29_inland_complexity_metrics(
        grid, surface, 0.0, continent, detail, objects)
    passed = (
        metrics["inland_relief_p95_p05_m"] >= 2200.0
        and metrics["inland_relief_p90_p10_m"] >= 750.0
        and metrics["inland_detail_diversity"] >= 5
        and metrics["object_kind_count"] >= 6
        and metrics["shield_objects"] >= 1
        and metrics["platform_objects"] >= 1
        and metrics["interior_basin_objects"] >= 1
        and metrics["old_subdued_orogen_objects"] >= 1
        and metrics["rift_basin_objects"] >= 1
        and metrics["plateau_objects"] >= 1
        and metrics["parented_shield_objects"] >= 1
        and metrics["parented_old_subdued_orogen_objects"] >= 1
        and metrics["parented_rift_basin_objects"] >= 1
        and metrics["parented_plateau_objects"] >= 1
        and 0.45 <= metrics["inland_flat_lowland_fraction"] <= 0.90
        and 0.03 <= metrics["inland_highland_fraction"] <= 0.24
    )
    return _result(
        "P29.inland_mechanism_diversity_fixture",
        passed,
        metrics,
        "mechanism-defined inland continent lacks shield/platform/basin/old-orogen/rift/plateau diversity without random texture",
    )


def _bench_p29_inland_relief_response_preserves_land_mask() -> dict[str, Any]:
    grid = SphereGrid.fibonacci(3600, 6.371e6)
    spec = get_preset("earthlike")
    spec.grid_cells = grid.n
    world = WorldState(grid=grid, spec=spec, time_myr=4500.0)
    terrain = TerrainModule()

    continent = (np.abs(grid.lat) < 48.0) & (grid.lon > -135.0) & (grid.lon < 135.0)
    shield = _cap_mask(grid, 15.0, -82.0, 22.0) & continent
    interior_basin = _cap_mask(grid, -17.0, -28.0, 20.0) & continent
    old_orogen = (
        continent
        & (grid.lon > 18.0)
        & (grid.lon < 41.0)
        & (np.abs(grid.lat) < 34.0)
    )
    rift_belt = (
        continent
        & (grid.lon > 78.0)
        & (grid.lon < 91.0)
        & (np.abs(grid.lat) < 34.0)
    )
    plateau = _cap_mask(grid, 18.0, 58.0, 18.0) & continent
    named = shield | interior_basin | old_orogen | rift_belt | plateau
    platform = continent & ~named

    ctype = np.where(continent, CONT, OCEAN).astype(np.float64)
    domain = np.where(continent, DOMAIN_CONTINENTAL_INTERIOR, DOMAIN_OCEANIC).astype(np.float64)
    domain[shield] = DOMAIN_CRATON
    domain[old_orogen] = DOMAIN_SUTURE
    domain[rift_belt] = DOMAIN_CONTINENTAL_MARGIN
    domain[plateau] = DOMAIN_LIP
    stability = np.where(continent, 0.68, 0.0).astype(np.float64)
    stability[shield] = 0.93
    stability[interior_basin] = 0.46
    stability[old_orogen] = 0.42
    stability[rift_belt] = 0.30
    stability[plateau] = 0.55
    age = np.where(continent, 1500.0, 80.0).astype(np.float64)
    age[shield] = 2850.0
    thick = np.where(continent, CONT_THICK + 2600.0, OCEAN_THICK).astype(np.float64)
    thick[interior_basin] = CONT_THICK - 5200.0
    thick[old_orogen] = CONT_THICK + 8200.0
    thick[plateau] = CONT_THICK + 16500.0
    origin = np.where(continent, ORIGIN_PRIMORDIAL, ORIGIN_RIDGE).astype(np.float64)
    surface = np.where(continent, 760.0, -4300.0).astype(np.float64)
    surface[shield] = 560.0
    surface[interior_basin] = 430.0
    surface[old_orogen] = 920.0
    surface[rift_belt] = 390.0
    surface[plateau] = 1450.0
    sediment = np.where(continent, 520.0, 60.0).astype(np.float64)
    sediment[interior_basin] = 2300.0
    sediment[rift_belt] = 1700.0
    sediment[old_orogen] = 430.0
    orog_age = np.full(grid.n, -1.0, dtype=np.float64)
    orog_age[old_orogen] = world.time_myr - 1500.0
    rift_potential = np.zeros(grid.n, dtype=np.float64)
    rift_potential[rift_belt] = 0.88

    world.set_field("crust.type", ctype)
    world.set_field("crust.domain", domain)
    world.set_field("crust.stability", stability)
    world.set_field("crust.age_myr", age)
    world.set_field("crust.thickness_m", thick)
    world.set_field("crust.origin", origin)
    world.set_field("tectonics.orogeny_age_myr", orog_age)
    world.set_field("tectonics.volcanism_age_myr", np.full(grid.n, -1.0))
    world.set_field("tectonics.rift_potential", rift_potential)
    world.set_field("tectonics.deformation_intensity", np.zeros(grid.n))
    world.set_field("tectonics.deformation_style", np.zeros(grid.n))
    world.objects["tectonics.cratons"] = [
        {"id": "craton:p29-relief-shield", "kind": "craton",
         "cells": np.where(shield)[0].tolist()}
    ]
    world.objects["tectonics.sutures"] = [
        {"id": "suture:p29-relief-old-orogen", "kind": "collision",
         "cells": np.where(old_orogen)[0].tolist()}
    ]
    world.objects["tectonics.rift_systems"] = [
        {"id": "rift_system:p29-relief-inland", "kind": "rift_system",
         "cells": np.where(rift_belt)[0].tolist()}
    ]
    world.objects["tectonics.lips"] = [
        {"id": "lip:p29-relief-plateau", "kind": "large_igneous_province",
         "cells": np.where(plateau)[0].tolist()}
    ]

    relieved = terrain._constrained_inland_geomorphology_relief(
        world, surface, 0.0, ctype, domain, origin, stability, orog_age)
    delta = relieved - surface
    land_unchanged = bool(np.array_equal(surface >= 0.0, relieved >= 0.0))
    detail_before = terrain._continental_detail_province(
        world, surface, 0.0, ctype, domain, origin, stability, orog_age=orog_age)
    detail_after = terrain._continental_detail_province(
        world, relieved, 0.0, ctype, domain, origin, stability, orog_age=orog_age)
    metrics = {
        "old_orogen_delta_mean_m": _p26_mean(delta[old_orogen]),
        "plateau_delta_mean_m": _p26_mean(delta[plateau]),
        "interior_basin_delta_mean_m": _p26_mean(delta[interior_basin]),
        "rift_basin_delta_mean_m": _p26_mean(delta[rift_belt]),
        "shield_abs_delta_mean_m": _p26_mean(np.abs(delta[shield])),
        "platform_abs_delta_mean_m": _p26_mean(np.abs(delta[platform])),
        "land_mask_unchanged": land_unchanged,
        "minimum_relieved_land_m": (
            float(np.min(relieved[surface >= 0.0])) if (surface >= 0.0).any() else 0.0
        ),
        "inland_relief_area_fraction": float(
            world.g("terrain.last_inland_geomorphology_relief_area_fraction", 0.0)),
        "inland_relief_mean_abs_m": float(
            world.g("terrain.last_inland_geomorphology_relief_mean_abs_m", 0.0)),
        "before_detail_diversity": int(np.unique(detail_before[continent]).size),
        "after_detail_diversity": int(np.unique(detail_after[continent]).size),
    }
    passed = (
        metrics["old_orogen_delta_mean_m"] > 65.0
        and metrics["plateau_delta_mean_m"] > 75.0
        and metrics["interior_basin_delta_mean_m"] < -45.0
        and metrics["rift_basin_delta_mean_m"] < -75.0
        and metrics["shield_abs_delta_mean_m"] < 8.0
        and metrics["platform_abs_delta_mean_m"] < 8.0
        and metrics["land_mask_unchanged"]
        and metrics["minimum_relieved_land_m"] >= 80.0
        and metrics["inland_relief_area_fraction"] > 0.01
        and 60.0 <= metrics["inland_relief_mean_abs_m"] <= 230.0
    )
    return _result(
        "P29.inland_relief_response_preserves_land_mask",
        passed,
        metrics,
        "production inland relief response is not process-localized or changes land/ocean topology",
    )


def _bench_p29_flat_interior_detector() -> dict[str, Any]:
    grid = SphereGrid.fibonacci(2600, 6.371e6)
    spec = get_preset("earthlike")
    spec.grid_cells = grid.n
    world = WorldState(grid=grid, spec=spec, time_myr=4500.0)
    terrain = TerrainModule()
    continent = (np.abs(grid.lat) < 42.0) & (grid.lon > -120.0) & (grid.lon < 120.0)
    ctype = np.where(continent, CONT, OCEAN).astype(np.float64)
    domain = np.where(continent, DOMAIN_CONTINENTAL_INTERIOR, DOMAIN_OCEANIC).astype(np.float64)
    stability = np.where(continent, 0.70, 0.0).astype(np.float64)
    surface = np.where(continent, 720.0, -4300.0).astype(np.float64)
    sediment = np.where(continent, 520.0, 60.0).astype(np.float64)
    orog_age = np.full(grid.n, -1.0, dtype=np.float64)

    world.set_field("crust.type", ctype)
    world.set_field("crust.domain", domain)
    world.set_field("crust.stability", stability)
    world.set_field("crust.age_myr", np.where(continent, 1400.0, 80.0))
    world.set_field("crust.thickness_m", np.where(continent, CONT_THICK + 2500.0, OCEAN_THICK))
    world.set_field("crust.origin", np.where(continent, ORIGIN_PRIMORDIAL, ORIGIN_RIDGE))
    world.set_field("tectonics.orogeny_age_myr", orog_age)
    world.set_field("tectonics.rift_potential", np.zeros(grid.n, dtype=np.float64))
    detail = terrain._continental_detail_province(
        world, surface, 0.0, ctype, domain, np.zeros(grid.n), stability,
        orog_age=orog_age)
    objects = terrain._continental_landform_objects(
        world, surface, 0.0, ctype, domain, np.zeros(grid.n), stability,
        detail, sediment, orog_age=orog_age)
    metrics = _p29_inland_complexity_metrics(
        grid, surface, 0.0, continent, detail, objects)
    flatness_detected = (
        metrics["inland_relief_p90_p10_m"] < 220.0
        and metrics["inland_detail_diversity"] <= 2
        and metrics["object_kind_count"] <= 2
        and metrics["inland_flat_lowland_fraction"] > 0.90
        and metrics["inland_highland_fraction"] < 0.01
    )
    metrics["flatness_detected"] = bool(flatness_detected)
    return _result(
        "P29.flat_interior_detector",
        flatness_detected,
        metrics,
        "diagnostic failed to flag a broad single-elevation continental interior as geomorphologically underexpressed",
    )


def _bench_p29_unparented_speckle_detector() -> dict[str, Any]:
    grid = SphereGrid.fibonacci(2600, 6.371e6)
    spec = get_preset("earthlike")
    spec.grid_cells = grid.n
    world = WorldState(grid=grid, spec=spec, time_myr=4500.0)
    terrain = TerrainModule()
    continent = (np.abs(grid.lat) < 42.0) & (grid.lon > -120.0) & (grid.lon < 120.0)
    speckle_high = continent & ((np.arange(grid.n) % 4) == 0)
    ctype = np.where(continent, CONT, OCEAN).astype(np.float64)
    domain = np.where(continent, DOMAIN_CONTINENTAL_INTERIOR, DOMAIN_OCEANIC).astype(np.float64)
    stability = np.where(continent, 0.70, 0.0).astype(np.float64)
    surface = np.where(continent, 540.0, -4300.0).astype(np.float64)
    surface[speckle_high] = 1820.0
    sediment = np.where(continent, 520.0, 60.0).astype(np.float64)
    orog_age = np.full(grid.n, -1.0, dtype=np.float64)

    world.set_field("crust.type", ctype)
    world.set_field("crust.domain", domain)
    world.set_field("crust.stability", stability)
    world.set_field("crust.age_myr", np.where(continent, 1400.0, 80.0))
    world.set_field("crust.thickness_m", np.where(continent, CONT_THICK + 2500.0, OCEAN_THICK))
    world.set_field("crust.origin", np.where(continent, ORIGIN_PRIMORDIAL, ORIGIN_RIDGE))
    world.set_field("tectonics.orogeny_age_myr", orog_age)
    world.set_field("tectonics.rift_potential", np.zeros(grid.n, dtype=np.float64))
    detail = terrain._continental_detail_province(
        world, surface, 0.0, ctype, domain, np.zeros(grid.n), stability,
        orog_age=orog_age)
    objects = terrain._continental_landform_objects(
        world, surface, 0.0, ctype, domain, np.zeros(grid.n), stability,
        detail, sediment, orog_age=orog_age)
    metrics = _p29_inland_complexity_metrics(
        grid, surface, 0.0, continent, detail, objects)
    comps = terrain._components(grid, speckle_high)
    comp_sizes = np.asarray([comp.size for comp in comps], dtype=np.float64)
    metrics.update({
        "speckle_high_component_count": int(len(comps)),
        "speckle_high_component_median_cells": (
            float(np.median(comp_sizes)) if comp_sizes.size else 0.0
        ),
        "speckle_high_fraction": (
            float(np.mean(speckle_high[continent])) if continent.any() else 0.0
        ),
    })
    speckle_detected = (
        metrics["inland_relief_p90_p10_m"] >= 900.0
        and metrics["parented_object_kind_count"] == 0
        and metrics["object_kind_count"] <= 2
        and metrics["speckle_high_component_count"] >= 80
        and metrics["speckle_high_component_median_cells"] <= 2.0
    )
    metrics["speckle_detected"] = bool(speckle_detected)
    return _result(
        "P29.unparented_speckle_detector",
        speckle_detected,
        metrics,
        "diagnostic failed to flag high-relief inland speckle without tectonic parentage or province-scale mechanism support",
    )


def run_p29_bench(root: Path = PROJECT_ROOT) -> dict[str, Any]:
    del root
    benchmarks = [
        _bench_p29_inland_mechanism_diversity_fixture(),
        _bench_p29_inland_relief_response_preserves_land_mask(),
        _bench_p29_flat_interior_detector(),
        _bench_p29_unparented_speckle_detector(),
    ]
    passed = all(b["passed"] for b in benchmarks)
    digest = _canonical_digest(benchmarks)
    return {
        "schema": "aevum.tectonics_bench.p29.v1",
        "suite": "P29",
        "status": "pass" if passed else "fail",
        "benchmarks": benchmarks,
        "determinism": {
            "summary_digest": digest,
            "passed": _canonical_digest(benchmarks) == digest,
        },
        "acceptance": {
            "all_microbenchmarks_pass": passed,
            "inland_mechanism_diversity_fixture": benchmarks[0]["passed"],
            "inland_relief_response_preserves_land_mask": benchmarks[1]["passed"],
            "flat_interior_detector_available": benchmarks[2]["passed"],
            "unparented_speckle_detector_available": benchmarks[3]["passed"],
        },
    }


def _p31_world_from_land_mask(grid: SphereGrid, land: np.ndarray) -> WorldState:
    spec = get_preset("earthlike")
    spec.grid_cells = grid.n
    world = WorldState(grid=grid, spec=spec, time_myr=4500.0)
    land = np.asarray(land, dtype=bool)
    world.set_g("ocean.sea_level_m", 0.0)
    world.set_field("terrain.elevation_m", np.where(land, 700.0, -4200.0))
    world.set_field("crust.type", np.where(land, CONT, OCEAN).astype(np.float64))
    world.set_field(
        "crust.thickness_m",
        np.where(land, CONT_THICK, OCEAN_THICK).astype(np.float64),
    )
    world.set_field("crust.age_myr", np.where(land, 1600.0, 90.0).astype(np.float64))
    world.set_field("crust.origin", np.where(land, ORIGIN_PRIMORDIAL, ORIGIN_RIDGE))
    world.set_field("crust.stability", np.where(land, 0.62, 0.0).astype(np.float64))
    return world


def _p31_flat_metrics(summary: dict[str, Any]) -> dict[str, Any]:
    out: dict[str, Any] = {
        "status": summary["status"],
        "out_of_envelope_count": len(summary["out_of_envelope"]),
        "out_of_envelope": list(summary["out_of_envelope"]),
        "dominant_gap": (
            summary["dominant_gaps"][0]["metric"]
            if summary["dominant_gaps"] else ""
        ),
        "within_initial_planform_envelope": bool(
            summary["acceptance"]["within_initial_planform_envelope"]
        ),
        "resolution_ladder_declared": bool(
            summary["acceptance"]["resolution_ladder_declared"]
        ),
    }
    for key, metric in summary["metrics"].items():
        out[key] = float(metric["value"])
        out[f"{key}_severity_ratio"] = float(metric["severity_ratio"])
        out[f"{key}_in_envelope"] = bool(metric["in_envelope"])
    flags = summary.get("diagnostic_flags", {})
    for key, value in flags.items():
        out[key] = bool(value)
    supporting = summary.get("supporting_metrics", {})
    for key in (
        "continental_ribbon_fraction_gt_0_5",
        "land_width_p50_steps",
        "land_width_p90_steps",
        "land_narrow_necks_per_1000",
        "continental_width_p50_steps",
        "continental_width_p90_steps",
    ):
        out[key] = float(supporting.get(key, 0.0))
    return out


def _p31_broad_multicontinent_mask(grid: SphereGrid) -> np.ndarray:
    land = np.zeros(grid.n, dtype=bool)
    for lat, lon, radius in (
        (20.0, -115.0, 30.0),
        (-30.0, -75.0, 16.0),
        (18.0, 5.0, 32.0),
        (-25.0, 42.0, 19.0),
        (0.0, 122.0, 23.0),
        (-34.0, 145.0, 14.0),
        (55.0, 85.0, 11.0),
    ):
        land |= _cap_mask(grid, lat, lon, radius)
    return land


def _bench_p31_broad_multicontinent_reference_fixture() -> dict[str, Any]:
    grid = SphereGrid.fibonacci(7200, CONSTANTS.EARTH_RADIUS)
    world = _p31_world_from_land_mask(grid, _p31_broad_multicontinent_mask(grid))
    summary = planform_reference_summary(world)
    metrics = _p31_flat_metrics(summary)
    passed = (
        metrics["within_initial_planform_envelope"]
        and metrics["land_fraction_in_envelope"]
        and metrics["land_component_count_in_envelope"]
        and metrics["largest_land_component_fraction_in_envelope"]
        and metrics["land_ribbon_fraction_gt_0_5_in_envelope"]
        and metrics["land_coastline_complexity_largest_in_envelope"]
        and metrics["resolution_ladder_declared"]
    )
    return _result(
        "P31.broad_multicontinent_planform_reference",
        passed,
        metrics,
        "broad multi-continent Earthlike fixture is misclassified as a ribbon/coastline failure",
    )


def _bench_p31_ribbon_land_detector() -> dict[str, Any]:
    grid = SphereGrid.fibonacci(7200, CONSTANTS.EARTH_RADIUS)
    land = (np.abs(grid.lat) < 4.0) & (grid.lon > -150.0) & (grid.lon < 150.0)
    land |= (np.abs(grid.lat - 18.0) < 3.0) & (grid.lon > -30.0) & (grid.lon < 150.0)
    world = _p31_world_from_land_mask(grid, land)
    summary = planform_reference_summary(world)
    metrics = _p31_flat_metrics(summary)
    passed = (
        metrics["ribbon_outside_initial_reference"]
        and metrics["land_ribbon_fraction_gt_0_5"] > 0.85
        and metrics["land_width_p50_steps"] <= 1.0
        and "land_ribbon_fraction_gt_0_5" in metrics["out_of_envelope"]
    )
    return _result(
        "P31.ribbon_land_planform_detector",
        passed,
        metrics,
        "diagnostic failed to flag a deterministic narrow-ribbon land planform",
    )


def _bench_p31_overcomplex_coastline_detector() -> dict[str, Any]:
    grid = SphereGrid.fibonacci(7200, CONSTANTS.EARTH_RADIUS)
    boundary = (
        24.0
        + 6.0 * np.sin(np.radians((grid.lon + 5.0) * 9.0))
        + 3.0 * np.sin(np.radians(grid.lon * 19.0))
    )
    land = (grid.lon > -95.0) & (grid.lon < 95.0) & (np.abs(grid.lat) < boundary)
    land |= _cap_mask(grid, 2.0, -20.0, 20.0)
    world = _p31_world_from_land_mask(grid, land)
    summary = planform_reference_summary(world)
    metrics = _p31_flat_metrics(summary)
    passed = (
        metrics["coastline_outside_initial_reference"]
        and not metrics["ribbon_outside_initial_reference"]
        and metrics["land_coastline_complexity_largest"] > 11.0
        and metrics["land_ribbon_fraction_gt_0_5"] < 0.35
        and "land_coastline_complexity_largest" in metrics["out_of_envelope"]
    )
    return _result(
        "P31.overcomplex_coastline_planform_detector",
        passed,
        metrics,
        "diagnostic failed to separate jagged coastline excess from pure ribbon land",
    )


def run_p31_bench(root: Path = PROJECT_ROOT) -> dict[str, Any]:
    del root
    benchmarks = [
        _bench_p31_broad_multicontinent_reference_fixture(),
        _bench_p31_ribbon_land_detector(),
        _bench_p31_overcomplex_coastline_detector(),
    ]
    passed = all(b["passed"] for b in benchmarks)
    digest = _canonical_digest(benchmarks)
    return {
        "schema": "aevum.tectonics_bench.p31.v1",
        "suite": "P31",
        "status": "pass" if passed else "fail",
        "benchmarks": benchmarks,
        "determinism": {
            "summary_digest": digest,
            "passed": _canonical_digest(benchmarks) == digest,
        },
        "acceptance": {
            "all_microbenchmarks_pass": passed,
            "planform_reference_gate_available": benchmarks[0]["passed"],
            "ribbon_land_detector_available": benchmarks[1]["passed"],
            "overcomplex_coastline_detector_available": benchmarks[2]["passed"],
            "diagnostic_only": True,
        },
    }


def _p32_jagged_coast_world(*, protected_bay: bool = False) -> tuple[WorldState, np.ndarray]:
    grid = SphereGrid.fibonacci(7200, CONSTANTS.EARTH_RADIUS)
    boundary = (
        24.0
        + 6.5 * np.sin(np.radians((grid.lon + 8.0) * 8.0))
        + 3.5 * np.sin(np.radians((grid.lon - 4.0) * 17.0))
    )
    land = (grid.lon > -100.0) & (grid.lon < 100.0) & (np.abs(grid.lat) < boundary)
    land |= _cap_mask(grid, 4.0, -24.0, 21.0)
    land |= _cap_mask(grid, -8.0, 46.0, 18.0)
    protected = np.zeros(grid.n, dtype=bool)
    if protected_bay:
        protected = _cap_mask(grid, 5.0, 8.0, 5.4)
        land &= ~protected
    world = _p31_world_from_land_mask(grid, land)
    module = TerrainModule()
    land_neighbors = module._same_neighbor_count(grid, land)
    ocean_neighbors = module._same_neighbor_count(grid, ~land)
    coastal_land = land & (ocean_neighbors > 0)
    shelf = module._dilate_mask(grid, land, passes=2) & ~land
    continental_shell = land | shelf | protected

    surface = np.full(grid.n, -4300.0, dtype=np.float64)
    surface[land] = 720.0
    surface[coastal_land] = 540.0
    surface[shelf] = -520.0
    surface[protected] = -360.0
    ctype = np.where(continental_shell, CONT, OCEAN).astype(np.float64)
    domain = np.where(continental_shell, DOMAIN_CONTINENTAL_INTERIOR, DOMAIN_OCEANIC).astype(np.float64)
    domain[shelf] = DOMAIN_CONTINENTAL_MARGIN
    weak_edge = coastal_land & ((land_neighbors <= 3) | (ocean_neighbors >= 3))
    domain[weak_edge] = DOMAIN_SUTURE
    terrane_edge = weak_edge & (grid.lon > 10.0)
    domain[terrane_edge] = DOMAIN_ACCRETED_TERRANE
    stability = np.where(continental_shell, 0.62, 0.0).astype(np.float64)
    stability[weak_edge] = 0.24
    stability[shelf] = 0.34
    origin = np.where(continental_shell, ORIGIN_PRIMORDIAL, ORIGIN_RIDGE).astype(np.float64)
    origin[domain == DOMAIN_SUTURE] = ORIGIN_SUTURE
    origin[domain == DOMAIN_ACCRETED_TERRANE] = ORIGIN_ARC
    thick = np.where(continental_shell, CONT_THICK, OCEAN_THICK).astype(np.float64)
    age = np.where(continental_shell, 1400.0, 90.0).astype(np.float64)

    world.set_field("terrain.elevation_m", surface)
    world.set_field("crust.type", ctype)
    world.set_field("crust.domain", domain)
    world.set_field("crust.origin", origin)
    world.set_field("crust.stability", stability)
    world.set_field("crust.thickness_m", thick)
    world.set_field("crust.age_myr", age)
    if protected_bay:
        world.objects["terrain.breakup_seaway_opened_corridors"] = [{
            "object_id": "p32:protected_bay",
            "cells": np.where(protected)[0].astype(int).tolist(),
            "cell_count": int(protected.sum()),
            "area_fraction": float(grid.cell_area[protected].sum() / grid.cell_area.sum()),
        }]
    return world, protected


def _p32_apply(world: WorldState) -> tuple[dict[str, Any], dict[str, Any], np.ndarray]:
    module = TerrainModule()
    before = planform_reference_summary(world)
    surface = module._simplify_modern_coastline_planform(
        world,
        world.field("terrain.elevation_m"),
        0.0,
        world.field("crust.type"),
        world.field("crust.domain"),
        world.field("crust.stability"),
    )
    world.set_field("terrain.elevation_m", surface)
    after = planform_reference_summary(world)
    return before, after, surface


def _bench_p32_coastline_simplification_fixture() -> dict[str, Any]:
    world, _ = _p32_jagged_coast_world()
    before, after, surface = _p32_apply(world)
    before_metrics = _p31_flat_metrics(before)
    after_metrics = _p31_flat_metrics(after)
    complexity_delta = (
        before_metrics["land_coastline_complexity_largest"]
        - after_metrics["land_coastline_complexity_largest"]
    )
    land_delta = abs(after_metrics["land_fraction"] - before_metrics["land_fraction"])
    passed = (
        before_metrics["coastline_outside_initial_reference"]
        and complexity_delta >= 0.35
        and land_delta <= 0.003
        and after_metrics["land_component_count"] <= before_metrics["land_component_count"] + 1
        and float(world.g("terrain.last_p32_coastline_swap_area_fraction", 0.0)) > 0.00025
    )
    return _result(
        "P32.object_constrained_coastline_simplification",
        passed,
        {
            "before_coastline_complexity_largest": before_metrics["land_coastline_complexity_largest"],
            "after_coastline_complexity_largest": after_metrics["land_coastline_complexity_largest"],
            "coastline_complexity_delta": complexity_delta,
            "before_land_fraction": before_metrics["land_fraction"],
            "after_land_fraction": after_metrics["land_fraction"],
            "land_fraction_delta": land_delta,
            "before_component_count": before_metrics["land_component_count"],
            "after_component_count": after_metrics["land_component_count"],
            "p32_swap_area_fraction": float(world.g("terrain.last_p32_coastline_swap_area_fraction", 0.0)),
            "p32_drowned_cells": float(world.g("terrain.last_p32_coastline_drowned_cells", 0.0)),
            "p32_filled_cells": float(world.g("terrain.last_p32_coastline_filled_cells", 0.0)),
            "surface_min_m": float(surface.min()),
            "surface_max_m": float(surface.max()),
        },
        "P32 coastline simplification failed to reduce jagged largest-component coastline while conserving land area",
    )


def _bench_p32_protected_seaway_preserved() -> dict[str, Any]:
    world, protected = _p32_jagged_coast_world(protected_bay=True)
    before, after, surface = _p32_apply(world)
    before_metrics = _p31_flat_metrics(before)
    after_metrics = _p31_flat_metrics(after)
    protected_still_ocean = bool(np.all(surface[protected] < 0.0)) if protected.any() else False
    complexity_delta = (
        before_metrics["land_coastline_complexity_largest"]
        - after_metrics["land_coastline_complexity_largest"]
    )
    passed = (
        protected_still_ocean
        and float(world.g("terrain.last_p32_coastline_swap_area_fraction", 0.0)) > 0.00025
        and complexity_delta >= 0.35
        and abs(after_metrics["land_fraction"] - before_metrics["land_fraction"]) <= 0.003
    )
    return _result(
        "P32.protected_breakup_seaway_not_refilled",
        passed,
        {
            "protected_cell_count": int(protected.sum()),
            "protected_still_ocean": protected_still_ocean,
            "before_coastline_complexity_largest": before_metrics["land_coastline_complexity_largest"],
            "after_coastline_complexity_largest": after_metrics["land_coastline_complexity_largest"],
            "coastline_complexity_delta": complexity_delta,
            "before_land_fraction": before_metrics["land_fraction"],
            "after_land_fraction": after_metrics["land_fraction"],
            "p32_swap_area_fraction": float(world.g("terrain.last_p32_coastline_swap_area_fraction", 0.0)),
        },
        "P32 coastline simplification filled a protected object-backed seaway or failed to act",
    )


def _p32_planform_metrics(grid: SphereGrid, surface: np.ndarray,
                          sea_level: float = 0.0) -> dict[str, float]:
    morphology = analyze_mask_morphology(
        grid, np.asarray(surface, dtype=np.float64) >= float(sea_level),
        name="exposed_land",
    ).metrics
    return {
        "land_fraction": float(morphology["mask_area_fraction_of_total"]),
        "land_component_count": float(morphology["component_count"]),
        "largest_land_component_fraction": float(
            morphology["largest_component_area_fraction_of_mask"]
        ),
        "land_ribbon_fraction_gt_0_5": float(
            morphology["ribbon_area_fraction_gt_0_5"]
        ),
        "land_coastline_complexity_largest": float(
            morphology["coastline_complexity_largest_component"]
        ),
        "land_width_p50_steps": float(morphology["width_p50_steps"]),
        "land_width_p90_steps": float(morphology["width_p90_steps"]),
    }


def _p32_overcomplex_coastline_fixture() -> tuple[
    WorldState,
    np.ndarray,
    np.ndarray,
    np.ndarray,
    np.ndarray,
    np.ndarray,
]:
    grid = SphereGrid.fibonacci(7200, CONSTANTS.EARTH_RADIUS)
    spec = get_preset("earthlike")
    spec.grid_cells = grid.n
    world = WorldState(grid=grid, spec=spec, time_myr=4500.0)
    terrain = TerrainModule()

    core = (
        (grid.lon > -92.0)
        & (grid.lon < 92.0)
        & (np.abs(grid.lat) < 22.0)
    )
    coastline = (
        28.0
        + 14.0 * np.sin(np.radians((grid.lon + 5.0) * 9.0))
        + 3.0 * np.sin(np.radians(grid.lon * 19.0))
    )
    protected_seaway = (np.abs(grid.lon) < 3.2) & (np.abs(grid.lat) < 32.0)
    jagged_land = (
        (grid.lon > -95.0)
        & (grid.lon < 95.0)
        & (np.abs(grid.lat) < coastline)
    )
    land = (core | jagged_land) & ~protected_seaway
    continental = terrain._dilate_mask(grid, land, passes=2) & ~protected_seaway

    ctype = np.where(continental, CONT, OCEAN).astype(np.float64)
    width = terrain._mask_width_steps(grid, continental)
    domain = np.where(
        continental, DOMAIN_CONTINENTAL_INTERIOR, DOMAIN_OCEANIC,
    ).astype(np.float64)
    domain[continental & (width <= 2.0)] = DOMAIN_CONTINENTAL_MARGIN
    domain[continental & (width >= 5.0)] = DOMAIN_CRATON
    land_width = terrain._mask_width_steps(grid, land)
    weak_edge = land & (land_width <= 3.0) & (domain != DOMAIN_CRATON)
    domain[weak_edge] = DOMAIN_ACCRETED_TERRANE

    stability = np.where(continental, 0.58, 0.0).astype(np.float64)
    stability[domain == DOMAIN_CRATON] = 0.86
    stability[domain == DOMAIN_ACCRETED_TERRANE] = 0.28
    surface = np.full(grid.n, -3600.0, dtype=np.float64)
    surface[continental] = -600.0
    surface[land] = 540.0
    surface[domain == DOMAIN_CRATON] = 820.0
    surface[weak_edge] = 260.0
    surface[protected_seaway] = -980.0

    world.set_field("crust.type", ctype)
    world.set_field(
        "crust.thickness_m",
        np.where(continental, CONT_THICK, OCEAN_THICK).astype(np.float64),
    )
    world.set_field("crust.age_myr", np.where(continental, 1600.0, 80.0))
    world.set_field(
        "crust.origin",
        np.where(continental, ORIGIN_PRIMORDIAL, ORIGIN_RIDGE).astype(np.float64),
    )
    world.set_field("crust.stability", stability)
    world.set_field("crust.domain", domain)
    world.set_field("tectonics.orogeny_age_myr", np.full(grid.n, -1.0))
    world.set_field("tectonics.volcanism_age_myr", np.full(grid.n, -1.0))
    world.objects["terrain.breakup_seaway_opened_corridors"] = [
        _r6_object("breakup_seaway", np.where(protected_seaway)[0], "p32:seaway")
    ]
    return world, surface, ctype, domain, stability, protected_seaway


def _bench_p32_coastline_smoothing_reduces_complexity() -> dict[str, Any]:
    (
        world,
        surface,
        ctype,
        domain,
        stability,
        protected_seaway,
    ) = _p32_overcomplex_coastline_fixture()
    terrain = TerrainModule()
    before = _p32_planform_metrics(world.grid, surface)
    out = terrain._smooth_modern_earthlike_coastlines(
        world, surface, 0.0, ctype, domain, stability)
    after = _p32_planform_metrics(world.grid, out)
    protected_land_fraction = (
        float(np.mean((out >= 0.0)[protected_seaway]))
        if protected_seaway.any() else 0.0
    )
    coast_drop = (
        before["land_coastline_complexity_largest"]
        - after["land_coastline_complexity_largest"]
    )
    ribbon_drop = (
        before["land_ribbon_fraction_gt_0_5"]
        - after["land_ribbon_fraction_gt_0_5"]
    )
    land_delta = after["land_fraction"] - before["land_fraction"]
    metrics = {
        "before_land_fraction": before["land_fraction"],
        "after_land_fraction": after["land_fraction"],
        "land_fraction_delta": land_delta,
        "before_component_count": before["land_component_count"],
        "after_component_count": after["land_component_count"],
        "before_largest_land_fraction": before["largest_land_component_fraction"],
        "after_largest_land_fraction": after["largest_land_component_fraction"],
        "before_ribbon_fraction": before["land_ribbon_fraction_gt_0_5"],
        "after_ribbon_fraction": after["land_ribbon_fraction_gt_0_5"],
        "ribbon_fraction_drop": ribbon_drop,
        "before_coastline_complexity": before["land_coastline_complexity_largest"],
        "after_coastline_complexity": after["land_coastline_complexity_largest"],
        "coastline_complexity_drop": coast_drop,
        "protected_seaway_land_fraction": protected_land_fraction,
        "drowned_area_fraction": float(
            world.g("terrain.last_modern_coastline_drowned_area_fraction", 0.0)),
        "fill_area_fraction": float(
            world.g("terrain.last_modern_coastline_fill_area_fraction", 0.0)),
        "payback_area_fraction": float(
            world.g("terrain.last_modern_coastline_payback_area_fraction", 0.0)),
        "payback_candidate_area_fraction": float(
            world.g("terrain.last_modern_coastline_payback_candidate_area_fraction", 0.0)),
    }
    passed = (
        metrics["before_land_fraction"] >= 0.245
        and 0.25 <= metrics["after_land_fraction"] <= 0.31
        and metrics["after_component_count"] >= 2
        and metrics["after_largest_land_fraction"] <= metrics["before_largest_land_fraction"] + 0.02
        and metrics["coastline_complexity_drop"] >= 0.75
        and metrics["after_coastline_complexity"] <= metrics["before_coastline_complexity"] * 0.94
        and metrics["ribbon_fraction_drop"] >= 0.018
        and metrics["after_ribbon_fraction"] <= 0.35
        and metrics["protected_seaway_land_fraction"] == 0.0
        and metrics["drowned_area_fraction"] > 0.010
        and metrics["fill_area_fraction"] > 0.008
        and (
            metrics["payback_area_fraction"] > 0.004
            or metrics["after_land_fraction"] >= metrics["before_land_fraction"] - 0.003
        )
    )
    return _result(
        "P32.coastline_smoothing_reduces_complexity",
        passed,
        metrics,
        "production coastline smoothing does not reduce jagged coastline complexity while preserving seaways and land budget",
    )


def run_p32_bench(root: Path = PROJECT_ROOT) -> dict[str, Any]:
    del root
    benchmarks = [
        _bench_p32_coastline_smoothing_reduces_complexity(),
        _bench_p32_coastline_simplification_fixture(),
        _bench_p32_protected_seaway_preserved(),
    ]
    passed = all(b["passed"] for b in benchmarks)
    digest = _canonical_digest(benchmarks)
    return {
        "schema": "aevum.tectonics_bench.p32.v1",
        "suite": "P32",
        "status": "pass" if passed else "fail",
        "benchmarks": benchmarks,
        "determinism": {
            "summary_digest": digest,
            "passed": _canonical_digest(benchmarks) == digest,
        },
        "acceptance": {
            "all_microbenchmarks_pass": passed,
            "coastline_smoothing_reduces_complexity": benchmarks[0]["passed"],
            "object_constrained_coastline_simplification": benchmarks[1]["passed"],
            "protected_breakup_seaway_preserved": benchmarks[2]["passed"],
        },
    }


def _p33_parented_sliver_fixture() -> tuple[
    WorldState,
    dict[str, np.ndarray],
]:
    grid = SphereGrid.fibonacci(7200, CONSTANTS.EARTH_RADIUS)
    spec = get_preset("earthlike")
    spec.grid_cells = grid.n
    world = WorldState(grid=grid, spec=spec, time_myr=4500.0)
    module = TectonicsModule()

    parent = _cap_mask(grid, 2.0, -42.0, 28.0)
    fringe = module._dilate_mask(grid, parent, passes=1) & ~parent
    mature_sliver = fringe & (grid.lat < 8.0)
    active_sliver = fringe & (grid.lat > 13.0)
    detached_arc = _cap_mask(grid, -4.0, 72.0, 5.6)
    cont = parent | mature_sliver | active_sliver | detached_arc

    ctype = np.where(cont, CONT, OCEAN).astype(np.float64)
    thick = np.where(cont, CONT_THICK + 2500.0, OCEAN_THICK).astype(np.float64)
    age = np.where(cont, 1900.0, 70.0).astype(np.float64)
    origin = np.where(cont, ORIGIN_PRIMORDIAL, ORIGIN_RIDGE).astype(np.float64)
    reworked = np.full(grid.n, -1.0, dtype=np.float64)
    stability = np.where(cont, 0.64, 0.0).astype(np.float64)
    orog_age = np.full(grid.n, -1.0, dtype=np.float64)
    volc_age = np.full(grid.n, -1.0, dtype=np.float64)

    origin[mature_sliver & (grid.lon < -38.0)] = ORIGIN_SUTURE
    origin[mature_sliver & (grid.lon >= -38.0)] = ORIGIN_ARC
    thick[mature_sliver] = CONT_THICK + 9000.0
    age[mature_sliver] = 1350.0
    stability[mature_sliver] = 0.18
    reworked[mature_sliver] = 850.0
    orog_age[mature_sliver] = 850.0
    volc_age[mature_sliver & (origin == ORIGIN_ARC)] = 850.0

    origin[active_sliver] = ORIGIN_SUTURE
    thick[active_sliver] = CONT_THICK + 11000.0
    age[active_sliver] = 900.0
    stability[active_sliver] = 0.22
    reworked[active_sliver] = 4460.0
    orog_age[active_sliver] = 4460.0
    volc_age[active_sliver] = 4460.0

    origin[detached_arc] = ORIGIN_ARC
    thick[detached_arc] = CONT_THICK
    age[detached_arc] = 420.0
    stability[detached_arc] = 0.24
    reworked[detached_arc] = 820.0
    volc_age[detached_arc] = 820.0

    world.set_field("crust.type", ctype)
    world.set_field("crust.thickness_m", thick)
    world.set_field("crust.age_myr", age)
    world.set_field("crust.origin", origin)
    world.set_field("crust.reworked_age_myr", reworked)
    world.set_field("crust.stability", stability)
    world.set_field("tectonics.orogeny_age_myr", orog_age)
    world.set_field("tectonics.volcanism_age_myr", volc_age)
    world.set_field(
        "terrain.elevation_m",
        np.where(cont, 550.0, -4200.0).astype(np.float64),
    )
    return world, {
        "parent": parent,
        "mature_sliver": mature_sliver,
        "active_sliver": active_sliver,
        "detached_arc": detached_arc,
        "ctype": ctype,
        "thick": thick,
        "age": age,
        "origin": origin,
        "reworked": reworked,
        "stability": stability,
        "orog_age": orog_age,
        "volc_age": volc_age,
    }


def _bench_p33_parented_sliver_consolidation() -> dict[str, Any]:
    world, arrays = _p33_parented_sliver_fixture()
    grid = world.grid
    module = TectonicsModule()
    ctype = arrays["ctype"].copy()
    thick = arrays["thick"].copy()
    age = arrays["age"].copy()
    origin = arrays["origin"].copy()
    reworked = arrays["reworked"].copy()
    stability = arrays["stability"].copy()
    orog_age = arrays["orog_age"].copy()
    volc_age = arrays["volc_age"].copy()
    mature = arrays["mature_sliver"]
    active = arrays["active_sliver"]
    detached = arrays["detached_arc"]

    before_domain = module._crust_domain_field(grid, ctype, origin, stability)
    before_terrane = module._terrane_mask(grid, ctype, origin, stability)
    before_pressure = module._continental_shape_pressure(grid, ctype, origin, stability)
    land_before = ctype == CONT
    out_origin, out_thick, out_age, out_stability = (
        module._consolidate_parented_margin_slivers(
            world, grid, ctype.copy(), thick.copy(), age.copy(), origin.copy(),
            reworked.copy(), stability.copy(), orog_age.copy(), volc_age.copy(),
            4500.0, 20.0, active_boundary_mask=active)
    )
    after_domain = module._crust_domain_field(grid, ctype, out_origin, out_stability)
    after_terrane = module._terrane_mask(grid, ctype, out_origin, out_stability)
    after_pressure = module._continental_shape_pressure(
        grid, ctype, out_origin, out_stability)
    land_after = ctype == CONT

    consolidated = mature & (origin != out_origin) & (out_origin == ORIGIN_PRIMORDIAL)
    active_changed = active & (origin != out_origin)
    detached_changed = detached & (origin != out_origin)
    before_mature_accretionary = mature & np.isin(
        before_domain, [DOMAIN_ACCRETED_TERRANE, DOMAIN_SUTURE])
    after_mature_accretionary = mature & np.isin(
        after_domain, [DOMAIN_ACCRETED_TERRANE, DOMAIN_SUTURE])
    passed = (
        int(before_mature_accretionary.sum()) > 0
        and int(consolidated.sum()) > 0
        and int(active_changed.sum()) == 0
        and int(detached_changed.sum()) == 0
        and np.array_equal(land_before, land_after)
        and int(after_mature_accretionary.sum()) < int(before_mature_accretionary.sum())
        and int(after_terrane[mature].sum()) < int(before_terrane[mature].sum())
        and after_pressure < before_pressure
        and float(world.g("tectonics.last_p33_parented_sliver_consolidated_cells", 0.0)) > 0.0
        and float(world.g("tectonics.last_p33_parented_sliver_active_preserved_cells", 0.0)) > 0.0
        and float(world.g("tectonics.last_p33_parented_sliver_detached_preserved_cells", 0.0)) > 0.0
    )
    return _result(
        "P33.parented_margin_sliver_consolidation",
        passed,
        {
            "before_shape_pressure": before_pressure,
            "after_shape_pressure": after_pressure,
            "mature_sliver_cells": int(mature.sum()),
            "before_mature_accretionary_cells": int(before_mature_accretionary.sum()),
            "after_mature_accretionary_cells": int(after_mature_accretionary.sum()),
            "consolidated_cells": int(consolidated.sum()),
            "active_changed_cells": int(active_changed.sum()),
            "detached_changed_cells": int(detached_changed.sum()),
            "land_mask_unchanged": bool(np.array_equal(land_before, land_after)),
            "recorded_candidate_cells": float(
                world.g("tectonics.last_p33_parented_sliver_candidate_cells", 0.0)),
            "recorded_consolidated_cells": float(
                world.g("tectonics.last_p33_parented_sliver_consolidated_cells", 0.0)),
            "recorded_area_fraction": float(
                world.g("tectonics.last_p33_parented_sliver_area_fraction", 0.0)),
            "recorded_active_preserved_cells": float(
                world.g("tectonics.last_p33_parented_sliver_active_preserved_cells", 0.0)),
            "recorded_detached_preserved_cells": float(
                world.g("tectonics.last_p33_parented_sliver_detached_preserved_cells", 0.0)),
            "consolidated_mean_thickness_m": (
                float(np.mean(out_thick[consolidated])) if consolidated.any() else 0.0
            ),
            "consolidated_mean_age_myr": (
                float(np.mean(out_age[consolidated])) if consolidated.any() else 0.0
            ),
        },
        "P33 failed to mature quiet parented accretion/suture slivers while preserving active belts, detached arcs, and land mask",
    )


def run_p33_bench(root: Path = PROJECT_ROOT) -> dict[str, Any]:
    del root
