def _p34_parented_platform_fixture() -> tuple[
    WorldState,
    dict[str, np.ndarray],
]:
    grid = SphereGrid.fibonacci(7200, CONSTANTS.EARTH_RADIUS)
    spec = get_preset("earthlike")
    spec.grid_cells = grid.n
    world = WorldState(grid=grid, spec=spec, time_myr=4500.0)
    world.set_g("crust.cont_fraction_init", 0.18)
    module = TectonicsModule()

    parent = _cap_mask(grid, 4.0, -36.0, 19.0)
    apron = module._dilate_mask(grid, parent, passes=2) & ~parent
    old_arc_apron = apron & (grid.lat < 12.0) & (grid.lon < -20.0)
    old_shell = apron & (grid.lat < 4.0) & (grid.lon >= -20.0)
    protected_seaway = apron & (np.abs(grid.lat - 8.0) < 4.0) & (grid.lon > -42.0)
    detached_arc = _cap_mask(grid, -9.0, 58.0, 5.2)
    active_rift = apron & (grid.lat > 15.0)
    cont = parent

    ctype = np.where(cont, CONT, OCEAN).astype(np.float64)
    thick = np.where(cont, CONT_THICK + 3000.0, OCEAN_THICK).astype(np.float64)
    age = np.where(cont, 2200.0, 95.0).astype(np.float64)
    origin = np.where(cont, ORIGIN_PRIMORDIAL, ORIGIN_RIDGE).astype(np.float64)
    reworked = np.full(grid.n, -1.0, dtype=np.float64)
    stability = np.where(cont, 0.70, 0.0).astype(np.float64)
    orog_age = np.full(grid.n, -1.0, dtype=np.float64)
    volc_age = np.full(grid.n, -1.0, dtype=np.float64)

    origin[old_arc_apron] = ORIGIN_ARC
    thick[old_arc_apron] = OCEAN_THICK + 7000.0
    age[old_arc_apron] = 360.0
    reworked[old_arc_apron] = 3600.0
    volc_age[old_arc_apron] = 3600.0

    age[old_shell] = 180.0
    thick[old_shell] = OCEAN_THICK + 2500.0
    reworked[old_shell] = 3600.0

    origin[detached_arc] = ORIGIN_ARC
    thick[detached_arc] = OCEAN_THICK + 6500.0
    age[detached_arc] = 420.0
    reworked[detached_arc] = 3600.0
    volc_age[detached_arc] = 3600.0

    reworked[active_rift] = 4480.0
    age[active_rift] = 25.0

    protected_seaway &= ~parent
    world.objects["terrain.breakup_seaway_opened_corridors"] = [
        _r6_object("breakup_seaway", np.where(protected_seaway)[0], "p34:protected-seaway")
    ]

    world.set_field("crust.type", ctype)
    world.set_field("crust.thickness_m", thick)
    world.set_field("crust.age_myr", age)
    world.set_field("crust.origin", origin)
    world.set_field("crust.reworked_age_myr", reworked)
    world.set_field("crust.stability", stability)
    world.set_field("tectonics.orogeny_age_myr", orog_age)
    world.set_field("tectonics.volcanism_age_myr", volc_age)
    return world, {
        "parent": parent,
        "old_arc_apron": old_arc_apron,
        "old_shell": old_shell,
        "protected_seaway": protected_seaway,
        "detached_arc": detached_arc,
        "active_rift": active_rift,
        "ctype": ctype,
        "thick": thick,
        "age": age,
        "origin": origin,
        "reworked": reworked,
        "stability": stability,
        "orog_age": orog_age,
        "volc_age": volc_age,
    }


def _bench_p34_parented_platform_progradation() -> dict[str, Any]:
    world, arrays = _p34_parented_platform_fixture()
    grid = world.grid
    module = TectonicsModule()
    ctype = arrays["ctype"].copy()
    thick = arrays["thick"].copy()
    age = arrays["age"].copy()
    origin = arrays["origin"].copy()
    reworked = arrays["reworked"].copy()
    stability = arrays["stability"].copy()
    orog_age = arrays["orog_age"].copy()
    volc_age = arrays["volc_age"].copy()
    old_arc = arrays["old_arc_apron"]
    old_shell = arrays["old_shell"]
    protected = arrays["protected_seaway"]
    detached = arrays["detached_arc"]
    active = arrays["active_rift"]

    before_cont = ctype == CONT
    before_frac = float(grid.cell_area[before_cont].sum() / grid.cell_area.sum())
    before_pressure = module._continental_shape_pressure(
        grid, ctype, origin, stability)
    out = module._conserve_continental(
        world, grid, ctype.copy(), thick.copy(), age.copy(), origin.copy(),
        reworked.copy(), stability.copy(), orog_age.copy(), volc_age.copy(),
        4500.0, 20.0, None,
        accretion_sources=np.zeros(grid.n, dtype=bool),
        erosion_sources=active,
    )
    (out_ctype, out_thick, out_age, out_origin, out_reworked,
     out_stability, out_orog_age, out_volc_age, after_frac) = out
    del out_reworked, out_orog_age, out_volc_age
    gained = (out_ctype == CONT) & ~before_cont
    parented_gain = gained & (out_origin == ORIGIN_PRIMORDIAL)
    arc_gain = gained & (out_origin == ORIGIN_ARC)
    protected_gain = gained & protected
    detached_gain = gained & detached
    active_gain = gained & active
    old_arc_restored = gained & old_arc
    shell_restored = gained & old_shell
    passed = (
        before_frac < 0.18
        and after_frac > before_frac
        and int(gained.sum()) > 0
        and int(parented_gain.sum()) == int(gained.sum())
        and int(arc_gain.sum()) == 0
        and int(old_arc_restored.sum()) > 0
        and int(shell_restored.sum()) > 0
        and int(protected_gain.sum()) == 0
        and int(detached_gain.sum()) == 0
        and int(active_gain.sum()) == 0
        and float(world.g("tectonics.last_p34_parented_platform_candidate_cells", 0.0)) > 0.0
        and float(world.g("tectonics.last_p34_parented_platform_restored_cells", 0.0)) > 0.0
        and float(world.g("tectonics.last_passive_margin_progradation_cells", 0.0)) > 0.0
    )
    return _result(
        "P34.parented_platform_progradation",
        passed,
        {
            "before_continental_fraction": before_frac,
            "after_continental_fraction": float(after_frac),
            "before_shape_pressure": before_pressure,
            "gained_cells": int(gained.sum()),
            "parented_gain_cells": int(parented_gain.sum()),
            "arc_gain_cells": int(arc_gain.sum()),
            "old_arc_restored_cells": int(old_arc_restored.sum()),
            "old_shell_restored_cells": int(shell_restored.sum()),
            "protected_gain_cells": int(protected_gain.sum()),
            "detached_gain_cells": int(detached_gain.sum()),
            "active_gain_cells": int(active_gain.sum()),
            "recorded_candidate_cells": float(
                world.g("tectonics.last_p34_parented_platform_candidate_cells", 0.0)),
            "recorded_restored_cells": float(
                world.g("tectonics.last_p34_parented_platform_restored_cells", 0.0)),
            "recorded_area_fraction": float(
                world.g("tectonics.last_p34_parented_platform_area_fraction", 0.0)),
            "recorded_protected_cells": float(
                world.g("tectonics.last_p34_parented_platform_protected_cells", 0.0)),
            "recorded_total_progradation_cells": float(
                world.g("tectonics.last_passive_margin_progradation_cells", 0.0)),
            "restored_mean_thickness_m": (
                float(np.mean(out_thick[gained])) if gained.any() else 0.0
            ),
            "restored_mean_age_myr": (
                float(np.mean(out_age[gained])) if gained.any() else 0.0
            ),
            "restored_mean_stability": (
                float(np.mean(out_stability[gained])) if gained.any() else 0.0
            ),
        },
        "P34 failed to restore parented passive platform cells without active accretion or protected-seaway closure",
    )


def run_p34_bench(root: Path = PROJECT_ROOT) -> dict[str, Any]:
    del root
