def _p39_old_platform_funnel_fixture() -> tuple[WorldState, dict[str, np.ndarray]]:
    grid = SphereGrid.fibonacci(7200, CONSTANTS.EARTH_RADIUS)
    spec = get_preset("earthlike")
    spec.grid_cells = grid.n
    world = WorldState(grid=grid, spec=spec, time_myr=4500.0)

    used = np.zeros(grid.n, dtype=bool)

    def take(mask: np.ndarray) -> np.ndarray:
        out = np.asarray(mask, dtype=bool) & ~used
        used[out] = True
        return out

    valid_lineaged = take(_cap_mask(grid, -54.0, -92.0, 20.0))
    orphan_anchor = take(_cap_mask(grid, -54.0, 12.0, 20.0))
    source_blocked = take(_cap_mask(grid, -16.0, -135.0, 13.0))
    thin_blocked = take(_cap_mask(grid, -16.0, -72.0, 13.0))
    rework_blocked = take(_cap_mask(grid, -16.0, -8.0, 13.0))
    young_blocked = take(_cap_mask(grid, -16.0, 56.0, 13.0))
    stability_blocked = take(_cap_mask(grid, 24.0, -96.0, 13.0))
    width_blocked = take(
        (grid.lon > 72.0)
        & (grid.lon < 146.0)
        & (grid.lat > 22.0)
        & (grid.lat < 25.8)
    )
    cont = used.copy()

    ctype = np.where(cont, CONT, OCEAN).astype(np.float64)
    thick = np.where(cont, CONT_THICK + 2800.0, OCEAN_THICK).astype(np.float64)
    age = np.where(cont, 2300.0, 35.0).astype(np.float64)
    origin = np.where(cont, ORIGIN_PRIMORDIAL, ORIGIN_RIDGE).astype(np.float64)
    reworked = np.where(cont, -1.0, 4450.0).astype(np.float64)
    stability = np.where(cont, 0.34, 0.0).astype(np.float64)

    origin[source_blocked] = ORIGIN_ARC
    thick[thin_blocked] = CONT_THICK
    reworked[rework_blocked] = 4440.0
    age[young_blocked] = 800.0
    stability[stability_blocked] = 0.22

    continent_id = np.full(grid.n, -1.0, dtype=np.float64)
    continent_id[valid_lineaged] = 20.0
    width = _graph_width_steps(grid, cont)
    world.objects["tectonics.continents"] = [
        {
            "id": "continent:20",
            "numeric_id": 20,
            "kind": "continent",
            "width_p50_steps": float(np.percentile(width[valid_lineaged], 50)),
            "width_p90_steps": float(np.percentile(width[valid_lineaged], 90)),
            "area_fraction": float(
                grid.cell_area[valid_lineaged].sum() / grid.cell_area.sum()),
            "cell_count": int(valid_lineaged.sum()),
        }
    ]

    world.set_field("crust.type", ctype)
    world.set_field("crust.thickness_m", thick)
    world.set_field("crust.age_myr", age)
    world.set_field("crust.origin", origin)
    world.set_field("crust.reworked_age_myr", reworked)
    world.set_field("crust.stability", stability)
    world.set_field("tectonics.continent_id", continent_id)
    return world, {
        "cont": cont,
        "valid_lineaged": valid_lineaged,
        "orphan_anchor": orphan_anchor,
        "source_blocked": source_blocked,
        "thin_blocked": thin_blocked,
        "rework_blocked": rework_blocked,
        "young_blocked": young_blocked,
        "stability_blocked": stability_blocked,
        "width_blocked": width_blocked,
        "ctype": ctype,
        "thick": thick,
        "age": age,
        "origin": origin,
        "reworked": reworked,
        "stability": stability,
    }


def _bench_p39_old_platform_anchor_funnel() -> dict[str, Any]:
    world, arrays = _p39_old_platform_funnel_fixture()
    grid = world.grid
    module = TectonicsModule()
    funnel = module._old_platform_anchor_funnel(
        world, grid,
        arrays["ctype"], arrays["thick"], arrays["age"], arrays["origin"],
        arrays["reworked"], arrays["stability"], 4500.0,
    )
    module._record_old_platform_anchor_funnel(world, funnel)
    masks = funnel["masks"]
    metrics = funnel["metrics"]
    process_anchor = masks["process_anchor"]
    legacy_anchor = module._stable_parent_anchor_mask(
        grid, arrays["ctype"], arrays["origin"], arrays["stability"])
    process_anchor_from_parent = module._stable_parent_anchor_mask(
        grid, arrays["ctype"], arrays["origin"], arrays["stability"],
        age=arrays["age"], thick=arrays["thick"], reworked=arrays["reworked"],
        t=4500.0)
    blocked_masks = (
        "source_blocked",
        "thin_blocked",
        "rework_blocked",
        "young_blocked",
        "stability_blocked",
        "width_blocked",
    )
    blocked_have_cells = all(int(arrays[name].sum()) > 0 for name in blocked_masks)
    blocked_not_anchors = all(
        int((process_anchor & arrays[name]).sum()) == 0
        for name in blocked_masks
    )
    valid_anchor_cells = int((process_anchor & arrays["valid_lineaged"]).sum())
    orphan_anchor_cells = int((process_anchor & arrays["orphan_anchor"]).sum())
    lineaged_anchor_cells = int(
        (process_anchor & masks["lineage_broad"] & arrays["valid_lineaged"]).sum())
    passed = (
        blocked_have_cells
        and blocked_not_anchors
        and int(legacy_anchor.sum()) == 0
        and np.array_equal(process_anchor, process_anchor_from_parent)
        and valid_anchor_cells > 0
        and orphan_anchor_cells > 0
        and lineaged_anchor_cells == valid_anchor_cells
        and metrics["process_anchor_unlineaged_cells"] >= orphan_anchor_cells
        and metrics["source_blocked_cells"] >= int(arrays["source_blocked"].sum())
        and metrics["thick_blocked_cells"] >= int(arrays["thin_blocked"].sum())
        and metrics["recently_reworked_cells"] >= int(arrays["rework_blocked"].sum())
        and metrics["age_old_blocked_cells"] >= int(arrays["young_blocked"].sum())
        and metrics["stability_ge030_blocked_cells"] >= int(
            arrays["stability_blocked"].sum())
        and metrics["width_ge3_blocked_cells"] >= int(arrays["width_blocked"].sum())
        and float(world.g(
            "tectonics.last_p39_old_platform_funnel_process_anchor_cells", 0.0
        )) == metrics["process_anchor_cells"]
    )
    return _result(
        "P39.old_platform_anchor_funnel",
        passed,
        {
            "continental_cells": metrics["continental_cells"],
            "legacy_anchor_cells": metrics["legacy_anchor_cells"],
            "process_anchor_cells": metrics["process_anchor_cells"],
            "valid_lineaged_anchor_cells": valid_anchor_cells,
            "orphan_process_anchor_cells": orphan_anchor_cells,
            "lineaged_anchor_cells": lineaged_anchor_cells,
            "source_blocked_cells": metrics["source_blocked_cells"],
            "thick_blocked_cells": metrics["thick_blocked_cells"],
            "recently_reworked_cells": metrics["recently_reworked_cells"],
            "age_old_blocked_cells": metrics["age_old_blocked_cells"],
            "stability_ge030_blocked_cells": metrics[
                "stability_ge030_blocked_cells"],
            "width_ge3_blocked_cells": metrics["width_ge3_blocked_cells"],
            "old_platform_core_cells": metrics["old_platform_core_cells"],
            "old_platform_margin_cells": metrics["old_platform_margin_cells"],
            "mature_platform_cells": metrics["mature_platform_cells"],
            "lineage_broad_cells": metrics["lineage_broad_cells"],
            "process_anchor_lineaged_cells": metrics[
                "process_anchor_lineaged_cells"],
            "process_anchor_unlineaged_cells": metrics[
                "process_anchor_unlineaged_cells"],
            "recorded_process_anchor_cells": float(world.g(
                "tectonics.last_p39_old_platform_funnel_process_anchor_cells", 0.0)),
        },
        "P39 failed to expose old-platform anchor losses by source/thickness/rework/age/width/stability/lineage",
    )


