def _bench_p55_inherited_province_physical_cargo() -> dict[str, Any]:
    grid = SphereGrid.fibonacci(2600, CONSTANTS.EARTH_RADIUS)
    spec = get_preset("earthlike")
    spec.grid_cells = grid.n
    world = WorldState(grid=grid, spec=spec, time_myr=4500.0)
    world.set_g("tectonics.enable_inherited_province_physical_cargo", 1.0)
    module = TectonicsModule()

    broad_west = (
        (grid.lon > -156.0) & (grid.lon < -24.0) & (np.abs(grid.lat) < 44.0)
    )
    broad_east = (
        (grid.lon > 28.0) & (grid.lon < 154.0) & (np.abs(grid.lat) < 42.0)
    )
    narrow_active = (
        (grid.lon > -8.0) & (grid.lon < 8.0) & (grid.lat > 54.0) & (grid.lat < 78.0)
    )
    continent = broad_west | broad_east | narrow_active
    shield_region = broad_west & (grid.lon < -68.0) & (np.abs(grid.lat) < 31.0)
    platform_region = broad_east & (grid.lon > 58.0) & (np.abs(grid.lat) < 32.0)

    ctype = np.where(continent, CONT, OCEAN).astype(np.float64)
    origin = np.where(continent, ORIGIN_PRIMORDIAL, ORIGIN_RIDGE).astype(np.float64)
    age = np.where(continent, 980.0, 18.0).astype(np.float64)
    thick = np.where(continent, CONT_THICK + 900.0, OCEAN_THICK).astype(np.float64)
    reworked = np.where(continent, 4460.0, 0.0).astype(np.float64)
    stability = np.where(continent, 0.28, 0.0).astype(np.float64)
    stability[shield_region] = 0.60
    stability[platform_region] = 0.33
    stability[narrow_active] = 0.24

    memory = np.full(grid.n, PROVINCE_NONE, dtype=np.float64)
    memory[shield_region] = PROVINCE_SHIELD
    memory[platform_region] = PROVINCE_PLATFORM
    memory[narrow_active] = PROVINCE_PLATFORM
    active_boundary = narrow_active.copy()

    width = _graph_width_steps(grid, continent)
    blocked_expected = (
        narrow_active
        & (width < 4.0)
        & (stability < 0.54)
        & (memory == PROVINCE_PLATFORM)
    )

    before = (origin.copy(), age.copy(), thick.copy(), reworked.copy(), stability.copy())
    out_origin, out_age, out_thick, out_reworked, out_stability = (
        module._preserve_inherited_province_physical_cargo(
            world, grid, ctype, origin, age, thick, reworked, stability,
            memory, 4500.0, active_boundary_mask=active_boundary)
    )
    domain = module._crust_domain_field(grid, ctype, out_origin, out_stability)
    continent_id = np.where(continent, 1.0, -1.0).astype(np.float64)
    platform_subsidence = np.zeros(grid.n, dtype=np.float64)
    platform_subsidence[platform_region] = 0.52
    province_objects = module._cratonic_province_objects(
        world, grid, ctype, out_age, out_thick, out_origin, out_reworked,
        out_stability, domain, continent_id, 4500.0,
        platform_subsidence=platform_subsidence, province_code=memory)

    area = grid.cell_area
    cont_area = max(float(area[continent].sum()), 1.0e-12)
    shield_preserved = (
        shield_region
        & (out_origin == ORIGIN_CRATON)
        & (out_age >= 2500.0)
        & (out_thick >= CONT_THICK + 5200.0)
        & (out_stability >= 0.84)
        & ((4500.0 - out_reworked) >= 900.0)
    )
    platform_preserved = (
        platform_region
        & (out_origin != ORIGIN_CRATON)
        & (out_age >= 2500.0)
        & (out_thick >= CONT_THICK + 2600.0)
        & (out_stability >= 0.76)
        & ((4500.0 - out_reworked) >= 800.0)
    )
    blocked_young = (
        blocked_expected
        & (out_age < 1200.0)
        & (out_stability < 0.54)
        & (out_origin == before[0])
    )
    shield_objects = _p48_object_mask(grid, province_objects["tectonics.shields"])
    platform_objects = _p48_object_mask(grid, province_objects["tectonics.platforms"])
    stable_ancient = continent & (out_age >= 2500.0) & (out_stability >= 0.75)

    metrics = {
        "shield_preserved_share": float(area[shield_preserved].sum() / cont_area),
        "platform_preserved_share": float(area[platform_preserved].sum() / cont_area),
        "stable_ancient_share": float(area[stable_ancient].sum() / cont_area),
        "blocked_expected_cells": float(np.count_nonzero(blocked_expected)),
        "blocked_young_fraction": _p30_fraction(blocked_young, blocked_expected),
        "telemetry_shield_preserved_share": float(world.g(
            "tectonics.last_p55_shield_cargo_preserved_share_of_continental_crust",
            0.0)),
        "telemetry_platform_preserved_share": float(world.g(
            "tectonics.last_p55_platform_cargo_preserved_share_of_continental_crust",
            0.0)),
        "telemetry_total_preserved_share": float(world.g(
            "tectonics.last_p55_total_cargo_preserved_share_of_continental_crust",
            0.0)),
        "telemetry_active_blocked_share": float(world.g(
            "tectonics.last_p55_active_blocked_share_of_continental_crust",
            0.0)),
        "shield_object_share_after_physical_cargo": float(
            area[shield_objects].sum() / cont_area),
        "platform_object_share_after_physical_cargo": float(
            area[platform_objects].sum() / cont_area),
    }
    physical_cargo_restored = (
        metrics["shield_preserved_share"] >= 0.12
        and metrics["platform_preserved_share"] >= 0.12
        and metrics["stable_ancient_share"] >= 0.24
        and metrics["telemetry_total_preserved_share"] >= 0.24
    )
    active_rework_respected = (
        metrics["blocked_expected_cells"] > 0.0
        and metrics["blocked_young_fraction"] >= 0.90
        and metrics["telemetry_active_blocked_share"] > 0.0
    )
    province_objects_restored = (
        metrics["shield_object_share_after_physical_cargo"] >= 0.12
        and metrics["platform_object_share_after_physical_cargo"] >= 0.18
    )
    passed = bool(
        physical_cargo_restored
        and active_rework_respected
        and province_objects_restored
    )
    metrics.update({
        "physical_cargo_restored": bool(physical_cargo_restored),
        "active_rework_respected": bool(active_rework_respected),
        "province_objects_restored_after_physical_cargo": bool(province_objects_restored),
    })
    return _result(
        "P55.inherited_province_physical_cargo",
        passed,
        metrics,
        "Inherited province labels do not preserve old stable basement cargo or over-preserve active narrow margins",
    )


