def _bench_p56_persistent_basement_cargo_archive() -> dict[str, Any]:
    grid = SphereGrid.fibonacci(2600, CONSTANTS.EARTH_RADIUS)
    spec = get_preset("earthlike")
    spec.grid_cells = grid.n
    world = WorldState(grid=grid, spec=spec, time_myr=4500.0)
    world.set_g("tectonics.enable_inherited_province_physical_cargo", 1.0)
    module = TectonicsModule()

    broad_west = (
        (grid.lon > -156.0) & (grid.lon < -26.0) & (np.abs(grid.lat) < 43.0)
    )
    broad_east = (
        (grid.lon > 26.0) & (grid.lon < 156.0) & (np.abs(grid.lat) < 41.0)
    )
    active_narrow = (
        (grid.lon > -10.0) & (grid.lon < 10.0) & (grid.lat > 54.0) & (grid.lat < 78.0)
    )
    continent = broad_west | broad_east | active_narrow
    shield_region = broad_west & (grid.lon < -70.0) & (np.abs(grid.lat) < 30.0)
    platform_region = broad_east & (grid.lon > 58.0) & (np.abs(grid.lat) < 31.0)

    ctype = np.where(continent, CONT, OCEAN).astype(np.float64)
    origin = np.where(continent, ORIGIN_PRIMORDIAL, ORIGIN_RIDGE).astype(np.float64)
    age = np.where(continent, 940.0, 18.0).astype(np.float64)
    thick = np.where(continent, CONT_THICK + 800.0, OCEAN_THICK).astype(np.float64)
    reworked = np.where(continent, 4460.0, 0.0).astype(np.float64)
    stability = np.where(continent, 0.28, 0.0).astype(np.float64)
    stability[active_narrow] = 0.24
    domain = np.where(continent, DOMAIN_CONTINENTAL_INTERIOR, DOMAIN_OCEANIC).astype(np.float64)
    domain[active_narrow] = DOMAIN_SUTURE
    province_code = np.full(grid.n, PROVINCE_NONE, dtype=np.float64)

    basement_age = np.zeros(grid.n, dtype=np.float64)
    basement_stability = np.zeros(grid.n, dtype=np.float64)
    basement_thick = np.zeros(grid.n, dtype=np.float64)
    inherited = shield_region | platform_region | active_narrow
    basement_age[inherited] = 2920.0
    basement_stability[shield_region] = 0.82
    basement_stability[platform_region | active_narrow] = 0.32
    basement_thick[shield_region] = CONT_THICK + 4300.0
    basement_thick[platform_region | active_narrow] = CONT_THICK + 1200.0
    active_boundary = active_narrow.copy()

    empty_province_objects = {
        "tectonics.shields": [],
        "tectonics.platforms": [],
        "tectonics.interior_basins": [],
    }
    updated_age, updated_stability, updated_thick = (
        module._update_basement_cargo_archive(
            world, grid, ctype, origin, age, thick, reworked, stability, domain,
            province_code, empty_province_objects, basement_age, basement_stability,
            basement_thick, 4500.0, active_boundary_mask=active_boundary)
    )
    out_origin, out_age, out_thick, out_reworked, out_stability = (
        module._preserve_inherited_province_physical_cargo(
            world, grid, ctype, origin.copy(), age.copy(), thick.copy(),
            reworked.copy(), stability.copy(), province_code, 4500.0,
            basement_age_floor=updated_age,
            basement_stability_floor=updated_stability,
            basement_thickness_floor=updated_thick,
            active_boundary_mask=active_boundary)
    )
    out_domain = module._crust_domain_field(grid, ctype, out_origin, out_stability)
    continent_id = np.where(continent, 1.0, -1.0).astype(np.float64)
    province_objects = module._cratonic_province_objects(
        world, grid, ctype, out_age, out_thick, out_origin, out_reworked,
        out_stability, out_domain, continent_id, 4500.0,
        province_code=province_code)

    area = grid.cell_area
    cont_area = max(float(area[continent].sum()), 1.0e-12)
    archive_shield = (
        shield_region
        & (updated_age >= 2500.0)
        & (updated_stability >= 0.80)
        & (updated_thick >= CONT_THICK + 5200.0)
    )
    archive_platform = (
        platform_region
        & (updated_age >= 2500.0)
        & (updated_stability >= 0.70)
        & (updated_thick >= CONT_THICK + 2600.0)
    )
    restored_shield = (
        shield_region
        & (out_origin == ORIGIN_CRATON)
        & (out_age >= 2500.0)
        & (out_stability >= 0.84)
        & (out_thick >= CONT_THICK + 5200.0)
    )
    restored_platform = (
        platform_region
        & (out_origin != ORIGIN_CRATON)
        & (out_age >= 2500.0)
        & (out_stability >= 0.76)
        & (out_thick >= CONT_THICK + 2600.0)
    )
    active_unrestored = (
        active_narrow
        & (updated_stability < 0.70)
        & (out_age < 1200.0)
        & (out_stability < 0.54)
    )
    shield_objects = _p48_object_mask(grid, province_objects["tectonics.shields"])
    platform_objects = _p48_object_mask(grid, province_objects["tectonics.platforms"])
    stable_ancient = continent & (out_age >= 2500.0) & (out_stability >= 0.75)

    metrics = {
        "archive_shield_share": float(area[archive_shield].sum() / cont_area),
        "archive_platform_share": float(area[archive_platform].sum() / cont_area),
        "restored_shield_share": float(area[restored_shield].sum() / cont_area),
        "restored_platform_share": float(area[restored_platform].sum() / cont_area),
        "stable_ancient_share": float(area[stable_ancient].sum() / cont_area),
        "active_unrestored_fraction": _p30_fraction(active_unrestored, active_narrow),
        "shield_object_share": float(area[shield_objects].sum() / cont_area),
        "platform_object_share": float(area[platform_objects].sum() / cont_area),
        "telemetry_archive_old_share": float(world.g(
            "tectonics.last_p56_basement_archive_old_share_of_continental_crust",
            0.0)),
        "telemetry_archive_shield_share": float(world.g(
            "tectonics.last_p56_basement_archive_shield_share_of_continental_crust",
            0.0)),
        "telemetry_archive_platform_share": float(world.g(
            "tectonics.last_p56_basement_archive_platform_share_of_continental_crust",
            0.0)),
        "telemetry_active_blocked_share": float(world.g(
            "tectonics.last_p56_basement_archive_active_blocked_share_of_continental_crust",
            0.0)),
    }
    archive_restored = (
        metrics["archive_shield_share"] >= 0.12
        and metrics["archive_platform_share"] >= 0.12
        and metrics["restored_shield_share"] >= 0.12
        and metrics["restored_platform_share"] >= 0.12
        and metrics["stable_ancient_share"] >= 0.24
    )
    active_respected = (
        metrics["active_unrestored_fraction"] >= 0.90
        and metrics["telemetry_active_blocked_share"] > 0.0
    )
    true_platform_objects = (
        metrics["shield_object_share"] >= 0.12
        and metrics["platform_object_share"] >= 0.12
        and metrics["platform_object_share"] < metrics["shield_object_share"] * 2.4
    )
    passed = bool(archive_restored and active_respected and true_platform_objects)
    metrics.update({
        "archive_restored": bool(archive_restored),
        "active_respected": bool(active_respected),
        "true_platform_objects": bool(true_platform_objects),
    })
    return _result(
        "P56.persistent_basement_cargo_archive",
        passed,
        metrics,
        "Persistent basement cargo archive does not restore old shield/platform floors or over-restores active narrow margins",
    )


def run_p56_bench(root: Path = PROJECT_ROOT) -> dict[str, Any]:
    del root
    benchmarks = [_bench_p56_persistent_basement_cargo_archive()]
    passed = all(b["passed"] for b in benchmarks)
    digest = _canonical_digest(benchmarks)
    main = benchmarks[0]["metrics"]
    return {
        "schema": "aevum.tectonics_bench.p56.v1",
        "suite": "P56",
        "status": "pass" if passed else "fail",
        "benchmarks": benchmarks,
        "determinism": {
            "summary_digest": digest,
            "passed": passed,
        },
        "acceptance": {
            "all_microbenchmarks_pass": passed,
            "persistent_basement_cargo_archive": benchmarks[0]["passed"],
            "archive_restored": bool(main["archive_restored"]),
            "active_respected": bool(main["active_respected"]),
            "true_platform_objects": bool(main["true_platform_objects"]),
        },
    }


def _bench_p57_conservation_basement_cargo_continuity() -> dict[str, Any]:
    world, arrays = _p34_parented_platform_fixture()
    grid = world.grid
    module = TectonicsModule()
    ctype = arrays["ctype"].copy()
    thick = arrays["thick"].copy()
    age = arrays["age"].copy()
    origin = arrays["origin"].copy()
    reworked = arrays["reworked"].copy()
    stability = arrays["stability"].copy()
    orog_age = arrays["orog_age"].copy()
    volc_age = arrays["volc_age"].copy()
    parent = arrays["parent"]
    old_arc = arrays["old_arc_apron"]
    old_shell = arrays["old_shell"]
    detached = arrays["detached_arc"]
    active = arrays["active_rift"]

    basement_age = np.zeros(grid.n, dtype=np.float64)
    basement_stability = np.zeros(grid.n, dtype=np.float64)
    basement_thick = np.zeros(grid.n, dtype=np.float64)
    basement_age[parent] = 3180.0
    basement_stability[parent] = 0.84
    basement_thick[parent] = CONT_THICK + 5400.0
    stale_ocean_archive = detached.copy()
    basement_age[stale_ocean_archive] = 3020.0
    basement_stability[stale_ocean_archive] = 0.80
    basement_thick[stale_ocean_archive] = CONT_THICK + 4200.0

    before_cont = ctype == CONT
    out = module._conserve_continental(
        world, grid, ctype.copy(), thick.copy(), age.copy(), origin.copy(),
        reworked.copy(), stability.copy(), orog_age.copy(), volc_age.copy(),
        4500.0, 20.0, None,
        accretion_sources=np.zeros(grid.n, dtype=bool),
        erosion_sources=active,
        basement_age=basement_age,
        basement_stability=basement_stability,
        basement_thick=basement_thick,
    )
    (out_ctype, _out_thick, _out_age, out_origin, _out_reworked,
     _out_stability, _out_orog_age, _out_volc_age, _after_frac) = out
    gained = (out_ctype == CONT) & ~before_cont
    parented_gain = gained & (out_origin == ORIGIN_PRIMORDIAL)
    platform_gain = gained & (old_arc | old_shell)
    parented_old_basement = (
        parented_gain
        & (basement_age >= 2500.0)
        & (basement_stability >= 0.70)
        & (basement_thick >= CONT_THICK + 2600.0)
    )

    helper_age = basement_age.copy()
    helper_stability = basement_stability.copy()
    helper_thick = basement_thick.copy()
    maintenance_like_missing = np.zeros(grid.n, dtype=bool)
    gained_cells = np.where(platform_gain)[0]
    if gained_cells.size:
        maintenance_like_missing[gained_cells[: max(1, gained_cells.size // 2)]] = True
    helper_age[maintenance_like_missing] = 0.0
    helper_stability[maintenance_like_missing] = 0.0
    helper_thick[maintenance_like_missing] = 0.0
    repaired_age, repaired_stability, repaired_thick = (
        module._repair_basement_cargo_after_conservation(
            world, grid, out_ctype, _out_age, _out_thick, _out_stability,
            helper_age, helper_stability, helper_thick, 4500.0)
    )
    helper_repaired_old = (
        maintenance_like_missing
        & (repaired_age >= 2500.0)
        & (repaired_stability >= 0.70)
        & (repaired_thick >= CONT_THICK + 2600.0)
    )
    stale_ocean_after = stale_ocean_archive & (out_ctype != CONT)
    stale_ocean_cleared = (
        stale_ocean_after
        & (repaired_age <= 0.0)
        & (repaired_stability <= 0.0)
        & (repaired_thick <= 0.0)
    )

    metrics = {
        "gained_cells": int(np.count_nonzero(gained)),
        "parented_gain_cells": int(np.count_nonzero(parented_gain)),
        "platform_gain_cells": int(np.count_nonzero(platform_gain)),
        "parented_old_basement_cells": int(np.count_nonzero(parented_old_basement)),
        "parented_old_basement_fraction": _p30_fraction(parented_old_basement, parented_gain),
        "maintenance_like_missing_cells": int(np.count_nonzero(maintenance_like_missing)),
        "helper_repaired_old_fraction": _p30_fraction(
            helper_repaired_old, maintenance_like_missing),
        "stale_ocean_archive_cells": int(np.count_nonzero(stale_ocean_after)),
        "stale_ocean_cleared_fraction": _p30_fraction(
            stale_ocean_cleared, stale_ocean_after),
        "telemetry_parented_inherited_cells": float(world.g(
            "tectonics.last_p57_parented_basement_cargo_inherited_cells", 0.0)),
        "telemetry_parented_old_inherited_cells": float(world.g(
            "tectonics.last_p57_parented_old_basement_cargo_inherited_cells", 0.0)),
        "telemetry_neighbor_inherited_cells": float(world.g(
            "tectonics.last_p57_neighbor_basement_cargo_inherited_cells", 0.0)),
        "telemetry_neighbor_old_inherited_cells": float(world.g(
            "tectonics.last_p57_neighbor_old_basement_cargo_inherited_cells", 0.0)),
        "telemetry_true_ocean_cleared_cells": float(world.g(
            "tectonics.last_p57_true_ocean_basement_cleared_cells", 0.0)),
        "telemetry_initialized_cells": float(world.g(
            "tectonics.last_p57_initialized_basement_cells", 0.0)),
    }
    parented_cargo_preserved = (
        metrics["platform_gain_cells"] > 0
        and metrics["parented_old_basement_fraction"] >= 0.95
        and metrics["telemetry_parented_inherited_cells"] >= metrics["platform_gain_cells"]
    )
    maintenance_gap_repaired = (
        metrics["maintenance_like_missing_cells"] > 0
        and metrics["helper_repaired_old_fraction"] >= 0.95
        and metrics["telemetry_neighbor_inherited_cells"] >= metrics[
            "maintenance_like_missing_cells"]
    )
    true_ocean_recycled = (
        metrics["stale_ocean_archive_cells"] > 0
        and metrics["stale_ocean_cleared_fraction"] >= 0.95
        and metrics["telemetry_true_ocean_cleared_cells"] >= metrics[
            "stale_ocean_archive_cells"]
    )
    passed = bool(parented_cargo_preserved and maintenance_gap_repaired and true_ocean_recycled)
    metrics.update({
        "parented_cargo_preserved": bool(parented_cargo_preserved),
        "maintenance_gap_repaired": bool(maintenance_gap_repaired),
        "true_ocean_recycled": bool(true_ocean_recycled),
    })
    return _result(
        "P57.conservation_basement_cargo_continuity",
        passed,
        metrics,
        "Continental conservation/restoration loses old basement cargo or resurrects basement archive in true oceanic cells",
    )


