def _bench_p66_multiseed_flagged_cratonic_audit() -> dict[str, Any]:
    seeds = (42, 31415, 27182)
    rows: list[dict[str, Any]] = []
    for seed in seeds:
        metrics = _p63_flagged_full_history_metrics(
            enable_p64_projection=True,
            enable_p65_refresh=True,
            seed=seed,
        )
        row = {
            "seed": int(seed),
            "land_fraction": float(metrics["land_fraction"]),
            "land_component_count": int(metrics["land_component_count"]),
            "largest_land_component_fraction": float(
                metrics["largest_land_component_fraction"]),
            "land_ribbon_fraction": float(metrics["land_ribbon_fraction"]),
            "continental_ribbon_fraction": float(metrics["continental_ribbon_fraction"]),
            "stable_craton_continental_fraction": float(
                metrics["stable_craton_continental_fraction"]),
            "ancient_continental_fraction": float(
                metrics["ancient_continental_fraction"]),
            "old_basement_archive_fraction": float(
                metrics["old_basement_archive_fraction"]),
            "p62_supported_cratonic_lithosphere_fraction": float(
                metrics["p62_supported_cratonic_lithosphere_fraction"]),
            "p48_mature_cratonic_share": float(metrics["p48_mature_cratonic_share"]),
            "p48_platform_share": float(metrics["p48_platform_share"]),
            "p60_old_candidate_share": float(metrics["p60_old_candidate_share"]),
            "p64_projected_share": float(metrics["p64_projected_share"]),
            "p65_refreshed_p48_mature_share": float(
                metrics["p65_refreshed_p48_mature_share"]),
            "p59_missing_old_source_cells_after": float(
                metrics["p59_missing_old_source_cells_after"]),
            "trajectory_fingerprint": metrics["trajectory_fingerprint"],
        }
        row["stable_ok"] = bool(row["stable_craton_continental_fraction"] >= 0.120)
        row["ancient_ok"] = bool(row["ancient_continental_fraction"] >= 0.200)
        row["mature_province_ok"] = bool(row["p48_mature_cratonic_share"] >= 0.160)
        row["archive_ok"] = bool(row["old_basement_archive_fraction"] >= 0.200)
        row["terrain_response_ok"] = bool(
            0.18 <= row["land_fraction"] <= 0.30
            and row["land_component_count"] <= 12
            and row["land_ribbon_fraction"] <= 0.72
            and row["continental_ribbon_fraction"] <= 0.72
            and row["p59_missing_old_source_cells_after"] == 0.0
        )
        row["seed_ready"] = bool(
            row["stable_ok"]
            and row["ancient_ok"]
            and row["mature_province_ok"]
            and row["archive_ok"]
            and row["terrain_response_ok"]
        )
        rows.append(row)

    unique_fingerprints = len({row["trajectory_fingerprint"] for row in rows})
    seed_invariant = unique_fingerprints == 1
    values = {
        "seeds": [int(seed) for seed in seeds],
        "seed_count": int(len(rows)),
        "unique_trajectory_fingerprint_count": int(unique_fingerprints),
        "seed_invariant_flagged_path": bool(seed_invariant),
        "per_seed_metrics": rows,
        "stable_min": float(min(row["stable_craton_continental_fraction"] for row in rows)),
        "ancient_min": float(min(row["ancient_continental_fraction"] for row in rows)),
        "mature_province_min": float(min(row["p48_mature_cratonic_share"] for row in rows)),
        "archive_min": float(min(row["old_basement_archive_fraction"] for row in rows)),
        "p62_support_min": float(
            min(row["p62_supported_cratonic_lithosphere_fraction"] for row in rows)),
        "land_ribbon_max": float(max(row["land_ribbon_fraction"] for row in rows)),
        "continental_ribbon_max": float(
            max(row["continental_ribbon_fraction"] for row in rows)),
        "land_component_max": int(max(row["land_component_count"] for row in rows)),
        "largest_land_component_max": float(
            max(row["largest_land_component_fraction"] for row in rows)),
        "p59_missing_old_source_cells_after_max": float(
            max(row["p59_missing_old_source_cells_after"] for row in rows)),
        "stable_ok_count": int(sum(row["stable_ok"] for row in rows)),
        "ancient_ok_count": int(sum(row["ancient_ok"] for row in rows)),
        "mature_province_ok_count": int(sum(row["mature_province_ok"] for row in rows)),
        "archive_ok_count": int(sum(row["archive_ok"] for row in rows)),
        "terrain_response_ok_count": int(sum(row["terrain_response_ok"] for row in rows)),
        "seed_ready_count": int(sum(row["seed_ready"] for row in rows)),
    }
    continuity_ready = (
        values["stable_ok_count"] == values["seed_count"]
        and values["ancient_ok_count"] == values["seed_count"]
        and values["mature_province_ok_count"] == values["seed_count"]
        and values["archive_ok_count"] == values["seed_count"]
    )
    terrain_ready = values["terrain_response_ok_count"] == values["seed_count"]
    # If all seed values collapse to the same deterministic trajectory, the
    # model may be behaving as intended, but a seed sweep has not proved
    # ensemble robustness.  Promotion then needs a physical-parameter or
    # initial-layout ensemble rather than more random seeds.
    promotion_ready = bool(continuity_ready and terrain_ready and not seed_invariant)
    audit_completed = (
        values["seed_count"] == len(seeds)
        and values["p59_missing_old_source_cells_after_max"] == 0.0
    )
    keeps_default_off_until_multiseed_ready = not promotion_ready
    passed = bool(audit_completed and (promotion_ready or keeps_default_off_until_multiseed_ready))
    values.update({
        "continuity_ready_all_seeds": bool(continuity_ready),
        "terrain_response_ready_all_seeds": bool(terrain_ready),
        "promotion_ready": bool(promotion_ready),
        "audit_completed": bool(audit_completed),
        "keeps_default_off_until_multiseed_ready": bool(
            keeps_default_off_until_multiseed_ready),
        "failed_seed_count": int(values["seed_count"] - values["seed_ready_count"]),
        "failed_seeds": [
            int(row["seed"])
            for row in rows
            if not row["seed_ready"]
        ],
    })
    return _result(
        "P66.multiseed_flagged_cratonic_audit",
        passed,
        values,
        "P66 failed to run a deterministic multi-seed P64+P65 audit or made an unsafe promotion decision from incomplete terrain/cratonic evidence",
    )


def run_p66_bench(root: Path = PROJECT_ROOT) -> dict[str, Any]:
    del root
    benchmarks = [_bench_p66_multiseed_flagged_cratonic_audit()]
    passed = all(b["passed"] for b in benchmarks)
    digest = _canonical_digest(benchmarks)
    main = benchmarks[0]["metrics"]
    return {
        "schema": "aevum.tectonics_bench.p66.v1",
        "suite": "P66",
        "status": "pass" if passed else "fail",
        "benchmarks": benchmarks,
        "determinism": {
            "summary_digest": digest,
            "passed": passed,
        },
        "acceptance": {
            "all_microbenchmarks_pass": passed,
            "multiseed_flagged_cratonic_audit": benchmarks[0]["passed"],
            "audit_completed": bool(main["audit_completed"]),
            "continuity_ready_all_seeds": bool(main["continuity_ready_all_seeds"]),
            "terrain_response_ready_all_seeds": bool(
                main["terrain_response_ready_all_seeds"]),
            "seed_invariant_flagged_path": bool(main["seed_invariant_flagged_path"]),
            "promotion_ready": bool(main["promotion_ready"]),
            "keeps_default_off_until_multiseed_ready": bool(
                main["keeps_default_off_until_multiseed_ready"]),
        },
    }


