def _bench_p67_deterministic_physical_ensemble_audit() -> dict[str, Any]:
    members = _p67_physical_ensemble_members()
    rows: list[dict[str, Any]] = []
    for member in members:
        metrics = _p63_flagged_full_history_metrics(
            enable_p64_projection=True,
            enable_p65_refresh=True,
            **member,
        )
        row = {
            "member_name": str(member["member_name"]),
            "seed": int(member["seed"]),
            "target_land_fraction": float(member["target_land_fraction"]),
            "n_plates": int(member["n_plates"]),
            "water_inventory_earth": float(member["water_inventory_earth"]),
            "radiogenic_abundance": float(member["radiogenic_abundance"]),
            "initial_internal_temp_k": float(member["initial_internal_temp_k"]),
            "crust_strength": float(member["crust_strength"]),
            "land_fraction": float(metrics["land_fraction"]),
            "land_component_count": int(metrics["land_component_count"]),
            "largest_land_component_fraction": float(
                metrics["largest_land_component_fraction"]),
            "land_ribbon_fraction": float(metrics["land_ribbon_fraction"]),
            "continental_ribbon_fraction": float(metrics["continental_ribbon_fraction"]),
            "stable_craton_continental_fraction": float(
                metrics["stable_craton_continental_fraction"]),
            "ancient_continental_fraction": float(
                metrics["ancient_continental_fraction"]),
            "old_basement_archive_fraction": float(
                metrics["old_basement_archive_fraction"]),
            "p62_supported_cratonic_lithosphere_fraction": float(
                metrics["p62_supported_cratonic_lithosphere_fraction"]),
            "p48_mature_cratonic_share": float(metrics["p48_mature_cratonic_share"]),
            "p48_platform_share": float(metrics["p48_platform_share"]),
            "p60_old_candidate_share": float(metrics["p60_old_candidate_share"]),
            "p64_projected_share": float(metrics["p64_projected_share"]),
            "p65_refreshed_p48_mature_share": float(
                metrics["p65_refreshed_p48_mature_share"]),
            "p59_missing_old_source_cells_after": float(
                metrics["p59_missing_old_source_cells_after"]),
            "trajectory_fingerprint": metrics["trajectory_fingerprint"],
        }
        row["stable_ok"] = bool(row["stable_craton_continental_fraction"] >= 0.120)
        row["ancient_ok"] = bool(row["ancient_continental_fraction"] >= 0.200)
        row["mature_province_ok"] = bool(row["p48_mature_cratonic_share"] >= 0.160)
        row["archive_ok"] = bool(row["old_basement_archive_fraction"] >= 0.195)
        row["cratonic_balance_ok"] = bool(
            row["stable_craton_continental_fraction"] <= 0.450
            and row["ancient_continental_fraction"] <= 0.650
            and row["old_basement_archive_fraction"] <= 0.700
            and row["p48_mature_cratonic_share"] <= 0.600
            and row["p48_platform_share"] >= 0.030
        )
        row["terrain_response_ok"] = bool(
            0.15 <= row["land_fraction"] <= 0.40
            and row["land_component_count"] <= 28
            and row["largest_land_component_fraction"] <= 0.88
            and row["land_ribbon_fraction"] <= 0.76
            and row["continental_ribbon_fraction"] <= 0.76
            and row["p59_missing_old_source_cells_after"] == 0.0
        )
        row["catastrophic_topology_free"] = bool(
            0.10 <= row["land_fraction"] <= 0.45
            and row["land_component_count"] <= 32
            and row["largest_land_component_fraction"] <= 0.92
            and row["land_ribbon_fraction"] <= 0.82
            and row["continental_ribbon_fraction"] <= 0.82
            and row["old_basement_archive_fraction"] >= 0.140
            and row["p59_missing_old_source_cells_after"] == 0.0
        )
        row["member_ready"] = bool(
            row["stable_ok"]
            and row["ancient_ok"]
            and row["mature_province_ok"]
            and row["archive_ok"]
            and row["cratonic_balance_ok"]
            and row["terrain_response_ok"]
        )
        rows.append(row)

    unique_fingerprints = len({row["trajectory_fingerprint"] for row in rows})
    values = {
        "member_count": int(len(rows)),
        "unique_trajectory_fingerprint_count": int(unique_fingerprints),
        "physical_ensemble_differentiated": bool(unique_fingerprints >= 2),
        "per_member_metrics": rows,
        "stable_min": float(min(row["stable_craton_continental_fraction"] for row in rows)),
        "ancient_min": float(min(row["ancient_continental_fraction"] for row in rows)),
        "mature_province_min": float(min(row["p48_mature_cratonic_share"] for row in rows)),
        "archive_min": float(min(row["old_basement_archive_fraction"] for row in rows)),
        "p62_support_min": float(
            min(row["p62_supported_cratonic_lithosphere_fraction"] for row in rows)),
        "land_fraction_min": float(min(row["land_fraction"] for row in rows)),
        "land_fraction_max": float(max(row["land_fraction"] for row in rows)),
        "land_ribbon_max": float(max(row["land_ribbon_fraction"] for row in rows)),
        "continental_ribbon_max": float(
            max(row["continental_ribbon_fraction"] for row in rows)),
        "land_component_max": int(max(row["land_component_count"] for row in rows)),
        "largest_land_component_max": float(
            max(row["largest_land_component_fraction"] for row in rows)),
        "p59_missing_old_source_cells_after_max": float(
            max(row["p59_missing_old_source_cells_after"] for row in rows)),
        "stable_ok_count": int(sum(row["stable_ok"] for row in rows)),
        "ancient_ok_count": int(sum(row["ancient_ok"] for row in rows)),
        "mature_province_ok_count": int(sum(row["mature_province_ok"] for row in rows)),
        "archive_ok_count": int(sum(row["archive_ok"] for row in rows)),
        "cratonic_balance_ok_count": int(
            sum(row["cratonic_balance_ok"] for row in rows)),
        "terrain_response_ok_count": int(sum(row["terrain_response_ok"] for row in rows)),
        "catastrophic_topology_free_count": int(
            sum(row["catastrophic_topology_free"] for row in rows)),
        "member_ready_count": int(sum(row["member_ready"] for row in rows)),
    }
    continuity_ready = (
        values["stable_ok_count"] == values["member_count"]
        and values["ancient_ok_count"] == values["member_count"]
        and values["mature_province_ok_count"] == values["member_count"]
        and values["archive_ok_count"] == values["member_count"]
        and values["cratonic_balance_ok_count"] == values["member_count"]
    )
    terrain_ready = values["terrain_response_ok_count"] == values["member_count"]
    catastrophic_free = values["catastrophic_topology_free_count"] == values["member_count"]
    audit_completed = (
        values["member_count"] == len(members)
        and values["physical_ensemble_differentiated"]
        and values["p59_missing_old_source_cells_after_max"] == 0.0
    )
    promotion_ready = bool(
        audit_completed and continuity_ready and terrain_ready and catastrophic_free)
    keeps_default_off_until_physical_ensemble_ready = not promotion_ready
    passed = bool(
        audit_completed
        and catastrophic_free
        and (promotion_ready or keeps_default_off_until_physical_ensemble_ready)
    )
    values.update({
        "continuity_ready_all_members": bool(continuity_ready),
        "terrain_response_ready_all_members": bool(terrain_ready),
        "catastrophic_topology_free_all_members": bool(catastrophic_free),
        "promotion_ready": bool(promotion_ready),
        "audit_completed": bool(audit_completed),
        "keeps_default_off_until_physical_ensemble_ready": bool(
            keeps_default_off_until_physical_ensemble_ready),
        "failed_member_count": int(values["member_count"] - values["member_ready_count"]),
        "failed_members": [
            str(row["member_name"])
            for row in rows
            if not row["member_ready"]
        ],
    })
    return _result(
        "P67.deterministic_physical_ensemble_audit",
        passed,
        values,
        "P67 failed to run a differentiated deterministic physical ensemble or found catastrophic morphology/archive breakage in the flagged P64+P65 path",
    )


