def _bench_p71_province_graph_fixture_suite() -> dict[str, Any]:
    fixture_suite = province_graph_fixture_summary()
    acceptance = fixture_suite["acceptance"]
    fixture_metrics = [fixture["metrics"] for fixture in fixture_suite["fixtures"]]
    metrics = {
        "fixture_count": fixture_suite["fixture_count"],
        "passed_fixture_count": sum(1 for fixture in fixture_suite["fixtures"] if fixture["passed"]),
        "province_class_count": fixture_suite["province_class_count"],
        "parent_process_count": fixture_suite["parent_process_count"],
        "total_province_count": sum(metric["province_count"] for metric in fixture_metrics),
        "total_class_edge_count": sum(metric["class_edge_count"] for metric in fixture_metrics),
        "max_largest_province_fraction": max(
            metric["largest_province_fraction"] for metric in fixture_metrics),
        "failed_fixture_count": sum(1 for fixture in fixture_suite["fixtures"] if not fixture["passed"]),
        "random_texture_only_province_count": sum(
            metric["random_texture_only_province_count"] for metric in fixture_metrics),
        "unparented_province_count": sum(
            metric["unparented_province_count"] for metric in fixture_metrics),
        "non_contiguous_province_count": sum(
            metric["non_contiguous_province_count"] for metric in fixture_metrics),
        "missing_expected_class_count": sum(
            metric["missing_expected_class_count"] for metric in fixture_metrics),
        "missing_expected_edge_count": sum(
            metric["missing_expected_edge_count"] for metric in fixture_metrics),
    }
    passed = (
        fixture_suite["status"] == "fixture_suite_ready"
        and all(acceptance.values())
        and metrics["fixture_count"] == 7
        and metrics["province_class_count"] >= 13
        and metrics["parent_process_count"] >= 13
        and metrics["failed_fixture_count"] == 0
        and metrics["random_texture_only_province_count"] == 0
        and metrics["unparented_province_count"] == 0
        and metrics["non_contiguous_province_count"] == 0
        and metrics["missing_expected_class_count"] == 0
        and metrics["missing_expected_edge_count"] == 0
    )
    return _result(
        "P71.province_graph_fixture_suite",
        passed,
        metrics,
        "P71 province graph fixtures are incomplete, non-contiguous, unparented, random-texture sourced, or physically misordered",
    )


