def _p72_generated_world_diversity(cells: int = 900) -> dict[str, Any]:
    from aevum.engine import Engine

    spec = get_preset("earthlike")
    spec.grid_cells = int(cells)
    spec.t_end_myr = 4500.0
    engine = Engine.build(spec)
    engine.run(n_frames=5)
    return generated_world_province_diversity_summary(engine.world)


def _bench_p72_generated_world_province_diversity(
    diversity: dict[str, Any],
) -> dict[str, Any]:
    metrics = dict(diversity["metrics"])
    metrics.update({
        "passive_margin_lowland_detail_class_missing": bool(
            diversity["limitations"]["passive_margin_lowland_detail_class_missing"]),
        "terrain_rewrite_pending": bool(diversity["limitations"]["terrain_rewrite_pending"]),
    })
    acceptance = diversity["acceptance"]
    passed = (
        diversity["status"] == "generated_world_gate_ready"
        and all(acceptance.values())
        and metrics["cells"] == 900
        and metrics["major_component_count"] >= 2
        and metrics["min_province_class_count_per_major"] >= 3
        and metrics["max_largest_internal_province_fraction"] <= 0.74
        and metrics["min_basin_or_lowland_share_per_major"] >= 0.18
        and metrics["max_active_highland_or_plateau_fraction"] <= 0.45
        and metrics["max_unparented_highland_fraction"] <= 0.15
        and metrics["terrain_landform_kind_count"] >= 5
        and metrics["terrain_landform_parent_process_count"] >= 5
        and metrics["unparented_landform_object_count"] == 0
    )
    return _result(
        "P72.generated_world_province_diversity_gate",
        passed,
        metrics,
        "P72 generated Earth-like world lacks multi-class process-parented major continents or still has high-flat/unparented province architecture",
    )


