def _p74_generated_world_template_metrics(cells: int = 900) -> dict[str, Any]:
    from collections import Counter

    from aevum import validation
    from aevum.compiler.map_compiler import MapCompiler
    from aevum.engine import Engine

    spec = get_preset("earthlike")
    spec.grid_cells = int(cells)
    spec.t_end_myr = 4500.0
    engine = Engine.build(spec)
    engine.run(n_frames=5)
    world = engine.world
    diversity = generated_world_province_diversity_summary(world)
    tectonics = validation.tectonic_diagnostics(engine)
    cm = MapCompiler(world, engine.archive).compile(width=72, height=36, n_starts=4)
    compiler = validation.compiler_consistency_metrics(engine, cm)
    ocean = tectonics["ocean_geography"]
    landforms = list(world.objects.get("terrain.continental_landforms", []))
    kind_counts = Counter(str(obj.get("kind", "unknown")) for obj in landforms)
    passive_objs = [
        obj for obj in landforms
        if str(obj.get("kind", "")) == "passive_margin_lowland"
    ]
    passive_field = np.asarray(
        world.get_field("terrain.passive_margin_lowland", 0.0),
        dtype=np.float64,
    ) > 0.0
    area = world.grid.cell_area
    total_area = max(float(area.sum()), 1.0e-12)
    passive_area = float(area[passive_field].sum() / total_area)
    passive_mean_elev = (
        float(np.average(
            world.get_field("terrain.elevation_m")[passive_field] - world.sea_level,
            weights=area[passive_field],
        ))
        if passive_field.any() else 0.0
    )
    metrics = {
        "cells": int(cells),
        "time_myr": float(world.time_myr),
        "p74_template_area_fraction": float(
            world.g("terrain.last_p74_template_area_fraction", 0.0)),
        "p74_template_mean_abs_m": float(
            world.g("terrain.last_p74_template_mean_abs_m", 0.0)),
        "p74_passive_margin_lowland_area_fraction": float(
            world.g("terrain.last_p74_passive_margin_lowland_area_fraction", 0.0)),
        "p74_foreland_lowland_area_fraction": float(
            world.g("terrain.last_p74_foreland_lowland_area_fraction", 0.0)),
        "p74_rift_lowland_area_fraction": float(
            world.g("terrain.last_p74_rift_lowland_area_fraction", 0.0)),
        "p74_old_orogen_template_area_fraction": float(
            world.g("terrain.last_p74_old_orogen_template_area_fraction", 0.0)),
        "p74_unsupported_highland_relaxed_area_fraction": float(
            world.g("terrain.last_p74_unsupported_highland_relaxed_area_fraction", 0.0)),
        "p74_land_preserved": bool(
            world.g("terrain.last_p74_land_preserved", 0.0) >= 0.5),
        "passive_margin_lowland_field_area_fraction": passive_area,
        "passive_margin_lowland_object_count": int(len(passive_objs)),
        "passive_margin_lowland_object_area_fraction": float(
            sum(float(obj.get("area_fraction", 0.0)) for obj in passive_objs)),
        "passive_margin_lowland_mean_elevation_m": passive_mean_elev,
        "terrain_landform_kind_count": int(len(kind_counts)),
        "platform_object_count": int(kind_counts.get("platform", 0)),
        "interior_basin_object_count": int(kind_counts.get("interior_basin", 0)),
        "rift_basin_object_count": int(kind_counts.get("rift_basin", 0)),
        "foreland_basin_object_count": int(kind_counts.get("foreland_basin", 0)),
        "old_subdued_orogen_object_count": int(kind_counts.get("old_subdued_orogen", 0)),
        "province_diversity_status": str(diversity["status"]),
        "major_component_count": int(diversity["metrics"]["major_component_count"]),
        "min_province_class_count_per_major": int(
            diversity["metrics"]["min_province_class_count_per_major"]),
        "max_largest_internal_province_fraction": float(
            diversity["metrics"]["max_largest_internal_province_fraction"]),
        "min_basin_or_lowland_share_per_major": float(
            diversity["metrics"]["min_basin_or_lowland_share_per_major"]),
        "max_active_highland_or_plateau_fraction": float(
            diversity["metrics"]["max_active_highland_or_plateau_fraction"]),
        "max_unparented_highland_fraction": float(
            diversity["metrics"]["max_unparented_highland_fraction"]),
        "nearshore_superdeep_fraction_gt2500m": float(
            ocean["nearshore_superdeep_fraction_gt2500m"]),
        "far_ocean_shallow_fraction_lt1500m": float(
            ocean["far_ocean_shallow_fraction_lt1500m"]),
        "shelf_fraction_of_ocean": float(ocean["shelf_fraction_of_ocean"]),
        "abyss_fraction_of_ocean": float(ocean["abyss_fraction_of_ocean"]),
        "compiler_broad_land_to_water_fraction": float(
            compiler["broad_land_to_water_fraction"]),
        "compiler_broad_ocean_to_land_fraction": float(
            compiler["broad_ocean_to_land_fraction"]),
        "compiler_elevation_sign_mismatch_fraction": float(
            compiler["terrain_elevation_sign_mismatch_fraction"]),
        "trajectory_fingerprint": _canonical_digest({
            "p74_template_area_fraction": round(float(
                world.g("terrain.last_p74_template_area_fraction", 0.0)), 6),
            "passive_margin_lowland_field_area_fraction": round(passive_area, 6),
            "passive_margin_lowland_object_count": int(len(passive_objs)),
            "major_component_count": int(diversity["metrics"]["major_component_count"]),
        }),
    }
    metrics["p74_template_response_active"] = bool(
        metrics["p74_template_area_fraction"] > 0.0
        and metrics["p74_template_mean_abs_m"] > 25.0
        and metrics["p74_land_preserved"]
    )
    metrics["passive_margin_lowland_object_layer_active"] = bool(
        metrics["passive_margin_lowland_field_area_fraction"] > 0.0
        and metrics["passive_margin_lowland_object_count"] > 0
        and metrics["passive_margin_lowland_mean_elevation_m"] < 500.0
    )
    metrics["lowland_and_basin_modes_present"] = bool(
        metrics["platform_object_count"] > 0
        and metrics["interior_basin_object_count"] > 0
        and metrics["min_basin_or_lowland_share_per_major"] >= 0.18
    )
    metrics["rift_and_foreland_lows_present"] = bool(
        metrics["rift_basin_object_count"] > 0
        and metrics["foreland_basin_object_count"] > 0
        and (
            metrics["p74_rift_lowland_area_fraction"] > 0.0
            or metrics["p74_foreland_lowland_area_fraction"] > 0.0
        )
    )
    metrics["old_orogen_expression_present"] = bool(
        metrics["old_subdued_orogen_object_count"] > 0)
    metrics["highlands_parented_or_limited"] = bool(
        metrics["max_unparented_highland_fraction"] <= 0.15
        and metrics["max_active_highland_or_plateau_fraction"] <= 0.45
    )
    metrics["bathymetry_regression_free"] = bool(
        metrics["nearshore_superdeep_fraction_gt2500m"] <= 0.06
        and metrics["far_ocean_shallow_fraction_lt1500m"] <= 0.15
        and metrics["shelf_fraction_of_ocean"] >= 0.02
        and metrics["abyss_fraction_of_ocean"] >= 0.20
    )
    metrics["compiler_regression_free"] = bool(
        metrics["compiler_broad_land_to_water_fraction"] <= 0.03
        and metrics["compiler_broad_ocean_to_land_fraction"] <= 0.03
        and metrics["compiler_elevation_sign_mismatch_fraction"] <= 0.05
    )
    return metrics


def _bench_p74_terrain_coupling_rewrite() -> dict[str, Any]:
    metrics = _p74_generated_world_template_metrics(cells=900)
    passed = bool(
        metrics["p74_template_response_active"]
        and metrics["passive_margin_lowland_object_layer_active"]
        and metrics["province_diversity_status"] == "generated_world_gate_ready"
        and metrics["major_component_count"] >= 2
        and metrics["min_province_class_count_per_major"] >= 3
        and metrics["max_largest_internal_province_fraction"] <= 0.74
        and metrics["lowland_and_basin_modes_present"]
        and metrics["rift_and_foreland_lows_present"]
        and metrics["old_orogen_expression_present"]
        and metrics["highlands_parented_or_limited"]
        and metrics["bathymetry_regression_free"]
        and metrics["compiler_regression_free"]
    )
    return _result(
        "P74.terrain_coupling_rewrite",
        passed,
        metrics,
        "P74 terrain coupling failed to produce process-template terrain response, passive-margin lowland objects, province diversity, or bathymetry/compiler regression guards",
    )


def run_p74_bench(root: Path = PROJECT_ROOT) -> dict[str, Any]:
    del root
    benchmarks = [_bench_p74_terrain_coupling_rewrite()]
    passed = all(b["passed"] for b in benchmarks)
    digest = _canonical_digest(benchmarks)
    main = benchmarks[0]["metrics"]
    return {
        "schema": "aevum.tectonics_bench.p74.v1",
        "suite": "P74",
        "status": "pass" if passed else "fail",
        "benchmarks": benchmarks,
        "determinism": {
            "summary_digest": digest,
            "passed": passed,
        },
        "acceptance": {
            "all_microbenchmarks_pass": passed,
            "terrain_coupling_rewrite": benchmarks[0]["passed"],
            "p74_template_response_active": bool(main["p74_template_response_active"]),
            "passive_margin_lowland_object_layer_active": bool(
                main["passive_margin_lowland_object_layer_active"]),
            "province_diversity_gate_ready": bool(
                main["province_diversity_status"] == "generated_world_gate_ready"),
            "lowland_and_basin_modes_present": bool(main["lowland_and_basin_modes_present"]),
            "rift_and_foreland_lows_present": bool(main["rift_and_foreland_lows_present"]),
            "old_orogen_expression_present": bool(main["old_orogen_expression_present"]),
            "highlands_parented_or_limited": bool(main["highlands_parented_or_limited"]),
            "bathymetry_regression_free": bool(main["bathymetry_regression_free"]),
            "compiler_regression_free": bool(main["compiler_regression_free"]),
            "release_promotion_audit_pending": True,
        },
    }


def _p75_archived_p69_summaries(root: Path) -> list[dict[str, Any]]:
    summaries: list[dict[str, Any]] = []
    pattern = "out_bench_p69_highres_physical_ensemble_visual_audit_20260626*/tectonics_bench_summary.json"
    for path in sorted(root.glob(pattern)):
        try:
            summary = json.loads(path.read_text())
        except Exception as exc:
            summaries.append({
                "path": str(path),
                "load_error": str(exc),
                "schema": "",
                "status": "unreadable",
                "summary": None,
            })
            continue
        summaries.append({
            "path": str(path),
            "load_error": "",
            "schema": str(summary.get("schema", "")),
            "status": str(summary.get("status", "")),
            "summary": summary,
        })
    return summaries


def _p75_select_archived_p69_summary(root: Path) -> dict[str, Any] | None:
    summaries = [
        item for item in _p75_archived_p69_summaries(root)
        if item["schema"] == "aevum.tectonics_bench.p69.v1"
        and isinstance(item.get("summary"), dict)
    ]
    passing = [item for item in summaries if item["status"] == "pass"]
    selected = passing[-1] if passing else (summaries[-1] if summaries else None)
    return selected


def _p75_asset_file_metrics(p69_metrics: dict[str, Any]) -> dict[str, Any]:
    rows = list(p69_metrics.get("per_member_metrics", []))
    key_assets = list(p69_metrics.get("key_assets", []))
    expected_key_asset_files = int(len(rows) * len(key_assets))
    actual_key_asset_files = 0
    member_asset_dirs_present = 0
    contact_sheets = set()
    for row in rows:
        asset_dir = str(row.get("asset_dir", ""))
        if asset_dir and Path(asset_dir).exists():
            member_asset_dirs_present += 1
        for path in row.get("asset_paths", []):
            if Path(path).exists():
                actual_key_asset_files += 1
        contact = str(row.get("contact_sheet", ""))
        if contact:
            contact_sheets.add(contact)
    contact_sheet_paths = sorted(contact_sheets)
    contact_sheet_present_count = int(sum(Path(path).exists() for path in contact_sheet_paths))
    return {
        "expected_key_asset_files": expected_key_asset_files,
        "actual_key_asset_files": int(actual_key_asset_files),
        "member_asset_dirs_present": int(member_asset_dirs_present),
        "contact_sheet_paths": contact_sheet_paths,
        "contact_sheet_present_count": contact_sheet_present_count,
        "all_key_asset_files_present": bool(
            expected_key_asset_files > 0
            and actual_key_asset_files == expected_key_asset_files
            and member_asset_dirs_present == len(rows)
            and contact_sheet_present_count >= 1
        ),
    }


def _bench_p75_release_and_promotion_audit(root: Path) -> dict[str, Any]:
    p69_summaries = _p75_archived_p69_summaries(root)
    selected = _p75_select_archived_p69_summary(root)
    if selected is None or not isinstance(selected.get("summary"), dict):
        p69_summary = None
        p69_metrics: dict[str, Any] = {}
        asset_metrics = {
            "expected_key_asset_files": 0,
            "actual_key_asset_files": 0,
            "member_asset_dirs_present": 0,
            "contact_sheet_paths": [],
            "contact_sheet_present_count": 0,
            "all_key_asset_files_present": False,
        }
    else:
        p69_summary = selected["summary"]
        p69_metrics = dict(p69_summary["benchmarks"][0]["metrics"])
        asset_metrics = _p75_asset_file_metrics(p69_metrics)

    gate_suites = {suite: run_suite(suite) for suite in ("P70", "P71", "P72", "P73", "P74")}
    legacy_suites = {suite: run_suite(suite) for suite in ("P29", "P48", "P49", "P68")}
    gate_statuses = {suite: summary["status"] for suite, summary in gate_suites.items()}
    legacy_statuses = {suite: summary["status"] for suite, summary in legacy_suites.items()}
    p70_acceptance = gate_suites["P70"]["acceptance"]
    p73_acceptance = gate_suites["P73"]["acceptance"]
    p74_acceptance = gate_suites["P74"]["acceptance"]

    p69_acceptance = {} if p69_summary is None else dict(p69_summary.get("acceptance", {}))
    p69_highres_ready = bool(p69_acceptance.get("highres_ready_all_members", False))
    p69_asset_sets_complete = bool(
        p69_acceptance.get("asset_sets_complete_all_members", False)
        and asset_metrics["all_key_asset_files_present"]
    )
    p69_archived_pass = bool(p69_summary is not None and p69_summary.get("status") == "pass")
    p69_promotion_ready = bool(p69_acceptance.get("promotion_ready", False))

    p70_p74_all_pass = all(summary["status"] == "pass" for summary in gate_suites.values())
    legacy_all_pass = all(summary["status"] == "pass" for summary in legacy_suites.values())
    reference_data_pending = bool(
        p70_acceptance.get("reference_data_download_required", False)
        or p73_acceptance.get("reference_raster_extraction_pending", False)
    )
    production_graph_pending = bool(p70_acceptance.get("production_province_graph_missing", False))
    terrain_rewrite_active = bool(
        p74_acceptance.get("terrain_coupling_rewrite", False)
        and not p74_acceptance.get("release_promotion_audit_pending", False)
    )
    p74_release_pending_seen = bool(p74_acceptance.get("release_promotion_audit_pending", False))

    blockers: list[str] = []
    if not p69_summary:
        blockers.append("p69_highres_summary_missing")
    if p69_summary and not p69_archived_pass:
        blockers.append("p69_highres_audit_failed")
    if not p69_asset_sets_complete:
        blockers.append("p69_highres_asset_files_incomplete")
    if not p69_highres_ready:
        blockers.append("p69_highres_members_not_ready")
    if not p70_p74_all_pass:
        blockers.append("p70_p74_gate_failure")
    if not legacy_all_pass:
        blockers.append("legacy_regression_gate_failure")
    if reference_data_pending:
        blockers.append("reference_data_download_or_raster_extraction_pending")
    if production_graph_pending:
        blockers.append("first_class_production_province_graph_pending")
    for blocker in p69_metrics.get("promotion_blockers", []):
        name = f"p69_{blocker}"
        if name not in blockers:
            blockers.append(name)

    audit_completed = bool(
        p69_archived_pass
        and p69_asset_sets_complete
        and p69_highres_ready
        and p70_p74_all_pass
        and legacy_all_pass
    )
    promotion_ready = bool(
        audit_completed
        and p69_promotion_ready
        and not reference_data_pending
        and not production_graph_pending
    )
    decision_recorded = bool(
        (promotion_ready and not blockers)
        or ((not promotion_ready) and bool(blockers))
    )
    pass_condition = bool(audit_completed and decision_recorded and not promotion_ready)

    metrics = {
        "p69_archived_summary_count": int(len([
            item for item in p69_summaries
            if item["schema"] == "aevum.tectonics_bench.p69.v1"
        ])),
        "p69_selected_summary_path": "" if selected is None else str(selected["path"]),
        "p69_selected_summary_status": "" if p69_summary is None else str(p69_summary.get("status", "")),
        "p69_cells": int(p69_metrics.get("cells", 0)),
        "p69_member_count": int(p69_metrics.get("member_count", 0)),
        "p69_asset_set_complete_count": int(p69_metrics.get("asset_set_complete_count", 0)),
        "p69_highres_member_ready_count": int(p69_metrics.get("highres_member_ready_count", 0)),
        "p69_earth_reference_screening_ready_count": int(
            p69_metrics.get("earth_reference_screening_ready_count", 0)),
        "p69_earth_reference_within_initial_envelope_count": int(
            p69_metrics.get("earth_reference_within_initial_envelope_count", 0)),
        "p69_earth_reference_out_of_envelope_max": int(
            p69_metrics.get("earth_reference_out_of_envelope_max", 0)),
        "p69_promotion_ready": p69_promotion_ready,
        "p69_archived_pass": p69_archived_pass,
        "p69_highres_ready_all_members": p69_highres_ready,
        "p69_asset_sets_complete": p69_asset_sets_complete,
        "p70_p74_gate_statuses": gate_statuses,
        "p70_p74_gate_pass_count": int(sum(status == "pass" for status in gate_statuses.values())),
        "legacy_gate_statuses": legacy_statuses,
        "legacy_gate_pass_count": int(sum(status == "pass" for status in legacy_statuses.values())),
        "reference_data_pending": reference_data_pending,
        "production_province_graph_pending": production_graph_pending,
        "p74_release_pending_seen": p74_release_pending_seen,
        "terrain_rewrite_active_after_p75": bool(
            p74_acceptance.get("terrain_coupling_rewrite", False)),
        "terrain_rewrite_promoted_by_p74": terrain_rewrite_active,
        "stage_a_next_step_ready": bool(
            audit_completed
            and reference_data_pending
            and production_graph_pending
        ),
        "promotion_blocker_count": int(len(blockers)),
        "promotion_blockers": blockers,
        "audit_completed": audit_completed,
        "promotion_ready": promotion_ready,
        "promotion_decision_recorded": decision_recorded,
        "keeps_default_off_until_stage_a_reference_metrics": bool(not promotion_ready),
        "next_recommended_suites": ["P76.reference_source_ledger_schema", "P77.real_earth_hypsometry_extraction"],
    }
    metrics.update(asset_metrics)
    return _result(
        "P75.release_and_promotion_audit",
        pass_condition,
        metrics,
        "P75 failed to combine P69 high-resolution assets, P70-P74 gates, legacy regression gates, and an explicit promotion decision",
    )


def run_p75_bench(root: Path = PROJECT_ROOT) -> dict[str, Any]:
    benchmarks = [_bench_p75_release_and_promotion_audit(root)]
    passed = all(b["passed"] for b in benchmarks)
    digest = _canonical_digest(benchmarks)
    main = benchmarks[0]["metrics"]
    return {
        "schema": "aevum.tectonics_bench.p75.v1",
        "suite": "P75",
        "status": "pass" if passed else "fail",
        "benchmarks": benchmarks,
        "determinism": {
            "summary_digest": digest,
            "passed": passed,
        },
        "acceptance": {
            "all_microbenchmarks_pass": passed,
            "release_and_promotion_audit": benchmarks[0]["passed"],
            "p69_highres_assets_available": bool(main["p69_asset_sets_complete"]),
            "p69_highres_ready_all_members": bool(main["p69_highres_ready_all_members"]),
            "p70_p74_gates_pass": bool(main["p70_p74_gate_pass_count"] == 5),
            "legacy_or_replacement_gates_pass": bool(main["legacy_gate_pass_count"] == 4),
            "promotion_decision_recorded": bool(main["promotion_decision_recorded"]),
            "promotion_ready": bool(main["promotion_ready"]),
            "keeps_default_off_until_stage_a_reference_metrics": bool(
                main["keeps_default_off_until_stage_a_reference_metrics"]),
            "stage_a_next_step_ready": bool(main["stage_a_next_step_ready"]),
        },
    }


def _bench_p76_reference_source_ledger_schema() -> dict[str, Any]:
    ledger = source_ledger_summary()
    metrics = {
        "source_count": int(ledger["source_count"]),
        "external_source_count": int(ledger["external_source_count"]),
        "internal_source_count": int(ledger["internal_source_count"]),
        "category_count": int(ledger["category_count"]),
        "required_field_count": int(len(ledger["required_fields"])),
        "missing_required_field_source_count": int(len(ledger["missing_required_fields"])),
        "invalid_phase_ref_source_count": int(len(ledger["invalid_phase_refs"])),
        "duplicate_source_id_count": int(len(ledger["duplicate_source_ids"])),
        "all_required_fields_present": bool(
            ledger["acceptance"]["all_required_fields_present"]),
        "source_ids_match_p70_inventory": bool(
            ledger["acceptance"]["source_ids_match_p70_inventory"]),
        "license_status_explicit": bool(
            ledger["acceptance"]["license_status_explicit"]),
        "source_version_note_explicit": bool(
            ledger["acceptance"]["source_version_note_explicit"]),
        "projection_resolution_note_explicit": bool(
            ledger["acceptance"]["projection_resolution_note_explicit"]),
        "raw_data_policy_explicit": bool(
            ledger["acceptance"]["raw_data_policy_explicit"]),
        "acquisition_separated_from_benchmarks": bool(
            ledger["acceptance"]["acquisition_separated_from_benchmarks"]),
        "derived_metric_targets_present": bool(
            ledger["acceptance"]["derived_metric_targets_present"]),
        "no_external_raw_data_required": bool(
            ledger["acceptance"]["no_external_raw_data_required"]),
    }
    passed = bool(
        ledger["status"] == "source_ledger_schema_ready"
        and all(ledger["acceptance"].values())
        and metrics["source_count"] >= 14
        and metrics["external_source_count"] >= 10
        and metrics["internal_source_count"] >= 1
        and metrics["category_count"] >= 4
        and metrics["required_field_count"] >= 12
        and metrics["missing_required_field_source_count"] == 0
        and metrics["invalid_phase_ref_source_count"] == 0
        and metrics["duplicate_source_id_count"] == 0
    )
    return _result(
        "P76.reference_source_ledger_schema",
        passed,
        metrics,
        "P76 source ledger schema is missing required metadata, explicit license/version/projection notes, or offline acquisition policy",
    )


