def _bench_p77_real_earth_hypsometry_extraction() -> dict[str, Any]:
    fixture = real_earth_hypsometry_fixture_summary()
    metrics = {
        "bin_count": int(fixture["bin_count"]),
        "bin_area_total": float(fixture["bin_area_total"]),
        "land_bin_area_total": float(fixture["land_bin_area_total"]),
        "ocean_bin_area_total": float(fixture["ocean_bin_area_total"]),
        "ocean_partition_sum": float(fixture["ocean_partition_sum"]),
        "missing_required_metric_count": int(len(fixture["missing_required_metrics"])),
        "land_fraction": float(fixture["metrics"]["land_fraction"]),
        "land_elevation_mean_m": float(fixture["metrics"]["land_elevation_mean_m"]),
        "land_elevation_p95_m": float(fixture["metrics"]["land_elevation_p95_m"]),
        "high_land_fraction_gt2500m": float(
            fixture["metrics"]["high_land_fraction_gt2500m"]),
        "lowland_fraction_lt500m": float(fixture["metrics"]["lowland_fraction_lt500m"]),
        "lowland_fraction_lt1000m": float(fixture["metrics"]["lowland_fraction_lt1000m"]),
        "ocean_depth_mean_m": float(fixture["metrics"]["ocean_depth_mean_m"]),
        "shelf_fraction_of_ocean": float(fixture["metrics"]["shelf_fraction_of_ocean"]),
        "slope_rise_fraction_of_ocean": float(
            fixture["metrics"]["slope_rise_fraction_of_ocean"]),
        "abyss_fraction_of_ocean": float(fixture["metrics"]["abyss_fraction_of_ocean"]),
        "shelf_to_abyss_depth_delta_m": float(
            fixture["metrics"]["shelf_to_abyss_depth_delta_m"]),
        "envelope_check_count": int(len(fixture["envelope_checks"])),
        "envelope_check_pass_count": int(sum(
            check["in_envelope"] for check in fixture["envelope_checks"].values())),
        "raw_raster_not_stored": bool(fixture["acceptance"]["raw_raster_not_stored"]),
        "direct_raster_extraction_marked_pending": bool(
            fixture["acceptance"]["direct_raster_extraction_marked_pending"]),
        "fixture_digest": fixture["fixture_digest"],
    }
    passed = bool(
        fixture["status"] == "hypsometry_fixture_ready"
        and all(fixture["acceptance"].values())
        and metrics["bin_count"] >= 10
        and abs(metrics["bin_area_total"] - 1.0) <= 1.0e-9
        and 0.25 <= metrics["land_fraction"] <= 0.33
        and 400.0 <= metrics["land_elevation_mean_m"] <= 1200.0
        and 1500.0 <= metrics["land_elevation_p95_m"] <= 5200.0
        and 0.0 <= metrics["high_land_fraction_gt2500m"] <= 0.18
        and 0.04 <= metrics["shelf_fraction_of_ocean"] <= 0.14
        and 0.10 <= metrics["slope_rise_fraction_of_ocean"] <= 0.35
        and 0.30 <= metrics["abyss_fraction_of_ocean"] <= 0.65
        and 1200.0 <= metrics["shelf_to_abyss_depth_delta_m"] <= 5200.0
        and metrics["envelope_check_pass_count"] == metrics["envelope_check_count"]
        and metrics["raw_raster_not_stored"]
        and metrics["direct_raster_extraction_marked_pending"]
    )
    return _result(
        "P77.real_earth_hypsometry_extraction",
        passed,
        metrics,
        "P77 real-Earth hypsometry fixture is incomplete, not area-balanced, outside the broad envelope, or unclear about raw raster policy",
    )


