def _p78_current_generated_hypsometry(cells: int = 900) -> dict[str, Any]:
    from aevum import validation
    from aevum.diagnostics.earth_reference import earth_reference_distribution_metrics
    from aevum.engine import Engine

    spec = get_preset("earthlike")
    spec.grid_cells = int(cells)
    spec.t_end_myr = 4500.0
    engine = Engine.build(spec)
    engine.run(n_frames=5)
    tectonics = validation.tectonic_diagnostics(engine)
    generated = generated_world_hypsometry_metrics(engine.world, tectonics)
    fixture = real_earth_hypsometry_fixture_summary()
    comparison = compare_metrics_to_fixture(generated, fixture["metrics"])
    earth_reference = earth_reference_distribution_metrics(
        engine.world, tectonics=tectonics)
    return {
        "cells": int(cells),
        "time_myr": float(engine.world.time_myr),
        "metrics": generated,
        "comparison": comparison,
        "earth_reference_status": str(earth_reference["status"]),
        "earth_reference_out_of_envelope": tuple(earth_reference["out_of_envelope"]),
        "earth_reference_out_of_envelope_count": int(len(earth_reference["out_of_envelope"])),
    }


def _p78_archived_highres_evidence(root: Path) -> dict[str, Any]:
    selected = _p75_select_archived_p69_summary(root)
    if selected is None or not isinstance(selected.get("summary"), dict):
        return {
            "available": False,
            "selected_summary_path": "",
            "status": "",
            "cells": 0,
            "member_count": 0,
            "highres_member_ready_count": 0,
            "earth_reference_out_of_envelope_max": 0,
            "earthlike_reference_out_of_envelope": (),
            "earthlike_reference_out_of_envelope_count": 0,
        }
    summary = selected["summary"]
    metrics = summary["benchmarks"][0]["metrics"]
    reference_rows = [
        row for row in metrics.get("per_member_metrics", [])
        if str(row.get("member_name", "")) == "earthlike_reference_physical_member"
    ]
    reference_row = reference_rows[0] if reference_rows else {}
    return {
        "available": True,
        "selected_summary_path": str(selected["path"]),
        "status": str(summary.get("status", "")),
        "cells": int(metrics.get("cells", 0)),
        "member_count": int(metrics.get("member_count", 0)),
        "highres_member_ready_count": int(metrics.get("highres_member_ready_count", 0)),
        "earth_reference_out_of_envelope_max": int(
            metrics.get("earth_reference_out_of_envelope_max", 0)),
        "earthlike_reference_out_of_envelope": tuple(
            reference_row.get("earth_reference_out_of_envelope", ())),
        "earthlike_reference_out_of_envelope_count": int(
            reference_row.get("earth_reference_out_of_envelope_count", 0)),
    }


def _bench_p78_generated_hypsometry_envelope(root: Path) -> dict[str, Any]:
    fixture = real_earth_hypsometry_fixture_summary()
    current = _p78_current_generated_hypsometry(cells=900)
    highres = _p78_archived_highres_evidence(root)
    comparison = current["comparison"]
    generated = current["metrics"]
    current_out = tuple(current["earth_reference_out_of_envelope"])
    expected_residuals = {
        "land_fraction",
        "land_component_count",
        "land_ribbon_fraction_gt_0_5",
        "land_coastline_complexity_largest",
        "trench_fraction_of_ocean",
    }
    residuals_recorded = bool(current_out) and set(current_out).issubset(expected_residuals)
    metrics = {
        "cells": int(current["cells"]),
        "fixture_status": str(fixture["status"]),
        "fixture_comparable_metric_count": int(comparison["comparable_metric_count"]),
        "generated_land_fraction": float(generated["land_fraction"]),
        "generated_land_elevation_mean_m": float(generated["land_elevation_mean_m"]),
        "generated_land_elevation_p95_m": float(generated["land_elevation_p95_m"]),
        "generated_high_land_fraction_gt2500m": float(
            generated["high_land_fraction_gt2500m"]),
        "generated_lowland_fraction_lt500m": float(generated["lowland_fraction_lt500m"]),
        "generated_lowland_fraction_lt1000m": float(generated["lowland_fraction_lt1000m"]),
        "generated_shelf_fraction_of_ocean": float(generated["shelf_fraction_of_ocean"]),
        "generated_slope_rise_fraction_of_ocean": float(
            generated["slope_rise_fraction_of_ocean"]),
        "generated_abyss_fraction_of_ocean": float(generated["abyss_fraction_of_ocean"]),
        "generated_shelf_to_abyss_depth_delta_m": float(
            generated["shelf_to_abyss_depth_delta_m"]),
        "core_hypsometry_envelope_pass": bool(
            comparison["core_hypsometry_envelope_pass"]),
        "land_fraction_close_to_fixture": bool(
            comparison["land_fraction_close_to_fixture"]),
        "lowland_ordering_plausible": bool(
            comparison["lowland_ordering_plausible"]),
        "current_out_of_envelope_count": int(current["earth_reference_out_of_envelope_count"]),
        "current_out_of_envelope": current_out,
        "current_expected_residuals_recorded": residuals_recorded,
        "archived_highres_available": bool(highres["available"]),
        "archived_highres_status": str(highres["status"]),
        "archived_highres_cells": int(highres["cells"]),
        "archived_highres_member_ready_count": int(
            highres["highres_member_ready_count"]),
        "archived_highres_member_count": int(highres["member_count"]),
        "archived_highres_out_of_envelope_max": int(
            highres["earth_reference_out_of_envelope_max"]),
        "archived_earthlike_reference_out_of_envelope_count": int(
            highres["earthlike_reference_out_of_envelope_count"]),
        "archived_earthlike_reference_out_of_envelope": tuple(
            highres["earthlike_reference_out_of_envelope"]),
        "promotion_calibration_still_required": True,
        "p79_province_reference_graph_extraction_pending": True,
    }
    passed = bool(
        fixture["status"] == "hypsometry_fixture_ready"
        and metrics["fixture_comparable_metric_count"] >= 12
        and metrics["core_hypsometry_envelope_pass"]
        and metrics["land_fraction_close_to_fixture"]
        and metrics["lowland_ordering_plausible"]
        and residuals_recorded
        and metrics["archived_highres_available"]
        and metrics["archived_highres_status"] == "pass"
        and metrics["archived_highres_cells"] == 8000
        and metrics["archived_highres_member_ready_count"] == metrics["archived_highres_member_count"] == 3
        and metrics["archived_highres_out_of_envelope_max"] <= 6
    )
    return _result(
        "P78.generated_hypsometry_envelope",
        passed,
        metrics,
        "P78 generated-world hypsometry failed the P77 fixture comparison, lost archived P69 high-resolution evidence, or failed to record residual calibration blockers",
    )


