def _bench_p82_wilson_cycle_lifecycle_reference(
    summary: dict[str, Any] | None = None,
) -> dict[str, Any]:
    summary = summary or _p82_wilson_cycle_lifecycle(cells=900)
    reference = summary["scripted_reference"]
    current = summary["current_generated"]
    object_counts = reference["object_set_counts"]
    current_counts = current["object_counts"]
    metrics = {
        "reference_status": str(reference["status"]),
        "current_status": str(current["status"]),
        "scripted_frame_count": int(reference["frame_count"]),
        "scripted_stage_sequence": tuple(reference["stage_sequence"]),
        "scripted_unique_basin_id_count": int(len(reference["unique_basin_ids"])),
        "scripted_unique_lineage_key_count": int(len(reference["unique_lineage_keys"])),
        "scripted_phase_codes": tuple(reference["phase_codes"]),
        "scripted_required_object_set_count": int(len(object_counts)),
        "scripted_required_object_sets_observed_count": int(sum(
            1 for count in object_counts.values() if int(count) > 0)),
        "scripted_gateway_status_count": int(len(reference["gateway_statuses"])),
        "scripted_gateway_statuses": tuple(reference["gateway_statuses"]),
        "scripted_parent_link_failure_count": int(len(reference["parent_link_failures"])),
        "scripted_old_orogen_relict_count": int(reference["old_orogen_relict_count"]),
        "scripted_basin_age_final_myr": float(reference["basin_ages_myr"][-1]),
        "current_ocean_basin_count": int(current_counts["tectonics.ocean_basins"]),
        "current_wilson_cycle_count": int(current_counts["tectonics.wilson_cycles"]),
        "current_gateway_count": int(current_counts["tectonics.ocean_gateways"]),
        "current_rift_system_count": int(current_counts["tectonics.rift_systems"]),
        "current_passive_margin_count": int(current_counts["tectonics.passive_margins"]),
        "current_spreading_center_count": int(current_counts["tectonics.spreading_centers"]),
        "current_closing_margin_count": int(current_counts["tectonics.closing_margins"]),
        "current_suture_count": int(current_counts["tectonics.sutures"]),
        "current_missing_object_sets": tuple(current["missing_object_sets"]),
        "current_unexpected_missing_object_sets": tuple(
            current["unexpected_missing_object_sets"]),
        "current_basin_stage_count": int(len(current["basin_stage_counts"])),
        "current_gateway_status_count": int(len(current["gateway_status_counts"])),
        "current_active_phase_code_count": int(len(current["active_phase_codes"])),
        "current_parent_link_failure_count": int(len(current["parent_link_failures"])),
        "current_spreading_center_residual_recorded": bool(
            current["limitations"]["current_spreading_center_objects_missing"]),
        "current_spreading_center_objects_available": (
            int(current_counts["tectonics.spreading_centers"]) > 0
            and not current["limitations"]["current_spreading_center_objects_missing"]
        ),
        "p83_crust_sediment_province_coupling_pending": True,
    }
    passed = bool(
        summary["status"] == "wilson_cycle_lifecycle_reference_ready"
        and reference["status"] == "scripted_wilson_cycle_reference_ready"
        and current["status"] == "generated_world_wilson_lifecycle_ready"
        and all(reference["acceptance"].values())
        and all(current["acceptance"].values())
        and metrics["scripted_frame_count"] == 7
        and metrics["scripted_stage_sequence"] == tuple(reference["expected_stage_sequence"])
        and metrics["scripted_unique_basin_id_count"] == 1
        and metrics["scripted_unique_lineage_key_count"] == 1
        and metrics["scripted_required_object_sets_observed_count"] == metrics["scripted_required_object_set_count"]
        and metrics["scripted_gateway_status_count"] >= 5
        and metrics["scripted_parent_link_failure_count"] == 0
        and metrics["scripted_old_orogen_relict_count"] >= 1
        and metrics["scripted_basin_age_final_myr"] >= 500.0
        and metrics["current_ocean_basin_count"] > 0
        and metrics["current_wilson_cycle_count"] > 0
        and metrics["current_gateway_count"] > 0
        and metrics["current_rift_system_count"] > 0
        and metrics["current_passive_margin_count"] > 0
        and metrics["current_spreading_center_count"] > 0
        and metrics["current_closing_margin_count"] > 0
        and metrics["current_suture_count"] > 0
        and metrics["current_missing_object_sets"] == ()
        and not metrics["current_unexpected_missing_object_sets"]
        and metrics["current_basin_stage_count"] >= 3
        and metrics["current_gateway_status_count"] >= 3
        and metrics["current_active_phase_code_count"] >= 3
        and metrics["current_parent_link_failure_count"] == 0
        and metrics["current_spreading_center_objects_available"]
    )
    return _result(
        "P82.wilson_cycle_lifecycle_reference",
        passed,
        metrics,
        "P82 Wilson-cycle lifecycle reference is incomplete, scripted lifecycle continuity failed, generated-world parent causality is broken, or current residuals are not recorded",
    )


