def _p91_render_ci_assets(engine: Any, compiled: Any, outdir: Path) -> dict[str, str]:
    from aevum import render

    outdir.mkdir(parents=True, exist_ok=True)
    render.render_world(engine.world, outdir)
    render.render_hexmap(compiled, outdir)
    render.render_compiler_consistency(compiled, outdir)
    render.render_timeline(engine.archive.timeline(), outdir)
    render.render_history(engine.archive, outdir)
    render.render_archive_continuity(engine, outdir)
    return {
        asset: str(outdir / asset)
        for asset in P91_REQUIRED_REVIEW_ASSETS
        if (outdir / asset).exists()
    }


def _p91_ci_world_audit_rows(outdir: Path | None) -> tuple[list[dict[str, Any]], dict[str, Any]]:
    from aevum import validation
    from aevum.compiler.map_compiler import MapCompiler
    from aevum.engine import Engine

    rows: list[dict[str, Any]] = []
    root_inventory: dict[str, Any] | None = None
    for cells in (900, 2500):
        spec = get_preset("earthlike")
        spec.grid_cells = int(cells)
        spec.t_end_myr = 4500.0
        engine = Engine.build(spec)
        engine.run(n_frames=5)
        compiled = MapCompiler(engine.world, engine.archive).compile(
            width=72,
            height=36,
            n_starts=4,
        )
        asset_dir = None if outdir is None else outdir / "ci_world_assets" / f"earthlike_{cells}cells"
        asset_paths = (
            {}
            if asset_dir is None
            else _p91_render_ci_assets(engine, compiled, asset_dir)
        )
        tectonics = validation.tectonic_diagnostics(engine)
        compiler_metrics = validation.compiler_consistency_metrics(engine, compiled)
        inventory = current_world_morphology_gap_inventory_summary(
            engine.world,
            tectonics=tectonics,
            compiler_metrics=compiler_metrics,
            asset_paths=asset_paths,
        )
        non_asset_gap_count = int(sum(
            1
            for gap in inventory.get("gaps", ())
            if gap.get("category") != "asset_review_pending"
        ))
        metrics = inventory["metrics"]
        direct = inventory["direct_surface_metrics"]
        row = {
            "cells": int(cells),
            "world_time_myr": float(engine.world.time_myr),
            "asset_dir": "" if asset_dir is None else str(asset_dir),
            "required_asset_paths": tuple(asset_paths.get(asset, "")
                                          for asset in P91_REQUIRED_REVIEW_ASSETS),
            "required_asset_present_count": int(len(asset_paths)),
            "asset_set_complete": bool(
                len(asset_paths) == len(P91_REQUIRED_REVIEW_ASSETS)),
            "missing_review_assets": tuple(inventory["missing_review_assets"]),
            "inventory_status": str(inventory["status"]),
            "gap_count": int(metrics["gap_count"]),
            "non_asset_gap_count": int(non_asset_gap_count),
            "owner_layer_count": int(metrics["owner_layer_count"]),
            "category_count": int(metrics["category_count"]),
            "unassigned_gap_count": int(metrics["unassigned_gap_count"]),
            "generic_blocker_count": int(metrics["generic_blocker_count"]),
            "compiler_passed_envelope": bool(metrics["compiler_passed_envelope"]),
            "compiler_broad_land_to_water_fraction": float(
                metrics["compiler_broad_land_to_water_fraction"]),
            "compiler_broad_ocean_to_land_fraction": float(
                metrics["compiler_broad_ocean_to_land_fraction"]),
            "compiler_shelf_as_deep_ocean_fraction": float(
                metrics["compiler_shelf_as_deep_ocean_fraction"]),
            "compiler_lowland_as_mountain_fraction": float(
                metrics["compiler_lowland_as_mountain_fraction"]),
            "compiler_terrain_elevation_sign_mismatch_fraction": float(
                metrics["compiler_terrain_elevation_sign_mismatch_fraction"]),
            "high_flat_interior_fraction_of_continental_land": float(
                direct["high_flat_interior_fraction_of_continental_land"]),
            "highland_without_parent_fraction_of_highlands": float(
                direct["highland_without_parent_fraction_of_highlands"]),
            "basin_lowland_fraction_of_continental_land": float(
                direct["basin_lowland_fraction_of_continental_land"]),
            "lowland_fraction_lt500m_of_continental_land": float(
                direct["lowland_fraction_lt500m_of_continental_land"]),
            "lowland_fraction_lt1000m_of_continental_land": float(
                direct["lowland_fraction_lt1000m_of_continental_land"]),
            "major_component_count": int(direct["major_component_count"]),
            "owner_counts": dict(inventory["owner_counts"]),
            "category_counts": dict(inventory["category_counts"]),
            "current_residual_items": tuple(inventory["current_residual_items"]),
            "inventory_digest": str(inventory["summary_digest"]),
            "world": engine.world,
            "compiled": compiled,
            "inventory": inventory,
        }
        rows.append(row)
        if cells == 900:
            root_inventory = inventory
    if root_inventory is None:
        raise RuntimeError("P91 failed to build the 900-cell root inventory")
    return rows, root_inventory


def _p91_current_stage_summaries_from_world(world: Any) -> dict[str, dict[str, Any]]:
    cells = int(world.grid.n)
    world_time = float(world.time_myr)

    p83 = crust_sediment_province_coupling_summary(world)
    p83["cells"] = cells
    p83["world_time_myr"] = world_time
    p83_bench = _bench_p83_crust_sediment_province_coupling(p83)

    p84 = source_to_sink_sediment_budget_summary(world)
    p84["cells"] = cells
    p84["world_time_myr"] = world_time
    p84_bench = _bench_p84_source_to_sink_sediment_budget(p84)

    p85 = drainage_divide_province_alignment_summary(world)
    p85["cells"] = cells
    p85["world_time_myr"] = world_time
    p85_bench = _bench_p85_drainage_divide_province_alignment(p85)

    p86 = old_orogen_erosion_decay_summary(world)
    p86["cells"] = cells
    p86["world_time_myr"] = world_time
    p86_bench = _bench_p86_old_orogen_erosion_decay(p86)

    p87 = mountain_inventory_expression_summary(world)
    p87["cells"] = cells
    p87["world_time_myr"] = world_time
    p87_bench = _bench_p87_mountain_inventory_expression(p87)

    p88 = rift_margin_escarpment_sequence_summary(world)
    p88["cells"] = cells
    p88["world_time_myr"] = world_time
    p88_bench = _bench_p88_rift_margin_escarpment_sequence(p88)

    p89 = plateau_area_cap_and_decay_summary(world)
    p89["cells"] = cells
    p89["world_time_myr"] = world_time
    p89_bench = _bench_p89_plateau_area_cap_and_decay(p89)

    return {
        "P83": {
            "schema": "aevum.tectonics_bench.p83.v1",
            "suite": "P83",
            "status": "pass" if p83_bench["passed"] else "fail",
            "benchmarks": [p83_bench],
            "acceptance": {"all_microbenchmarks_pass": bool(p83_bench["passed"])},
        },
        "P84": {
            "schema": "aevum.tectonics_bench.p84.v1",
            "suite": "P84",
            "status": "pass" if p84_bench["passed"] else "fail",
            "benchmarks": [p84_bench],
            "acceptance": {"all_microbenchmarks_pass": bool(p84_bench["passed"])},
        },
        "P85": {
            "schema": "aevum.tectonics_bench.p85.v1",
            "suite": "P85",
            "status": "pass" if p85_bench["passed"] else "fail",
            "benchmarks": [p85_bench],
            "acceptance": {"all_microbenchmarks_pass": bool(p85_bench["passed"])},
        },
        "P86": {
            "schema": "aevum.tectonics_bench.p86.v1",
            "suite": "P86",
            "status": "pass" if p86_bench["passed"] else "fail",
            "benchmarks": [p86_bench],
            "acceptance": {"all_microbenchmarks_pass": bool(p86_bench["passed"])},
        },
        "P87": {
            "schema": "aevum.tectonics_bench.p87.v1",
            "suite": "P87",
            "status": "pass" if p87_bench["passed"] else "fail",
            "benchmarks": [p87_bench],
            "acceptance": {"all_microbenchmarks_pass": bool(p87_bench["passed"])},
        },
        "P88": {
            "schema": "aevum.tectonics_bench.p88.v1",
            "suite": "P88",
            "status": "pass" if p88_bench["passed"] else "fail",
            "benchmarks": [p88_bench],
            "acceptance": {"all_microbenchmarks_pass": bool(p88_bench["passed"])},
        },
        "P89": {
            "schema": "aevum.tectonics_bench.p89.v1",
            "suite": "P89",
            "status": "pass" if p89_bench["passed"] else "fail",
            "benchmarks": [p89_bench],
            "acceptance": {"all_microbenchmarks_pass": bool(p89_bench["passed"])},
        },
    }


def _p91_integrated_real_earth_morphology_promotion_audit(
    root: Path = PROJECT_ROOT,
    outdir: Path | None = None,
) -> dict[str, Any]:
    selected = _p75_select_archived_p69_summary(root)
    p69_summary = (
        selected.get("summary")
        if selected is not None and isinstance(selected.get("summary"), dict)
        else None
    )
    ci_rows, root_inventory = _p91_ci_world_audit_rows(outdir)
    contact_sheet = None
    if outdir is not None:
        contact_sheet = render_ci_world_contact_sheet(
            ci_rows,
            outdir / "p91_ci_world_contact_sheet.png",
        )
    current_stage_summaries = _p91_current_stage_summaries_from_world(
        ci_rows[0]["world"])
    current_stage_summaries["P90"] = {
        "schema": "aevum.tectonics_bench.p90.v1",
        "suite": "P90",
        "status": "pass" if root_inventory["status"].endswith("_ready") else "fail",
        "benchmarks": [{
            "name": "P90.current_world_morphology_gap_inventory",
            "passed": root_inventory["status"].endswith("_ready"),
        }],
        "acceptance": {
            "all_microbenchmarks_pass": root_inventory["status"].endswith("_ready")
            and root_inventory["metrics"]["unassigned_gap_count"] == 0
            and root_inventory["metrics"]["generic_blocker_count"] == 0,
        },
    }
    stage_matrix = latest_stage_summary_matrix(
        root,
        current_summaries=current_stage_summaries,
    )
    highres_assets = highres_review_asset_metrics(root, p69_summary)
    ci_review = ci_world_review_metrics(ci_rows, contact_sheet)
    return promotion_audit_summary(
        stage_matrix=stage_matrix,
        highres_assets=highres_assets,
        ci_review=ci_review,
        ci_rows=ci_rows,
        root_p90_inventory=root_inventory,
    )


