def _p93_target_by_metric(
    calibration: dict[str, Any],
    metric: str,
) -> dict[str, Any]:
    for target in calibration.get("calibration_targets", ()):
        if target.get("metric") == metric:
            return target
    return {}


def _bench_p93_generated_component_ribbon_envelope(
    calibration: dict[str, Any] | None = None,
) -> dict[str, Any]:
    calibration = calibration or planform_reference_calibration_summary(PROJECT_ROOT)
    generated = calibration["generated_envelope"]
    component = generated["land_component_count"]
    ribbon = generated["land_ribbon_fraction_gt_0_5"]
    coastline = generated["land_coastline_complexity_largest"]
    land_fraction = generated["land_fraction"]
    component_target = _p93_target_by_metric(calibration, "land_component_count")
    ribbon_target = _p93_target_by_metric(calibration, "land_ribbon_fraction_gt_0_5")
    coastline_target = _p93_target_by_metric(
        calibration,
        "land_coastline_complexity_largest",
    )
    land_target = _p93_target_by_metric(calibration, "land_fraction")
    metrics = {
        "generated_envelope_metric_count": int(
            calibration["metrics"]["generated_envelope_metric_count"]),
        "current_900_land_fraction": float(land_fraction["current_900_value"]),
        "current_900_land_fraction_direction": str(
            land_target["current_900_direction"]),
        "current_900_component_count": float(component["current_900_value"]),
        "current_900_component_direction": str(
            component_target["current_900_direction"]),
        "current_900_ribbon_fraction": float(ribbon["current_900_value"]),
        "current_900_ribbon_direction": str(ribbon_target["current_900_direction"]),
        "current_900_coastline_complexity": float(coastline["current_900_value"]),
        "current_900_coastline_direction": str(
            coastline_target["current_900_direction"]),
        "p69_earthlike_component_count": float(component["p69_earthlike_value"]),
        "p69_earthlike_ribbon_fraction": float(ribbon["p69_earthlike_value"]),
        "p69_earthlike_coastline_complexity": float(
            coastline["p69_earthlike_value"]),
        "p69_member_count": int(component["p69_member_count"]),
        "p69_component_in_envelope_count": int(
            component["p69_member_in_envelope_count"]),
        "p69_ribbon_in_envelope_count": int(ribbon["p69_member_in_envelope_count"]),
        "p69_coastline_in_envelope_count": int(
            coastline["p69_member_in_envelope_count"]),
        "does_not_promote_default": bool(
            calibration["metrics"]["does_not_promote_default"]),
        "candidate_microbenchmarks_declared": bool(
            calibration["acceptance"]["candidate_microbenchmarks_declared"]),
    }
    passed = bool(
        calibration["status"] == "planform_reference_calibration_ready"
        and metrics["generated_envelope_metric_count"] == 5
        and metrics["current_900_land_fraction_direction"] == "increase"
        and metrics["current_900_component_direction"] == "increase"
        and metrics["current_900_ribbon_direction"] == "decrease"
        and metrics["current_900_coastline_direction"] == "decrease"
        and metrics["current_900_component_count"] < component["reference_min"]
        and metrics["current_900_ribbon_fraction"] > ribbon["reference_max"]
        and metrics["current_900_coastline_complexity"] > coastline["reference_max"]
        and metrics["p69_member_count"] >= 3
        and metrics["candidate_microbenchmarks_declared"]
        and metrics["does_not_promote_default"]
    )
    return _result(
        "P93.generated_component_ribbon_envelope",
        passed,
        metrics,
        "P93 failed to preserve generated-world component/ribbon/coastline calibration directions for the first production planform repair",
    )


