def _p96_crust_sediment_surface_world(cells: int = 900) -> dict[str, Any]:
    from aevum.engine import Engine

    spec = get_preset("earthlike")
    spec.grid_cells = int(cells)
    spec.t_end_myr = 4500.0
    engine = Engine.build(spec)
    engine.run(n_frames=5)
    graph = production_province_graph_summary(engine.world)
    coupling = crust_sediment_province_coupling_summary(engine.world)
    inventory = current_world_morphology_gap_inventory_summary(engine.world)
    direct = inventory["direct_surface_metrics"]
    telemetry_keys = (
        "terrain.last_p96_surface_ordering_area_fraction",
        "terrain.last_p96_surface_ordering_mean_abs_m",
        "terrain.last_p96_platform_raise_area_fraction",
        "terrain.last_p96_basin_lower_area_fraction",
        "terrain.last_p96_high_flat_fraction_before",
        "terrain.last_p96_high_flat_fraction_after",
    )
    telemetry = {
        key: float(engine.world.g(key, 0.0))
        for key in telemetry_keys
    }
    summary = {
        "cells": int(cells),
        "world_time_myr": float(engine.world.time_myr),
        "production_graph": graph,
        "crust_sediment_coupling": coupling,
        "direct_surface_metrics": {
            "high_flat_interior_fraction_of_continental_land": float(
                direct["high_flat_interior_fraction_of_continental_land"]),
            "basin_lowland_fraction_of_continental_land": float(
                direct["basin_lowland_fraction_of_continental_land"]),
            "lowland_fraction_lt500m_of_continental_land": float(
                direct["lowland_fraction_lt500m_of_continental_land"]),
            "lowland_fraction_lt1000m_of_continental_land": float(
                direct["lowland_fraction_lt1000m_of_continental_land"]),
            "highland_without_parent_fraction_of_highlands": float(
                direct["highland_without_parent_fraction_of_highlands"]),
            "major_component_count": int(direct["major_component_count"]),
        },
        "p96_terrain_telemetry": telemetry,
    }
    summary["summary_digest"] = _canonical_digest(summary)
    return summary


def _bench_p96_high_flat_interior_owner_reduction(
    worlds: dict[int, dict[str, Any]] | None = None,
) -> dict[str, Any]:
    worlds = worlds or {
        900: _p96_crust_sediment_surface_world(900),
        2500: _p96_crust_sediment_surface_world(2500),
    }
    direct_rows = {
        int(cells): row["direct_surface_metrics"]
        for cells, row in worlds.items()
    }
    telemetry_rows = {
        int(cells): row["p96_terrain_telemetry"]
        for cells, row in worlds.items()
    }
    metrics = {
        "world_count": int(len(worlds)),
        "max_high_flat_interior_fraction_of_continental_land": float(max(
            row["high_flat_interior_fraction_of_continental_land"]
            for row in direct_rows.values())),
        "min_basin_lowland_fraction_of_continental_land": float(min(
            row["basin_lowland_fraction_of_continental_land"]
            for row in direct_rows.values())),
        "min_lowland_fraction_lt500m_of_continental_land": float(min(
            row["lowland_fraction_lt500m_of_continental_land"]
            for row in direct_rows.values())),
        "min_lowland_fraction_lt1000m_of_continental_land": float(min(
            row["lowland_fraction_lt1000m_of_continental_land"]
            for row in direct_rows.values())),
        "max_highland_without_parent_fraction_of_highlands": float(max(
            row["highland_without_parent_fraction_of_highlands"]
            for row in direct_rows.values())),
        "min_major_component_count": int(min(
            row["major_component_count"] for row in direct_rows.values())),
        "max_p96_high_flat_fraction_after": float(max(
            row["terrain.last_p96_high_flat_fraction_after"]
            for row in telemetry_rows.values())),
        "max_p96_high_flat_fraction_before": float(max(
            row["terrain.last_p96_high_flat_fraction_before"]
            for row in telemetry_rows.values())),
        "max_surface_ordering_mean_abs_m": float(max(
            row["terrain.last_p96_surface_ordering_mean_abs_m"]
            for row in telemetry_rows.values())),
        "worlds_with_surface_ordering_telemetry": int(sum(
            "terrain.last_p96_surface_ordering_area_fraction" in row
            for row in telemetry_rows.values())),
    }
    passed = bool(
        metrics["world_count"] == 2
        and metrics["max_high_flat_interior_fraction_of_continental_land"] <= 0.080
        and metrics["min_basin_lowland_fraction_of_continental_land"] >= 0.20
        and metrics["min_lowland_fraction_lt500m_of_continental_land"] >= 0.20
        and metrics["min_lowland_fraction_lt1000m_of_continental_land"] >= 0.45
        and metrics["max_highland_without_parent_fraction_of_highlands"] <= 0.35
        and metrics["min_major_component_count"] >= 2
        and metrics["max_p96_high_flat_fraction_after"] <= 0.020
        and metrics["worlds_with_surface_ordering_telemetry"] == 2
    )
    return _result(
        "P96.high_flat_interior_owner_reduction",
        passed,
        metrics,
        "P96 failed to keep high flat interiors low while preserving basin/lowland area and parented highlands in generated worlds",
    )


def _bench_p96_province_crust_sediment_surface_ordering(
    worlds: dict[int, dict[str, Any]] | None = None,
) -> dict[str, Any]:
    worlds = worlds or {
        900: _p96_crust_sediment_surface_world(900),
        2500: _p96_crust_sediment_surface_world(2500),
    }
    graph_rows = {
        int(cells): row["production_graph"]
        for cells, row in worlds.items()
    }
    coupling_rows = {
        int(cells): row["crust_sediment_coupling"]["current_generated"]
        for cells, row in worlds.items()
    }
    graph_metrics = {
        int(cells): row["metrics"]
        for cells, row in graph_rows.items()
    }
    coupling_metrics = {
        int(cells): row["metrics"]
        for cells, row in coupling_rows.items()
    }
    basin_minus_platform = {
        cells: (
            float(metrics["basin_lowland_mean_elevation_m"])
            - float(metrics["platform_mean_elevation_m"])
        )
        for cells, metrics in coupling_metrics.items()
    }
    sediment_margin = {
        cells: (
            float(metrics["basin_lowland_mean_sediment_m"])
            - float(metrics["platform_mean_sediment_m"])
        )
        for cells, metrics in coupling_metrics.items()
    }
    orogen_margin = {
        cells: (
            float(metrics["orogen_mean_elevation_m"])
            - float(metrics["basin_lowland_mean_elevation_m"])
        )
        for cells, metrics in coupling_metrics.items()
    }
    metrics = {
        "world_count": int(len(worlds)),
        "production_graph_ready_world_count": int(sum(
            row["status"] == "production_province_graph_ready"
            for row in graph_rows.values())),
        "coupling_ready_world_count": int(sum(
            row["status"] == "generated_world_crust_sediment_province_audit_ready"
            for row in coupling_rows.values())),
        "min_province_class_count": int(min(
            row["province_class_count"] for row in graph_metrics.values())),
        "min_parent_process_count": int(min(
            row["parent_process_count"] for row in graph_metrics.values())),
        "max_missing_required_class_count": int(max(
            row["missing_required_class_count"] for row in graph_metrics.values())),
        "max_missing_required_edge_count": int(max(
            row["missing_required_edge_count"] for row in graph_metrics.values())),
        "max_p80_missing_reference_class_count": int(max(
            row["p80_missing_reference_class_count"] for row in graph_metrics.values())),
        "max_p80_missing_required_class_edge_count": int(max(
            row["p80_missing_required_class_edge_count"] for row in graph_metrics.values())),
        "min_platform_area_fraction": float(min(
            float(row["province_class_area_fractions"].get("platform", 0.0))
            for row in graph_rows.values())),
        "min_intracratonic_basin_area_fraction": float(min(
            float(row["province_class_area_fractions"].get(
                "intracratonic_basin", 0.0))
            for row in graph_rows.values())),
        "min_foreland_basin_area_fraction": float(min(
            float(row["province_class_area_fractions"].get("foreland_basin", 0.0))
            for row in graph_rows.values())),
        "max_basin_minus_platform_elevation_m": float(max(
            basin_minus_platform.values())),
        "min_basin_minus_platform_sediment_m": float(min(
            sediment_margin.values())),
        "min_orogen_minus_basin_elevation_m": float(min(
            orogen_margin.values())),
        "production_aggregation_world_count": int(sum(
            row["aggregation_source"] == "tectonics.continental_provinces"
            for row in coupling_rows.values())),
        "max_missing_production_field_count": int(max(
            row["metrics"]["missing_production_province_field_count"]
            for row in coupling_rows.values())),
    }
    passed = bool(
        metrics["world_count"] == 2
        and metrics["production_graph_ready_world_count"] == 2
        and metrics["coupling_ready_world_count"] == 2
        and metrics["min_province_class_count"] >= 9
        and metrics["min_parent_process_count"] >= 9
        and metrics["max_missing_required_class_count"] == 0
        and metrics["max_missing_required_edge_count"] == 0
        and metrics["max_p80_missing_reference_class_count"] == 0
        and metrics["max_p80_missing_required_class_edge_count"] <= 3
        and metrics["min_platform_area_fraction"] >= 0.003
        and metrics["min_intracratonic_basin_area_fraction"] > 0.0
        and metrics["min_foreland_basin_area_fraction"] > 0.0
        and metrics["max_basin_minus_platform_elevation_m"] < 0.0
        and metrics["min_basin_minus_platform_sediment_m"] >= 500.0
        and metrics["min_orogen_minus_basin_elevation_m"] >= 400.0
        and metrics["production_aggregation_world_count"] == 2
        and metrics["max_missing_production_field_count"] == 0
    )
    return _result(
        "P96.province_crust_sediment_surface_ordering",
        passed,
        metrics,
        "P96 failed to make production province graphs and generated surface fields obey crust/sediment/elevation ordering for platforms, basins, and highlands",
    )


def run_p96_bench(root: Path = PROJECT_ROOT) -> dict[str, Any]:
    del root
    worlds = {
        900: _p96_crust_sediment_surface_world(900),
        2500: _p96_crust_sediment_surface_world(2500),
    }
    benchmarks = [
        _bench_p96_high_flat_interior_owner_reduction(worlds),
        _bench_p96_province_crust_sediment_surface_ordering(worlds),
    ]
    passed = all(b["passed"] for b in benchmarks)
    digest = _canonical_digest({
        "benchmarks": benchmarks,
        "crust_sediment_surface_worlds": worlds,
    })
    flat = benchmarks[0]["metrics"]
    ordering = benchmarks[1]["metrics"]
    return {
        "schema": "aevum.tectonics_bench.p96.v1",
        "suite": "P96",
        "status": "pass" if passed else "fail",
        "benchmarks": benchmarks,
        "crust_sediment_surface_worlds": {
            str(cells): world for cells, world in worlds.items()
        },
        "determinism": {
            "summary_digest": digest,
            "passed": passed,
        },
        "acceptance": {
            "all_microbenchmarks_pass": passed,
            "high_flat_interior_owner_reduction": benchmarks[0]["passed"],
            "province_crust_sediment_surface_ordering": benchmarks[1]["passed"],
            "high_flat_interiors_below_current_floor": (
                flat["max_p96_high_flat_fraction_after"] <= 0.020),
            "basin_lowland_area_preserved": (
                flat["min_basin_lowland_fraction_of_continental_land"] >= 0.20),
            "production_province_graphs_ready": (
                ordering["production_graph_ready_world_count"] == 2),
            "production_coupling_audits_ready": (
                ordering["coupling_ready_world_count"] == 2),
            "platform_basin_orogen_surface_ordering": (
                ordering["max_basin_minus_platform_elevation_m"] < 0.0
                and ordering["min_orogen_minus_basin_elevation_m"] >= 400.0),
            "sediment_accommodation_signal_preserved": (
                ordering["min_basin_minus_platform_sediment_m"] >= 500.0),
            "p97_drainage_source_to_sink_fields_pending": True,
        },
    }


def _p97_drainage_source_to_sink_world(cells: int = 900) -> dict[str, Any]:
    from aevum.engine import Engine

    spec = get_preset("earthlike")
    spec.grid_cells = int(cells)
    spec.t_end_myr = 4500.0
    engine = Engine.build(spec)
    engine.run(n_frames=5)
    source_to_sink = source_to_sink_sediment_budget_summary(engine.world)
    drainage = drainage_divide_province_alignment_summary(engine.world)
    old_orogen = old_orogen_erosion_decay_summary(engine.world)
    return {
        "cells": int(cells),
        "world_time_myr": float(engine.world.time_myr),
        "source_to_sink": source_to_sink,
        "drainage": drainage,
        "old_orogen": old_orogen,
        "terrain_globals": {
            key: float(value)
            for key, value in sorted(engine.world.globals.items())
            if key.startswith("terrain.last_p97_")
        },
        "summary_digest": _canonical_digest({
            "cells": int(cells),
            "time": float(engine.world.time_myr),
            "source_to_sink": source_to_sink["summary_digest"],
            "drainage": drainage["summary_digest"],
            "old_orogen": old_orogen["summary_digest"],
        }),
    }


