def _p99_bathymetry_margin_sequence_world(cells: int) -> dict[str, Any]:
    from aevum.engine import Engine

    spec = get_preset("earthlike")
    spec.grid_cells = int(cells)
    spec.t_end_myr = 4500.0
    engine = Engine.build(spec)
    engine.run(n_frames=5)
    world = engine.world
    sequence = rift_margin_escarpment_sequence_summary(world)
    sequence["cells"] = int(cells)
    sequence["world_time_myr"] = float(world.time_myr)

    stage = np.asarray(world.field("terrain.rift_margin_stage"), dtype=np.float64)
    sequence_id = np.asarray(
        world.field("terrain.rift_margin_sequence_id"), dtype=np.float64)
    lineage_id = np.asarray(
        world.field("tectonics.rift_margin_lineage_id"), dtype=np.float64)
    rift_shoulders = np.asarray(
        world.field("terrain.rift_shoulders"), dtype=np.float64)
    escarpments = np.asarray(world.field("terrain.escarpments"), dtype=np.float64)
    elevation = np.asarray(world.field("terrain.elevation_m"), dtype=np.float64)
    sea = float(world.g("ocean.sea_level_m", 0.0))
    depth = np.maximum(sea - elevation, 0.0)

    def count_ids(values: np.ndarray) -> int:
        return int(len({int(value) for value in np.unique(values) if int(value) > 0}))

    def stage_mask(code: int) -> np.ndarray:
        return stage == float(code)

    def percentile(mask: np.ndarray, q: float) -> float:
        values = depth[np.asarray(mask, dtype=bool)]
        values = values[np.isfinite(values)]
        if values.size == 0:
            return float("nan")
        return float(np.percentile(values, q))

    field_metrics = {
        "sequence_id_count": count_ids(sequence_id),
        "lineage_id_count": count_ids(lineage_id),
        "rift_shoulder_id_count": count_ids(rift_shoulders),
        "escarpment_id_count": count_ids(escarpments),
        "sequence_cell_count": int(np.count_nonzero(sequence_id > 0.0)),
        "lineage_cell_count": int(np.count_nonzero(lineage_id > 0.0)),
        "rift_shoulder_cell_count": int(np.count_nonzero(rift_shoulders > 0.0)),
        "escarpment_cell_count": int(np.count_nonzero(escarpments > 0.0)),
        "stage_count": int(len({int(value) for value in np.unique(stage)
                                if int(value) > 0})),
        "passive_lowland_stage_cell_count": int(np.count_nonzero(
            stage_mask(RIFT_MARGIN_STAGE_PASSIVE_LOWLAND))),
        "shelf_stage_cell_count": int(np.count_nonzero(
            stage_mask(RIFT_MARGIN_STAGE_SHELF))),
        "slope_stage_cell_count": int(np.count_nonzero(
            stage_mask(RIFT_MARGIN_STAGE_SLOPE))),
        "rise_stage_cell_count": int(np.count_nonzero(
            stage_mask(RIFT_MARGIN_STAGE_RISE))),
        "abyss_stage_cell_count": int(np.count_nonzero(
            stage_mask(RIFT_MARGIN_STAGE_ABYSS))),
        "shelf_depth_p75_m": percentile(stage_mask(RIFT_MARGIN_STAGE_SHELF), 75.0),
        "slope_depth_p50_m": percentile(stage_mask(RIFT_MARGIN_STAGE_SLOPE), 50.0),
        "rise_depth_p50_m": percentile(stage_mask(RIFT_MARGIN_STAGE_RISE), 50.0),
        "abyss_depth_p50_m": percentile(stage_mask(RIFT_MARGIN_STAGE_ABYSS), 50.0),
        "sequence_object_count": int(len(
            world.objects.get("terrain.rift_margin_sequences", []))),
        "rift_shoulder_object_count": int(len(
            world.objects.get("terrain.rift_shoulders", []))),
        "escarpment_object_count": int(len(
            world.objects.get("terrain.escarpments", []))),
    }
    return {
        "cells": int(cells),
        "world_time_myr": float(world.time_myr),
        "rift_margin_escarpment_sequence": sequence,
        "field_metrics": field_metrics,
    }


def _bench_p99_production_rift_margin_sequence_fields(
    worlds: dict[int, dict[str, Any]]
) -> dict[str, Any]:
    current_metrics = {
        cells: world["rift_margin_escarpment_sequence"][
            "current_generated"]["metrics"]
        for cells, world in worlds.items()
    }
    field_metrics = {cells: world["field_metrics"] for cells, world in worlds.items()}
    metrics = {
        "world_count": int(len(worlds)),
        "sequence_ready_world_count": int(sum(
            1 for world in worlds.values()
            if world["rift_margin_escarpment_sequence"]["status"]
            == "rift_margin_escarpment_sequence_ready"
        )),
        "max_missing_sequence_item_count": int(max(
            row["missing_sequence_item_count"] for row in current_metrics.values()
        )),
        "min_sequence_id_count": int(min(
            row["sequence_id_count"] for row in field_metrics.values()
        )),
        "min_lineage_id_count": int(min(
            row["lineage_id_count"] for row in field_metrics.values()
        )),
        "min_stage_count": int(min(
            row["stage_count"] for row in field_metrics.values()
        )),
        "min_rift_shoulder_cell_count": int(min(
            row["rift_shoulder_cell_count"] for row in field_metrics.values()
        )),
        "min_escarpment_cell_count": int(min(
            row["escarpment_cell_count"] for row in field_metrics.values()
        )),
        "min_sequence_object_count": int(min(
            row["sequence_object_count"] for row in field_metrics.values()
        )),
        "min_rift_shoulder_object_count": int(min(
            row["rift_shoulder_object_count"] for row in field_metrics.values()
        )),
        "min_escarpment_object_count": int(min(
            row["escarpment_object_count"] for row in field_metrics.values()
        )),
        "min_passive_lowland_stage_cell_count": int(min(
            row["passive_lowland_stage_cell_count"]
            for row in field_metrics.values()
        )),
    }
    passed = bool(
        metrics["world_count"] == 2
        and metrics["sequence_ready_world_count"] == 2
        and metrics["max_missing_sequence_item_count"] == 0
        and metrics["min_sequence_id_count"] > 0
        and metrics["min_lineage_id_count"] > 0
        and metrics["min_stage_count"] >= 6
        and metrics["min_rift_shoulder_cell_count"] > 0
        and metrics["min_escarpment_cell_count"] > 0
        and metrics["min_sequence_object_count"] > 0
        and metrics["min_rift_shoulder_object_count"] > 0
        and metrics["min_escarpment_object_count"] > 0
        and metrics["min_passive_lowland_stage_cell_count"] > 0
    )
    return _result(
        "P99.production_rift_margin_sequence_fields",
        passed,
        metrics,
        "P99 failed to expose production rift shoulder, escarpment, sequence id, stage, and lineage fields across generated worlds",
    )


def _bench_p99_production_bathymetry_margin_ordering(
    worlds: dict[int, dict[str, Any]]
) -> dict[str, Any]:
    field_metrics = {cells: world["field_metrics"] for cells, world in worlds.items()}
    metrics = {
        "world_count": int(len(worlds)),
        "min_shelf_stage_cell_count": int(min(
            row["shelf_stage_cell_count"] for row in field_metrics.values()
        )),
        "min_slope_stage_cell_count": int(min(
            row["slope_stage_cell_count"] for row in field_metrics.values()
        )),
        "min_rise_stage_cell_count": int(min(
            row["rise_stage_cell_count"] for row in field_metrics.values()
        )),
        "min_abyss_stage_cell_count": int(min(
            row["abyss_stage_cell_count"] for row in field_metrics.values()
        )),
        "max_shelf_depth_p75_m": float(max(
            row["shelf_depth_p75_m"] for row in field_metrics.values()
        )),
        "min_slope_depth_p50_m": float(min(
            row["slope_depth_p50_m"] for row in field_metrics.values()
        )),
        "min_rise_depth_p50_m": float(min(
            row["rise_depth_p50_m"] for row in field_metrics.values()
        )),
        "min_abyss_depth_p50_m": float(min(
            row["abyss_depth_p50_m"] for row in field_metrics.values()
        )),
        "min_shelf_to_abyss_depth_delta_m": float(min(
            row["abyss_depth_p50_m"] - row["shelf_depth_p75_m"]
            for row in field_metrics.values()
        )),
        "ordered_world_count": int(sum(
            1
            for row in field_metrics.values()
            if (
                np.isfinite(row["shelf_depth_p75_m"])
                and np.isfinite(row["slope_depth_p50_m"])
                and np.isfinite(row["rise_depth_p50_m"])
                and np.isfinite(row["abyss_depth_p50_m"])
                and row["shelf_depth_p75_m"]
                < row["slope_depth_p50_m"]
                < row["rise_depth_p50_m"]
                < row["abyss_depth_p50_m"]
            )
        )),
    }
    passed = bool(
        metrics["world_count"] == 2
        and metrics["ordered_world_count"] == 2
        and metrics["min_shelf_stage_cell_count"] > 0
        and metrics["min_slope_stage_cell_count"] > 0
        and metrics["min_rise_stage_cell_count"] > 0
        and metrics["min_abyss_stage_cell_count"] > 0
        and metrics["max_shelf_depth_p75_m"] < 800.0
        and metrics["min_shelf_to_abyss_depth_delta_m"] > 1000.0
    )
    return _result(
        "P99.production_bathymetry_margin_ordering",
        passed,
        metrics,
        "P99 failed to expose an ordered shelf-slope-rise-abyss production sequence across generated worlds",
    )


