def _latest_archived_suite_summary(root: Path, suite: str) -> dict[str, Any]:
    candidates = sorted(
        root.glob(f"out_bench_{suite.lower()}_*/tectonics_bench_summary.json")
    )
    load_error = ""
    for path in reversed(candidates):
        try:
            summary = json.loads(path.read_text())
        except Exception as exc:
            load_error = str(exc)
            continue
        if str(summary.get("suite", "")).upper() == suite:
            benches = tuple(summary.get("benchmarks", ()))
            return {
                "suite": suite,
                "packet_id": P100_REPAIR_SUITE_TO_PACKET.get(suite, ""),
                "summary_path": str(path),
                "schema": str(summary.get("schema", "")),
                "status": str(summary.get("status", "")),
                "benchmark_count": int(len(benches)),
                "passed_benchmark_count": int(
                    sum(1 for bench in benches if bench.get("passed"))),
                "all_microbenchmarks_pass": bool(
                    summary.get("acceptance", {}).get(
                        "all_microbenchmarks_pass",
                        summary.get("status") == "pass",
                    )
                ),
            }
    return {
        "suite": suite,
        "packet_id": P100_REPAIR_SUITE_TO_PACKET.get(suite, ""),
        "summary_path": "",
        "schema": "",
        "status": "missing",
        "benchmark_count": 0,
        "passed_benchmark_count": 0,
        "all_microbenchmarks_pass": False,
        "load_error": load_error,
    }


def _p100_integrated_reaudit_and_promotion_gate(
    root: Path = PROJECT_ROOT,
    outdir: Path | None = None,
) -> dict[str, Any]:
    workspace = (
        outdir
        if outdir is not None
        else root / "out_bench_p100_integrated_reaudit_and_promotion_gate_runtime"
    )
    p91_outdir = workspace / "p91_reaudit"
    p91_summary = run_p91_bench(root, outdir=p91_outdir)
    p91_outdir.mkdir(parents=True, exist_ok=True)
    (p91_outdir / "tectonics_bench_summary.json").write_text(
        json.dumps(p91_summary, indent=2, default=_json_default) + "\n"
    )
    _write_bench_csv(p91_summary, p91_outdir / "p91_microbenchmarks.csv")
    audit = p91_summary["integrated_real_earth_morphology_promotion_audit"]
    decision = audit["promotion_decision"]
    blockers = tuple(str(item) for item in decision["promotion_blockers"])
    root_owner_counts = {
        str(k): int(v) for k, v in audit.get("root_p90_owner_counts", {}).items()
    }
    ci_owner_counts = {
        int(row.get("cells", 0)): {
            str(k): int(v) for k, v in row.get("owner_counts", {}).items()
        }
        for row in audit.get("ci_worlds", ())
    }
    repair_rows = tuple(
        _latest_archived_suite_summary(root, suite)
        for suite in P100_REPAIR_SUITE_TO_PACKET
    )
    repair_pass_count = int(sum(
        row["status"] == "pass" and row["all_microbenchmarks_pass"]
        for row in repair_rows
    ))
    missing_repair_suites = tuple(
        row["suite"] for row in repair_rows if row["status"] == "missing"
    )
    failing_repair_suites = tuple(
        row["suite"] for row in repair_rows
        if row["status"] != "pass" or not row["all_microbenchmarks_pass"]
    )
    remaining_owner_blockers = tuple(
        blocker
        for blocker in blockers
        if blocker.endswith("_residuals_unresolved")
        and blocker != "p90_current_world_residuals_unresolved"
    )
    cleared_owner_blockers = tuple(
        blocker
        for blocker in P100_CLEARED_ROOT_OWNER_BLOCKERS
        if blocker not in blockers
    )
    p90_metrics = audit["metrics"]
    p91_stage_matrix = audit["stage_matrix"]
    p91_ci_review = audit["ci_review"]
    p91_highres = audit["highres_review_assets"]
    expected_blocker_set_matched = (
        tuple(blockers) == P100_EXPECTED_REMAINING_BLOCKERS
    )
    release_gate_allowed = bool(decision["promotion_ready"] and not blockers)
    next_recommended_action = (
        "default_earthlike_promotion"
        if release_gate_allowed
        else "P101.planform_crust_sediment_residual_repair"
    )
    status_ready = bool(
        repair_pass_count == len(repair_rows)
        and p91_summary["status"] == "pass"
        and p91_summary["determinism"]["passed"]
        and expected_blocker_set_matched
        and not release_gate_allowed
    )
    metrics = {
        "repair_suite_count": int(len(repair_rows)),
        "repair_suite_pass_count": repair_pass_count,
        "missing_repair_suite_count": int(len(missing_repair_suites)),
        "failing_repair_suite_count": int(len(failing_repair_suites)),
        "p91_after_p99_status": str(p91_summary["status"]),
        "p91_after_p99_deterministic": bool(p91_summary["determinism"]["passed"]),
        "p91_stage_suite_count": int(p91_stage_matrix["suite_count"]),
        "p91_stage_suite_pass_count": int(p91_stage_matrix["pass_count"]),
        "p91_ci_world_count": int(p91_ci_review["world_count"]),
        "p91_ci_asset_set_complete_count": int(
            p91_ci_review["asset_set_complete_count"]),
        "p91_ci_compiler_passed_count": int(
            p91_ci_review["compiler_passed_count"]),
        "p91_highres_member_count": int(p91_highres["member_count"]),
        "p91_promotion_ready": bool(decision["promotion_ready"]),
        "p91_keeps_default_off": bool(
            decision["keeps_default_off_until_named_residuals_resolved"]),
        "promotion_blocker_count": int(len(blockers)),
        "expected_remaining_blocker_count": int(
            len(P100_EXPECTED_REMAINING_BLOCKERS)),
        "expected_blocker_set_matched": bool(expected_blocker_set_matched),
        "remaining_owner_blocker_count": int(len(remaining_owner_blockers)),
        "cleared_root_owner_blocker_count": int(len(cleared_owner_blockers)),
        "root_p90_gap_count": int(p90_metrics["p90_gap_count"]),
        "root_p90_non_asset_gap_count": int(
            p90_metrics["p90_non_asset_gap_count"]),
        "root_p90_owner_layer_count": int(
            p90_metrics["p90_owner_layer_count"]),
        "root_p90_category_count": int(p90_metrics["p90_category_count"]),
        "root_p90_residual_item_count": int(
            len(audit.get("root_p90_current_residual_items", ()))),
        "release_gate_allowed": bool(release_gate_allowed),
        "next_recommended_action": next_recommended_action,
    }
    acceptance = {
        "p93_p99_repair_suites_available": (
            metrics["missing_repair_suite_count"] == 0),
        "p93_p99_repair_suites_pass": (
            metrics["repair_suite_pass_count"] == metrics["repair_suite_count"]),
        "p91_after_p99_reaudit_pass": bool(
            p91_summary["status"] == "pass"
            and p91_summary["determinism"]["passed"]),
        "p91_ci_assets_and_compilers_pass": bool(
            metrics["p91_ci_asset_set_complete_count"] == metrics["p91_ci_world_count"]
            and metrics["p91_ci_compiler_passed_count"] == metrics["p91_ci_world_count"]),
        "completed_owner_blockers_cleared_from_root": bool(
            tuple(cleared_owner_blockers) == P100_CLEARED_ROOT_OWNER_BLOCKERS),
        "remaining_blockers_are_named": bool(expected_blocker_set_matched),
        "default_promotion_blocked": bool(
            not decision["promotion_ready"]
            and decision["keeps_default_off_until_named_residuals_resolved"]),
        "next_action_targets_planform_crust_sediment": bool(
            next_recommended_action
            == "P101.planform_crust_sediment_residual_repair"),
    }
    return {
        "schema": "aevum.p100_integrated_reaudit_and_promotion_gate.v1",
        "status": (
            "integrated_reaudit_and_promotion_gate_ready"
            if status_ready and all(acceptance.values())
            else "integrated_reaudit_and_promotion_gate_incomplete"
        ),
        "repair_suite_matrix": {
            "schema": "aevum.p100_repair_suite_matrix.v1",
            "rows": repair_rows,
            "suite_to_packet": dict(P100_REPAIR_SUITE_TO_PACKET),
            "missing_suites": missing_repair_suites,
            "failing_suites": failing_repair_suites,
        },
        "after_p99_p91_reaudit": {
            "summary_path": str(p91_outdir / "tectonics_bench_summary.json"),
            "contact_sheet_path": str(p91_outdir / "p91_ci_world_contact_sheet.png"),
            "status": str(p91_summary["status"]),
            "promotion_blockers": blockers,
            "expected_remaining_blockers": P100_EXPECTED_REMAINING_BLOCKERS,
            "cleared_root_owner_blockers": cleared_owner_blockers,
            "remaining_owner_blockers": remaining_owner_blockers,
            "root_p90_owner_counts": root_owner_counts,
            "ci_owner_counts": ci_owner_counts,
        },
        "promotion_decision": {
            "release_gate_allowed": release_gate_allowed,
            "default_promotion_ready": bool(decision["promotion_ready"]),
            "default_promotion_blocked": bool(not release_gate_allowed),
            "next_recommended_action": next_recommended_action,
            "reason": (
                "planform and crust/sediment residual blockers remain after P99"
                if not release_gate_allowed else "all P100 blockers cleared"
            ),
        },
        "metrics": metrics,
        "acceptance": acceptance,
    }


def _bench_p100_integrated_owner_repair_reaudit(
    gate: dict[str, Any] | None = None,
) -> dict[str, Any]:
    gate = gate or _p100_integrated_reaudit_and_promotion_gate()
    metrics_in = gate["metrics"]
    metrics = {
        "gate_status": str(gate["status"]),
        "repair_suite_count": int(metrics_in["repair_suite_count"]),
        "repair_suite_pass_count": int(metrics_in["repair_suite_pass_count"]),
        "missing_repair_suite_count": int(
            metrics_in["missing_repair_suite_count"]),
        "failing_repair_suite_count": int(
            metrics_in["failing_repair_suite_count"]),
        "p91_after_p99_status": str(metrics_in["p91_after_p99_status"]),
        "p91_after_p99_deterministic": bool(
            metrics_in["p91_after_p99_deterministic"]),
        "p91_stage_suite_count": int(metrics_in["p91_stage_suite_count"]),
        "p91_stage_suite_pass_count": int(
            metrics_in["p91_stage_suite_pass_count"]),
        "p91_ci_world_count": int(metrics_in["p91_ci_world_count"]),
        "p91_ci_asset_set_complete_count": int(
            metrics_in["p91_ci_asset_set_complete_count"]),
        "p91_ci_compiler_passed_count": int(
            metrics_in["p91_ci_compiler_passed_count"]),
        "p91_highres_member_count": int(metrics_in["p91_highres_member_count"]),
        "cleared_root_owner_blocker_count": int(
            metrics_in["cleared_root_owner_blocker_count"]),
        "remaining_owner_blocker_count": int(
            metrics_in["remaining_owner_blocker_count"]),
        "root_p90_non_asset_gap_count": int(
            metrics_in["root_p90_non_asset_gap_count"]),
        "root_p90_owner_layer_count": int(
            metrics_in["root_p90_owner_layer_count"]),
        "root_p90_residual_item_count": int(
            metrics_in["root_p90_residual_item_count"]),
    }
    passed = bool(
        gate["status"] == "integrated_reaudit_and_promotion_gate_ready"
        and gate["acceptance"]["p93_p99_repair_suites_available"]
        and gate["acceptance"]["p93_p99_repair_suites_pass"]
        and gate["acceptance"]["p91_after_p99_reaudit_pass"]
        and gate["acceptance"]["p91_ci_assets_and_compilers_pass"]
        and gate["acceptance"]["completed_owner_blockers_cleared_from_root"]
        and metrics["repair_suite_count"] == 7
        and metrics["repair_suite_pass_count"] == 7
        and metrics["missing_repair_suite_count"] == 0
        and metrics["failing_repair_suite_count"] == 0
        and metrics["p91_after_p99_status"] == "pass"
        and metrics["p91_stage_suite_count"] == 15
        and metrics["p91_stage_suite_pass_count"] == 15
        and metrics["p91_ci_world_count"] == 2
        and metrics["p91_ci_asset_set_complete_count"] == 2
        and metrics["p91_ci_compiler_passed_count"] == 2
        and metrics["p91_highres_member_count"] >= 3
        and metrics["cleared_root_owner_blocker_count"] == len(
            P100_CLEARED_ROOT_OWNER_BLOCKERS)
        and metrics["remaining_owner_blocker_count"] == 2
        and metrics["root_p90_non_asset_gap_count"] == 11
        and metrics["root_p90_owner_layer_count"] == 2
        and metrics["root_p90_residual_item_count"] == 0
    )
    return _result(
        "P100.integrated_owner_repair_reaudit",
        passed,
        metrics,
        "P100 failed to verify P93-P99 repair-suite evidence, rerun the after-P99 P91 audit, or narrow root residual owners to planform plus crust/sediment",
    )


def _bench_p100_default_promotion_decision_gate(
    gate: dict[str, Any] | None = None,
) -> dict[str, Any]:
    gate = gate or _p100_integrated_reaudit_and_promotion_gate()
    metrics_in = gate["metrics"]
    blockers = tuple(gate["after_p99_p91_reaudit"]["promotion_blockers"])
    decision = gate["promotion_decision"]
    metrics = {
        "gate_status": str(gate["status"]),
        "promotion_blocker_count": int(metrics_in["promotion_blocker_count"]),
        "expected_remaining_blocker_count": int(
            metrics_in["expected_remaining_blocker_count"]),
        "expected_blocker_set_matched": bool(
            metrics_in["expected_blocker_set_matched"]),
        "p91_promotion_ready": bool(metrics_in["p91_promotion_ready"]),
        "p91_keeps_default_off": bool(metrics_in["p91_keeps_default_off"]),
        "release_gate_allowed": bool(metrics_in["release_gate_allowed"]),
        "next_recommended_action": str(metrics_in["next_recommended_action"]),
        "promotion_blockers": blockers,
        "default_promotion_blocked": bool(decision["default_promotion_blocked"]),
    }
    passed = bool(
        gate["status"] == "integrated_reaudit_and_promotion_gate_ready"
        and gate["acceptance"]["remaining_blockers_are_named"]
        and gate["acceptance"]["default_promotion_blocked"]
        and gate["acceptance"]["next_action_targets_planform_crust_sediment"]
        and metrics["promotion_blocker_count"] == len(
            P100_EXPECTED_REMAINING_BLOCKERS)
        and metrics["expected_blocker_set_matched"]
        and not metrics["p91_promotion_ready"]
        and metrics["p91_keeps_default_off"]
        and not metrics["release_gate_allowed"]
        and metrics["default_promotion_blocked"]
        and metrics["next_recommended_action"]
        == "P101.planform_crust_sediment_residual_repair"
    )
    return _result(
        "P100.default_promotion_decision_gate",
        passed,
        metrics,
        "P100 failed to keep default Earth-like promotion blocked behind the exact named P69/P90/planform/crust-sediment residual set",
    )


def run_p100_bench(root: Path = PROJECT_ROOT,
                   outdir: Path | None = None) -> dict[str, Any]:
    gate = _p100_integrated_reaudit_and_promotion_gate(root, outdir)
    benchmarks = [
        _bench_p100_integrated_owner_repair_reaudit(gate),
        _bench_p100_default_promotion_decision_gate(gate),
    ]
    passed = all(b["passed"] for b in benchmarks)
    digest = _canonical_digest({
        "benchmarks": benchmarks,
        "gate": gate,
    })
    return {
        "schema": "aevum.tectonics_bench.p100.v1",
        "suite": "P100",
        "status": "pass" if passed else "fail",
        "benchmarks": benchmarks,
        "integrated_reaudit_and_promotion_gate": gate,
        "determinism": {
            "summary_digest": digest,
            "passed": passed,
        },
        "acceptance": {
            "all_microbenchmarks_pass": passed,
            "integrated_owner_repair_reaudit": benchmarks[0]["passed"],
            "default_promotion_decision_gate": benchmarks[1]["passed"],
            "p93_p99_repair_suites_available": gate["acceptance"][
                "p93_p99_repair_suites_available"],
            "p93_p99_repair_suites_pass": gate["acceptance"][
                "p93_p99_repair_suites_pass"],
            "p91_after_p99_reaudit_pass": gate["acceptance"][
                "p91_after_p99_reaudit_pass"],
            "completed_owner_blockers_cleared_from_root": gate["acceptance"][
                "completed_owner_blockers_cleared_from_root"],
            "remaining_blockers_are_named": gate["acceptance"][
                "remaining_blockers_are_named"],
            "default_promotion_blocked": gate["acceptance"][
                "default_promotion_blocked"],
            "next_action_targets_planform_crust_sediment": gate["acceptance"][
                "next_action_targets_planform_crust_sediment"],
        },
    }


