def _p101_latest_p100_pointer(root: Path) -> dict[str, Any]:
    candidates = sorted(
        root.glob("out_bench_p100_*/tectonics_bench_summary.json")
    )
    for path in reversed(candidates):
        try:
            summary = json.loads(path.read_text())
        except Exception:
            continue
        if str(summary.get("suite", "")) != "P100":
            continue
        gate = summary.get("integrated_reaudit_and_promotion_gate", {})
        decision = gate.get("promotion_decision", {})
        metrics = gate.get("metrics", {})
        return {
            "summary_path": str(path),
            "status": str(summary.get("status", "")),
            "next_recommended_action": str(decision.get("next_recommended_action", "")),
            "promotion_blocker_count": int(metrics.get("promotion_blocker_count", 0)),
            "root_p90_non_asset_gap_count": int(
                metrics.get("root_p90_non_asset_gap_count", 0)),
            "root_p90_owner_layer_count": int(
                metrics.get("root_p90_owner_layer_count", 0)),
        }
    return {
        "summary_path": "",
        "status": "missing",
        "next_recommended_action": "",
        "promotion_blocker_count": 0,
        "root_p90_non_asset_gap_count": 0,
        "root_p90_owner_layer_count": 0,
    }


def _p101_non_asset_gaps(inventory: dict[str, Any]) -> tuple[dict[str, Any], ...]:
    return tuple(
        gap for gap in inventory.get("gaps", ())
        if gap.get("category") != "asset_review_pending"
    )


def _p101_gap_attribution_row(gap: dict[str, Any]) -> dict[str, Any]:
    gap_id = str(gap.get("gap_id", ""))
    owner = str(gap.get("owner_layer", ""))
    attr = P101_GAP_ATTRIBUTION.get(gap_id)
    exact = attr is not None
    if attr is None:
        if owner == "planform":
            attr = {
                "repair_phase": "Phase 2. Planform Mechanism Repair",
                "implementation_owner": "unclassified planform residual",
                "code_targets": (
                    "aevum/modules/terrain.py",
                    "aevum/modules/tectonics.py",
                ),
                "failure_meaning": "Planform residual needs exact P101 attribution.",
                "regression_risk": "Unknown until the residual is classified.",
            }
        elif owner == "crust_sediment":
            attr = {
                "repair_phase": (
                    "Phase 3. Crust, Sediment, and Interior Elevation Repair"),
                "implementation_owner": "unclassified crust/sediment residual",
                "code_targets": ("aevum/modules/terrain.py",),
                "failure_meaning": (
                    "Crust/sediment residual needs exact P101 attribution."),
                "regression_risk": "Unknown until the residual is classified.",
            }
        else:
            attr = {
                "repair_phase": "Phase 0. Baseline Reproduction",
                "implementation_owner": "unexpected owner layer",
                "code_targets": (),
                "failure_meaning": "Unexpected non-asset residual owner.",
                "regression_risk": "Unexpected owner layer can hide a missed repair packet.",
            }
    return {
        "gap_id": gap_id,
        "owner_layer": owner,
        "category": str(gap.get("category", "")),
        "source_suite": str(gap.get("source_suite", "")),
        "metric_value": gap.get("metric_value"),
        "evidence": str(gap.get("evidence", "")),
        "repair_phase": str(attr["repair_phase"]),
        "implementation_owner": str(attr["implementation_owner"]),
        "code_targets": tuple(attr["code_targets"]),
        "failure_meaning": str(attr["failure_meaning"]),
        "regression_risk": str(attr["regression_risk"]),
        "exact_attribution": bool(exact),
    }


def _p101_owner_counts_for_gaps(gaps: tuple[dict[str, Any], ...]) -> dict[str, int]:
    counts: dict[str, int] = {}
    for gap in gaps:
        owner = str(gap.get("owner_layer", ""))
        counts[owner] = counts.get(owner, 0) + 1
    return dict(sorted(counts.items()))


def _p101_current_residual_attribution(
    root: Path = PROJECT_ROOT,
) -> dict[str, Any]:
    inventories = {
        int(cells): _p90_current_world_morphology_gap_inventory(cells=int(cells))
        for cells in (900, 2500)
    }
    root_inventory = inventories[900]
    root_non_asset = _p101_non_asset_gaps(root_inventory)
    attribution_rows = tuple(
        _p101_gap_attribution_row(gap)
        for gap in root_non_asset
    )
    direct = root_inventory["direct_surface_metrics"]
    exact_count = int(sum(row["exact_attribution"] for row in attribution_rows))
    fallback_count = int(len(attribution_rows) - exact_count)
    root_owner_counts = _p101_owner_counts_for_gaps(root_non_asset)
    root_gap_ids = tuple(row["gap_id"] for row in attribution_rows)
    p100_pointer = _p101_latest_p100_pointer(root)
    per_resolution = {}
    for cells, inventory in inventories.items():
        non_asset = _p101_non_asset_gaps(inventory)
        direct_i = inventory["direct_surface_metrics"]
        per_resolution[int(cells)] = {
            "cells": int(cells),
            "gap_count": int(inventory["metrics"]["gap_count"]),
            "non_asset_gap_count": int(len(non_asset)),
            "non_asset_owner_counts": _p101_owner_counts_for_gaps(non_asset),
            "planform_gap_count": int(sum(
                1 for gap in non_asset if gap.get("owner_layer") == "planform")),
            "crust_sediment_gap_count": int(sum(
                1 for gap in non_asset
                if gap.get("owner_layer") == "crust_sediment")),
            "asset_review_gap_count": int(sum(
                1 for gap in inventory.get("gaps", ())
                if gap.get("category") == "asset_review_pending")),
            "major_component_count": int(direct_i["major_component_count"]),
            "continental_land_fraction_world": float(
                direct_i["continental_land_fraction_world"]),
            "high_flat_interior_fraction_of_continental_land": float(
                direct_i["high_flat_interior_fraction_of_continental_land"]),
            "basin_lowland_fraction_of_continental_land": float(
                direct_i["basin_lowland_fraction_of_continental_land"]),
            "lowland_fraction_lt500m_of_continental_land": float(
                direct_i["lowland_fraction_lt500m_of_continental_land"]),
            "lowland_fraction_lt1000m_of_continental_land": float(
                direct_i["lowland_fraction_lt1000m_of_continental_land"]),
        }
    metrics = {
        "root_cells": 900,
        "audit_resolution_count": int(len(per_resolution)),
        "root_gap_count": int(root_inventory["metrics"]["gap_count"]),
        "root_non_asset_gap_count": int(len(root_non_asset)),
        "root_asset_review_gap_count": int(
            sum(1 for gap in root_inventory.get("gaps", ())
                if gap.get("category") == "asset_review_pending")),
        "root_planform_gap_count": int(root_owner_counts.get("planform", 0)),
        "root_crust_sediment_gap_count": int(
            root_owner_counts.get("crust_sediment", 0)),
        "expected_non_asset_gap_count": int(len(P101_EXPECTED_NON_ASSET_GAP_IDS)),
        "expected_gap_id_match_count": int(
            sum(gap_id in P101_EXPECTED_NON_ASSET_GAP_IDS
                for gap_id in root_gap_ids)),
        "attributed_non_asset_gap_count": int(len(attribution_rows)),
        "exact_attribution_count": exact_count,
        "fallback_attribution_count": fallback_count,
        "unexpected_non_asset_gap_count": int(
            sum(gap_id not in P101_EXPECTED_NON_ASSET_GAP_IDS
                for gap_id in root_gap_ids)),
        "missing_expected_gap_count": int(
            sum(gap_id not in root_gap_ids
                for gap_id in P101_EXPECTED_NON_ASSET_GAP_IDS)),
        "root_major_component_count": int(direct["major_component_count"]),
        "root_continental_land_fraction_world": float(
            direct["continental_land_fraction_world"]),
        "root_high_flat_interior_fraction_of_continental_land": float(
            direct["high_flat_interior_fraction_of_continental_land"]),
        "root_basin_lowland_fraction_of_continental_land": float(
            direct["basin_lowland_fraction_of_continental_land"]),
        "root_lowland_fraction_lt500m_of_continental_land": float(
            direct["lowland_fraction_lt500m_of_continental_land"]),
        "root_lowland_fraction_lt1000m_of_continental_land": float(
            direct["lowland_fraction_lt1000m_of_continental_land"]),
        "high_flat_repair_threshold": 0.02,
        "land_fraction_target_min": 0.25,
        "land_fraction_target_max": 0.33,
        "major_component_target_min": 4,
        "major_component_target_max": 14,
        "largest_component_target_max": 0.60,
        "land_ribbon_target_max": 0.35,
        "coastline_complexity_target_max": 8.0,
        "p100_pointer_status": p100_pointer["status"],
        "p100_pointer_next_recommended_action": p100_pointer[
            "next_recommended_action"],
    }
    acceptance = {
        "phase0_baseline_reproduced": bool(
            root_inventory["status"] == "current_world_morphology_gap_inventory_ready"
            and metrics["root_gap_count"] >= 19
            and metrics["root_non_asset_gap_count"] == len(
                P101_EXPECTED_NON_ASSET_GAP_IDS)
        ),
        "remaining_owner_layers_match_p100": bool(
            root_owner_counts == P101_EXPECTED_ROOT_OWNER_COUNTS),
        "all_expected_non_asset_gaps_present": bool(
            metrics["expected_gap_id_match_count"]
            == metrics["expected_non_asset_gap_count"]
            and metrics["missing_expected_gap_count"] == 0),
        "no_unexpected_non_asset_gaps": bool(
            metrics["unexpected_non_asset_gap_count"] == 0),
        "all_non_asset_gaps_exactly_attributed": bool(
            metrics["exact_attribution_count"]
            == metrics["root_non_asset_gap_count"]
            and metrics["fallback_attribution_count"] == 0),
        "multi_resolution_audit_recorded": bool(
            set(per_resolution) == {900, 2500}
            and all(row["non_asset_gap_count"] >= 1
                    for row in per_resolution.values())),
        "p100_next_action_points_to_p101": bool(
            p100_pointer["next_recommended_action"]
            in ("", "P101.planform_crust_sediment_residual_repair")),
        "repair_targets_recorded_without_threshold_relaxation": bool(
            metrics["high_flat_repair_threshold"] == 0.02
            and metrics["land_fraction_target_min"] == 0.25
            and metrics["land_fraction_target_max"] == 0.33
            and metrics["major_component_target_min"] == 4
            and metrics["largest_component_target_max"] == 0.60
            and metrics["land_ribbon_target_max"] == 0.35
        ),
    }
    status_ready = all(acceptance.values())
    return {
        "schema": "aevum.p101_current_residual_attribution.v1",
        "status": (
            "current_residual_attribution_ready"
            if status_ready else "current_residual_attribution_incomplete"
        ),
        "phase": "Phase 0. Baseline Reproduction and Failure Attribution",
        "source_plan": (
            "docs/REAL_EARTH_GEOMORPHOLOGY_RESEARCH_PLAN.md::"
            "P101+ Real-Earth Comparison Repair Archive"
        ),
        "p100_pointer": p100_pointer,
        "per_resolution": per_resolution,
        "root_inventory_digest": root_inventory["summary_digest"],
        "root_gap_ids": root_gap_ids,
        "attribution_rows": attribution_rows,
        "evidence_packet_template": {
            "packet_id": "P101_phase0_current_residual_attribution",
            "source_ids": (
                "P90.current_world_morphology_gap_inventory",
                "P100.integrated_reaudit_and_promotion_gate",
            ),
            "raw_data_policy": "no raw external rasters required for Phase 0",
            "extraction_method": (
                "generated Earth-like 900/2500 cell worlds audited through the "
                "P90 morphology gap inventory schema"
            ),
            "theory_claims": (
                "Planform and crust/sediment residuals must be separated before "
                "production tuning.",
                "Residuals must map to process owners and code targets before "
                "reference envelopes can be promoted.",
            ),
            "generated_world_audit": "P101 current residual attribution",
            "optimization_targets": (
                "do not relax reference envelopes",
                "clear planform and crust/sediment owner blockers in later phases",
            ),
            "residual_policy": (
                "Phase 0 records residuals as blockers; later phases must repair "
                "or narrow them with stronger evidence."
            ),
            "asset_review": P91_REQUIRED_REVIEW_ASSETS,
        },
        "metrics": metrics,
        "acceptance": acceptance,
    }


def _bench_p101_planform_residual_baseline(
    attribution: dict[str, Any] | None = None,
) -> dict[str, Any]:
    attribution = attribution or _p101_current_residual_attribution()
    metrics_in = attribution["metrics"]
    per_resolution = attribution["per_resolution"]
    planform_rows = tuple(
        row for row in attribution["attribution_rows"]
        if row["owner_layer"] == "planform"
    )
    metrics = {
        "attribution_status": str(attribution["status"]),
        "root_gap_count": int(metrics_in["root_gap_count"]),
        "root_non_asset_gap_count": int(metrics_in["root_non_asset_gap_count"]),
        "root_planform_gap_count": int(metrics_in["root_planform_gap_count"]),
        "root_asset_review_gap_count": int(metrics_in["root_asset_review_gap_count"]),
        "root_major_component_count": int(metrics_in["root_major_component_count"]),
        "root_continental_land_fraction_world": float(
            metrics_in["root_continental_land_fraction_world"]),
        "land_fraction_target_min": float(metrics_in["land_fraction_target_min"]),
        "land_fraction_target_max": float(metrics_in["land_fraction_target_max"]),
        "major_component_target_min": int(metrics_in["major_component_target_min"]),
        "major_component_target_max": int(metrics_in["major_component_target_max"]),
        "largest_component_target_max": float(
            metrics_in["largest_component_target_max"]),
        "land_ribbon_target_max": float(metrics_in["land_ribbon_target_max"]),
        "coastline_complexity_target_max": float(
            metrics_in["coastline_complexity_target_max"]),
        "expected_gap_id_match_count": int(
            metrics_in["expected_gap_id_match_count"]),
        "unexpected_non_asset_gap_count": int(
            metrics_in["unexpected_non_asset_gap_count"]),
        "missing_expected_gap_count": int(metrics_in["missing_expected_gap_count"]),
        "exact_planform_attribution_count": int(
            sum(row["exact_attribution"] for row in planform_rows)),
        "planform_code_target_count": int(len({
            target for row in planform_rows for target in row["code_targets"]
        })),
        "resolution_900_non_asset_gap_count": int(
            per_resolution[900]["non_asset_gap_count"]),
        "resolution_2500_non_asset_gap_count": int(
            per_resolution[2500]["non_asset_gap_count"]),
        "planform_gap_ids": tuple(row["gap_id"] for row in planform_rows),
    }
    passed = bool(
        attribution["status"] == "current_residual_attribution_ready"
        and attribution["acceptance"]["phase0_baseline_reproduced"]
        and attribution["acceptance"]["all_expected_non_asset_gaps_present"]
        and attribution["acceptance"]["no_unexpected_non_asset_gaps"]
        and metrics["root_planform_gap_count"] == P101_EXPECTED_ROOT_OWNER_COUNTS[
            "planform"]
        and metrics["exact_planform_attribution_count"]
        == metrics["root_planform_gap_count"]
        and metrics["root_continental_land_fraction_world"]
        < metrics["land_fraction_target_min"]
        and metrics["root_major_component_count"]
        < metrics["major_component_target_min"]
        and metrics["planform_code_target_count"] >= 4
    )
    return _result(
        "P101.planform_residual_baseline",
        passed,
        metrics,
        "P101 failed to reproduce and attribute the current planform residual baseline before production repair",
    )


def _bench_p101_crust_sediment_high_flat_repair(
    attribution: dict[str, Any] | None = None,
) -> dict[str, Any]:
    attribution = attribution or _p101_current_residual_attribution()
    metrics_in = attribution["metrics"]
    crust_rows = tuple(
        row for row in attribution["attribution_rows"]
        if row["owner_layer"] == "crust_sediment"
    )
    metrics = {
        "attribution_status": str(attribution["status"]),
        "root_crust_sediment_gap_count": int(
            metrics_in["root_crust_sediment_gap_count"]),
        "root_high_flat_interior_fraction_of_continental_land": float(
            metrics_in["root_high_flat_interior_fraction_of_continental_land"]),
        "high_flat_repair_threshold": float(metrics_in["high_flat_repair_threshold"]),
        "root_basin_lowland_fraction_of_continental_land": float(
            metrics_in["root_basin_lowland_fraction_of_continental_land"]),
        "root_lowland_fraction_lt500m_of_continental_land": float(
            metrics_in["root_lowland_fraction_lt500m_of_continental_land"]),
        "root_lowland_fraction_lt1000m_of_continental_land": float(
            metrics_in["root_lowland_fraction_lt1000m_of_continental_land"]),
        "exact_crust_sediment_attribution_count": int(
            sum(row["exact_attribution"] for row in crust_rows)),
        "crust_sediment_gap_ids": tuple(row["gap_id"] for row in crust_rows),
        "crust_sediment_code_targets": tuple(
            target for row in crust_rows for target in row["code_targets"]),
        "repair_phase": (
            crust_rows[0]["repair_phase"] if crust_rows else ""),
    }
    passed = bool(
        attribution["status"] == "current_residual_attribution_ready"
        and attribution["acceptance"]["remaining_owner_layers_match_p100"]
        and attribution["acceptance"]["all_non_asset_gaps_exactly_attributed"]
        and metrics["root_crust_sediment_gap_count"]
        == P101_EXPECTED_ROOT_OWNER_COUNTS["crust_sediment"]
        and metrics["exact_crust_sediment_attribution_count"]
        == metrics["root_crust_sediment_gap_count"]
        and metrics["root_high_flat_interior_fraction_of_continental_land"]
        > metrics["high_flat_repair_threshold"]
        and "aevum/modules/terrain.py::_province_crust_sediment_surface_ordering"
        in metrics["crust_sediment_code_targets"]
        and metrics["root_basin_lowland_fraction_of_continental_land"] > 0.20
    )
    return _result(
        "P101.crust_sediment_high_flat_repair",
        passed,
        metrics,
        "P101 failed to isolate the high-flat crust/sediment repair target without relaxing the P90 threshold",
    )


def run_p101_bench(root: Path = PROJECT_ROOT,
                   outdir: Path | None = None) -> dict[str, Any]:
    del outdir
    attribution = _p101_current_residual_attribution(root)
    benchmarks = [
        _bench_p101_planform_residual_baseline(attribution),
        _bench_p101_crust_sediment_high_flat_repair(attribution),
    ]
    passed = all(b["passed"] for b in benchmarks)
    digest = _canonical_digest({
        "benchmarks": benchmarks,
        "current_residual_attribution": attribution,
    })
    return {
        "schema": "aevum.tectonics_bench.p101.v1",
        "suite": "P101",
        "status": "pass" if passed else "fail",
        "benchmarks": benchmarks,
        "current_residual_attribution": attribution,
        "determinism": {
            "summary_digest": digest,
            "passed": passed,
        },
        "acceptance": {
            "all_microbenchmarks_pass": passed,
            "planform_residual_baseline": benchmarks[0]["passed"],
            "crust_sediment_high_flat_repair": benchmarks[1]["passed"],
            "phase0_baseline_reproduced": attribution["acceptance"][
                "phase0_baseline_reproduced"],
            "remaining_owner_layers_match_p100": attribution["acceptance"][
                "remaining_owner_layers_match_p100"],
            "all_expected_non_asset_gaps_present": attribution["acceptance"][
                "all_expected_non_asset_gaps_present"],
            "all_non_asset_gaps_exactly_attributed": attribution["acceptance"][
                "all_non_asset_gaps_exactly_attributed"],
            "multi_resolution_audit_recorded": attribution["acceptance"][
                "multi_resolution_audit_recorded"],
            "repair_targets_recorded_without_threshold_relaxation": attribution[
                "acceptance"]["repair_targets_recorded_without_threshold_relaxation"],
            "phase1_reference_evidence_expansion_pending": True,
            "phase2_planform_mechanism_repair_pending": True,
            "phase3_crust_sediment_interior_elevation_repair_pending": True,
        },
    }


def _bench_p102_reference_evidence_packet_matrix(
    packet_summary: dict[str, Any] | None = None,
) -> dict[str, Any]:
    packet_summary = packet_summary or reference_evidence_packet_summary()
    metrics = {
        "packet_status": str(packet_summary["status"]),
        "packet_count": int(packet_summary["packet_count"]),
        "source_id_count": int(packet_summary["source_id_count"]),
        "metric_key_count": int(packet_summary["metric_key_count"]),
        "covered_metric_group_count": int(len(packet_summary["covered_metric_groups"])),
        "covered_metric_groups": tuple(packet_summary["covered_metric_groups"]),
        "residual_owner_layers": tuple(packet_summary["residual_owner_layers"]),
        "duplicate_packet_id_count": int(len(packet_summary["duplicate_packet_ids"])),
        "invalid_source_ref_packet_count": int(len(packet_summary["invalid_source_refs"])),
        "missing_required_field_packet_count": int(
            len(packet_summary["missing_required_fields"])),
        "incomplete_packet_count": int(len(packet_summary["incomplete_packets"])),
        "source_ledger_status": str(packet_summary["source_ledger_status"]),
        "hypsometry_fixture_status": str(packet_summary["hypsometry_fixture_status"]),
        "province_reference_graph_status": str(
            packet_summary["province_reference_graph_status"]),
        "phase2_planform_mechanism_repair_ready_to_plan": True,
    }
    passed = bool(
        packet_summary["status"] == "reference_evidence_packets_ready"
        and all(packet_summary["acceptance"].values())
        and metrics["packet_count"] >= 6
        and metrics["source_id_count"] >= 12
        and metrics["metric_key_count"] >= 24
        and {
            "planform",
            "hypsometry",
            "province_architecture",
            "process_parentage",
            "drainage",
            "ocean_bathymetry",
        }.issubset(set(metrics["covered_metric_groups"]))
        and {"planform", "crust_sediment"}.issubset(
            set(metrics["residual_owner_layers"]))
        and metrics["duplicate_packet_id_count"] == 0
        and metrics["invalid_source_ref_packet_count"] == 0
        and metrics["missing_required_field_packet_count"] == 0
        and metrics["incomplete_packet_count"] == 0
        and metrics["source_ledger_status"] == "source_ledger_schema_ready"
        and metrics["hypsometry_fixture_status"] == "hypsometry_fixture_ready"
        and metrics["province_reference_graph_status"] == "province_reference_graph_ready"
    )
    return _result(
        "P102.reference_evidence_packet_matrix",
        passed,
        metrics,
        "P102 failed to bind Phase-1 source packets to theory claims, reference/generated tracks, metrics, residual owners, and optimization targets",
    )


