P103_REPAIRED_GAP_IDS = (
    "planform.land_fraction_out_of_envelope",
)


def _p103_current_planform_row(cells: int) -> dict[str, Any]:
    from aevum import validation
    from aevum.compiler.map_compiler import MapCompiler
    from aevum.engine import Engine

    spec = get_preset("earthlike")
    spec.grid_cells = int(cells)
    spec.t_end_myr = 4500.0
    engine = Engine.build(spec)
    engine.run(n_frames=5)
    compiled = MapCompiler(engine.world, engine.archive).compile(
        width=72,
        height=36,
        n_starts=4,
    )
    tectonics = validation.tectonic_diagnostics(engine)
    compiler_metrics = validation.compiler_consistency_metrics(engine, compiled)
    inventory = current_world_morphology_gap_inventory_summary(
        engine.world,
        tectonics=tectonics,
        compiler_metrics=compiler_metrics,
    )
    morphology = compute_world_morphology(engine.world)
    direct = inventory["direct_surface_metrics"]
    land = morphology.metrics["exposed_land"]
    cont = morphology.metrics["continental_crust"]
    non_asset_gap_ids = tuple(
        str(gap["gap_id"])
        for gap in inventory["gaps"]
        if gap.get("category") != "asset_review_pending"
    )
    planform_gap_ids = tuple(
        str(gap["gap_id"])
        for gap in inventory["gaps"]
        if gap.get("owner_layer") == "planform"
        and gap.get("category") != "asset_review_pending"
    )
    stages = tuple(engine.world.objects.get("terrain.land_component_stage_telemetry", ()))
    stage_lookup = {str(row.get("stage", "")): row for row in stages}
    post_solve = stage_lookup.get("after_post_planform_sea_level_solve", {})
    post_drop = stage_lookup.get("after_post_sea_level_drop_unsupported", {})
    post_smooth = stage_lookup.get("after_post_sea_level_coast_smoothing", {})
    return {
        "cells": int(cells),
        "world_time_myr": float(engine.world.time_myr),
        "inventory_status": str(inventory["status"]),
        "gap_count": int(inventory["metrics"]["gap_count"]),
        "non_asset_gap_count": int(len(non_asset_gap_ids)),
        "planform_gap_count": int(len(planform_gap_ids)),
        "crust_sediment_gap_count": int(
            sum(
                1 for gap in inventory["gaps"]
                if gap.get("owner_layer") == "crust_sediment"
                and gap.get("category") != "asset_review_pending"
            )
        ),
        "non_asset_gap_ids": non_asset_gap_ids,
        "planform_gap_ids": planform_gap_ids,
        "repaired_gap_ids_absent": tuple(
            gap_id for gap_id in P103_REPAIRED_GAP_IDS
            if gap_id not in non_asset_gap_ids
        ),
        "new_unexpected_gap_ids": tuple(
            gap_id for gap_id in non_asset_gap_ids
            if gap_id not in P101_EXPECTED_NON_ASSET_GAP_IDS
        ),
        "owner_counts": dict(inventory["owner_counts"]),
        "category_counts": dict(inventory["category_counts"]),
        "compiler_passed_envelope": bool(
            inventory["metrics"]["compiler_passed_envelope"]),
        "compiler_broad_land_to_water_fraction": float(
            inventory["metrics"]["compiler_broad_land_to_water_fraction"]),
        "compiler_broad_ocean_to_land_fraction": float(
            inventory["metrics"]["compiler_broad_ocean_to_land_fraction"]),
        "continental_land_fraction_world": float(
            direct["continental_land_fraction_world"]),
        "major_component_count": int(direct["major_component_count"]),
        "largest_land_component_fraction": float(
            land["largest_component_area_fraction_of_mask"]),
        "land_ribbon_fraction": float(land["ribbon_area_fraction_gt_0_5"]),
        "land_coastline_complexity_largest_component": float(
            land["coastline_complexity_largest_component"]),
        "continental_crust_ribbon_fraction": float(
            cont["ribbon_area_fraction_gt_0_5"]),
        "continental_crust_narrow_fraction_le2_width": float(
            cont["narrow_fraction_le2_width"]),
        "land_elevation_p95_m": float(
            generated_world_hypsometry_metrics(engine.world, tectonics)[
                "land_elevation_p95_m"]),
        "high_flat_interior_fraction_of_continental_land": float(
            direct["high_flat_interior_fraction_of_continental_land"]),
        "post_planform_solve_land_fraction": float(
            post_solve.get("land_fraction", 0.0)),
        "post_planform_solve_component_count": int(
            post_solve.get("land_component_count", 0)),
        "post_sea_level_drop_land_fraction": float(
            post_drop.get("land_fraction", 0.0)),
        "post_coast_smoothing_land_fraction": float(
            post_smooth.get("land_fraction", 0.0)),
        "largest_shave_floor_fraction": float(
            engine.world.g("terrain.last_largest_landmass_shave_floor_fraction", 0.0)),
        "largest_shave_land_fraction_before": float(
            engine.world.g("terrain.last_largest_landmass_shave_land_fraction_before", 0.0)),
        "largest_shave_land_fraction_after": float(
            engine.world.g("terrain.last_largest_landmass_shave_land_fraction_after", 0.0)),
        "largest_shave_area_fraction": float(
            engine.world.g("terrain.last_largest_landmass_shave_area_fraction", 0.0)),
        "largest_shave_rejected_by_land_floor": bool(
            engine.world.g("terrain.last_largest_landmass_shave_rejected_by_land_floor", 0.0) > 0.0),
        "seaway_payback_recovery_need_fraction": float(
            engine.world.g("terrain.last_modern_seaway_payback_recovery_need_fraction", 0.0)),
        "seaway_payback_candidate_area_fraction": float(
            engine.world.g("terrain.last_modern_seaway_payback_candidate_area_fraction", 0.0)),
        "seaway_payback_area_fraction": float(
            engine.world.g("terrain.last_modern_seaway_payback_area_fraction", 0.0)),
        "coastline_payback_area_fraction": float(
            engine.world.g("terrain.last_modern_coastline_payback_area_fraction", 0.0)),
        "inventory_digest": str(inventory["summary_digest"]),
    }


def _p103_planform_repair_rows() -> tuple[dict[str, Any], ...]:
    return tuple(_p103_current_planform_row(cells) for cells in (900, 2500))


def _bench_p103_reference_land_floor_guard(
    rows: tuple[dict[str, Any], ...],
    packets: dict[str, Any],
) -> dict[str, Any]:
    row_by_cells = {int(row["cells"]): row for row in rows}
    root = row_by_cells[900]
    metrics = {
        "packet_status": str(packets["status"]),
        "cells_checked": tuple(sorted(row_by_cells)),
        "root_land_fraction": float(root["continental_land_fraction_world"]),
        "root_land_fraction_target_min": 0.25,
        "root_land_fraction_gap_absent": bool(
            "planform.land_fraction_out_of_envelope"
            not in root["non_asset_gap_ids"]),
        "root_largest_shave_floor_fraction": float(
            root["largest_shave_floor_fraction"]),
        "root_largest_shave_land_fraction_before": float(
            root["largest_shave_land_fraction_before"]),
        "root_largest_shave_land_fraction_after": float(
            root["largest_shave_land_fraction_after"]),
        "root_largest_shave_area_fraction": float(
            root["largest_shave_area_fraction"]),
        "root_largest_shave_rejected_by_land_floor": bool(
            root["largest_shave_rejected_by_land_floor"]),
        "root_seaway_payback_candidate_area_fraction": float(
            root["seaway_payback_candidate_area_fraction"]),
        "root_seaway_payback_area_fraction": float(
            root["seaway_payback_area_fraction"]),
        "root_coastline_payback_area_fraction": float(
            root["coastline_payback_area_fraction"]),
        "min_land_fraction_across_resolutions": float(
            min(row["continental_land_fraction_world"] for row in rows)),
        "all_resolutions_clear_land_fraction_gap": bool(
            all(
                "planform.land_fraction_out_of_envelope"
                not in row["non_asset_gap_ids"]
                for row in rows
            )
        ),
        "all_resolutions_compiler_passed": bool(
            all(row["compiler_passed_envelope"] for row in rows)),
    }
    passed = bool(
        metrics["packet_status"] == "reference_evidence_packets_ready"
        and set(metrics["cells_checked"]) == {900, 2500}
        and metrics["root_land_fraction"] >= metrics["root_land_fraction_target_min"]
        and metrics["root_land_fraction_gap_absent"]
        and metrics["root_largest_shave_floor_fraction"] >= 0.25
        and (
            metrics["root_largest_shave_land_fraction_after"] >= 0.25
            or metrics["root_largest_shave_rejected_by_land_floor"]
            or metrics["root_largest_shave_area_fraction"] <= 0.0
        )
        and metrics["all_resolutions_clear_land_fraction_gap"]
        and metrics["all_resolutions_compiler_passed"]
    )
    return _result(
        "P103.reference_land_floor_guard",
        passed,
        metrics,
        "P103 failed to keep the reference Earth-like land floor after terminal component/coastline repair",
    )


def _bench_p103_planform_repair_progress(
    rows: tuple[dict[str, Any], ...],
) -> dict[str, Any]:
    row_by_cells = {int(row["cells"]): row for row in rows}
    root = row_by_cells[900]
    cleared = tuple(
        gap_id for gap_id in P103_REPAIRED_GAP_IDS
        if gap_id not in root["non_asset_gap_ids"]
    )
    metrics = {
        "root_non_asset_gap_count": int(root["non_asset_gap_count"]),
        "root_planform_gap_count": int(root["planform_gap_count"]),
        "root_crust_sediment_gap_count": int(root["crust_sediment_gap_count"]),
        "root_repaired_gap_ids_absent": cleared,
        "root_repaired_gap_count": int(len(cleared)),
        "root_new_unexpected_gap_count": int(len(root["new_unexpected_gap_ids"])),
        "root_new_unexpected_gap_ids": tuple(root["new_unexpected_gap_ids"]),
        "root_major_component_count": int(root["major_component_count"]),
        "root_largest_land_component_fraction": float(
            root["largest_land_component_fraction"]),
        "root_land_ribbon_fraction": float(root["land_ribbon_fraction"]),
        "root_land_coastline_complexity_largest_component": float(
            root["land_coastline_complexity_largest_component"]),
        "root_continental_crust_ribbon_fraction": float(
            root["continental_crust_ribbon_fraction"]),
        "root_post_planform_solve_land_fraction": float(
            root["post_planform_solve_land_fraction"]),
        "root_post_planform_solve_component_count": int(
            root["post_planform_solve_component_count"]),
        "root_post_sea_level_drop_land_fraction": float(
            root["post_sea_level_drop_land_fraction"]),
        "root_post_coast_smoothing_land_fraction": float(
            root["post_coast_smoothing_land_fraction"]),
        "max_non_asset_gap_count_across_resolutions": int(
            max(row["non_asset_gap_count"] for row in rows)),
        "max_new_unexpected_gap_count_across_resolutions": int(
            max(len(row["new_unexpected_gap_ids"]) for row in rows)),
    }
    passed = bool(
        metrics["root_repaired_gap_count"] >= 1
        and "planform.land_fraction_out_of_envelope" in cleared
        and metrics["root_planform_gap_count"] < P101_EXPECTED_ROOT_OWNER_COUNTS[
            "planform"]
        and metrics["root_non_asset_gap_count"] <= len(P101_EXPECTED_NON_ASSET_GAP_IDS)
        and metrics["root_new_unexpected_gap_count"] == 0
        and metrics["max_new_unexpected_gap_count_across_resolutions"] <= 2
        and metrics["root_post_planform_solve_component_count"] >= 4
        and metrics["root_post_coast_smoothing_land_fraction"] >= 0.25
    )
    return _result(
        "P103.planform_repair_progress",
        passed,
        metrics,
        "P103 failed to clear at least one P101 planform residual without introducing unowned current-world gaps",
    )


def run_p103_bench(root: Path = PROJECT_ROOT,
                   outdir: Path | None = None) -> dict[str, Any]:
    del root, outdir
    packets = reference_evidence_packet_summary()
    packet_digest = _canonical_digest(packets)
    rows = _p103_planform_repair_rows()
    benchmarks = [
        _bench_p103_reference_land_floor_guard(rows, packets),
        _bench_p103_planform_repair_progress(rows),
    ]
    passed = all(b["passed"] for b in benchmarks)
    digest = _canonical_digest({
        "benchmarks": benchmarks,
        "planform_rows": rows,
        "reference_evidence_packets_digest": packet_digest,
    })
    root_row = next(row for row in rows if int(row["cells"]) == 900)
    return {
        "schema": "aevum.tectonics_bench.p103.v1",
        "suite": "P103",
        "status": "pass" if passed else "fail",
        "phase": "Phase 2. Planform Mechanism Repair",
        "benchmarks": benchmarks,
        "planform_repair_rows": rows,
        "reference_evidence_packets_digest": packet_digest,
        "determinism": {
            "summary_digest": digest,
            "passed": passed,
        },
        "acceptance": {
            "all_microbenchmarks_pass": passed,
            "reference_land_floor_guard": benchmarks[0]["passed"],
            "planform_repair_progress": benchmarks[1]["passed"],
            "p102_reference_evidence_consumed": bool(
                packets["status"] == "reference_evidence_packets_ready"),
            "multi_resolution_audit_recorded": bool(
                {int(row["cells"]) for row in rows} == {900, 2500}),
            "land_fraction_residual_cleared": bool(
                "planform.land_fraction_out_of_envelope"
                not in root_row["non_asset_gap_ids"]),
            "no_new_root_unexpected_gaps": bool(
                len(root_row["new_unexpected_gap_ids"]) == 0),
            "compiler_consistency_preserved": bool(
                all(row["compiler_passed_envelope"] for row in rows)),
            "phase2_remaining_planform_residuals_recorded": bool(
                root_row["planform_gap_count"] >= 1),
            "phase3_crust_sediment_interior_elevation_repair_pending": bool(
                root_row["crust_sediment_gap_count"] >= 1),
        },
    }


P104A_GENERATED_WORLD_SEEDS = (42, 31415, 16180)


def _p104a_current_mosaic_row(seed: int, cells: int = 900) -> dict[str, Any]:
    from aevum.engine import Engine

    spec = get_preset("earthlike")
    spec.seed = int(seed)
    spec.grid_cells = int(cells)
    spec.t_end_myr = 4500.0
    engine = Engine.build(spec)
    engine.run(n_frames=5)
    province_summary = generated_world_province_diversity_summary(engine.world)
    metrics = province_summary["metrics"]
    acceptance = province_summary["acceptance"]
    major_components = tuple(
        {
            "component_id": int(comp["component_id"]),
            "area_fraction": float(
                comp["area_fraction_of_exposed_continental_land"]),
            "province_class_count_gt2pct": int(
                comp["province_class_count_gt2pct"]),
            "largest_internal_province_fraction": float(
                comp["largest_internal_province_fraction"]),
            "basin_or_lowland_share": float(comp["basin_or_lowland_share"]),
            "active_highland_or_plateau_fraction": float(
                comp["active_highland_or_plateau_fraction"]),
            "unparented_highland_fraction_of_highlands": float(
                comp["unparented_highland_fraction_of_highlands"]),
        }
        for comp in province_summary["major_components"]
    )
    row = {
        "seed": int(seed),
        "cells": int(cells),
        "world_time_myr": float(engine.world.time_myr),
        "legacy_province_diversity_status": str(province_summary["status"]),
        "legacy_passive_margin_lowland_object_layer_present": bool(
            acceptance["passive_margin_lowland_object_layer_present"]),
        "legacy_generated_world_province_signal_present": bool(
            acceptance["generated_world_province_signal_present"]),
        "exposed_continental_land_fraction_of_world": float(
            metrics["exposed_continental_land_fraction_of_world"]),
        "component_count": int(metrics["component_count"]),
        "major_component_count": int(metrics["major_component_count"]),
        "detail_class_count_global_gt2pct": int(
            metrics["detail_class_count_global_gt2pct"]),
        "terrain_landform_kind_count": int(metrics["terrain_landform_kind_count"]),
        "terrain_landform_parent_process_count": int(
            metrics["terrain_landform_parent_process_count"]),
        "unparented_landform_object_count": int(
            metrics["unparented_landform_object_count"]),
        "min_province_class_count_per_major": int(
            metrics["min_province_class_count_per_major"]),
        "max_largest_internal_province_fraction": float(
            metrics["max_largest_internal_province_fraction"]),
        "min_basin_or_lowland_share_per_major": float(
            metrics["min_basin_or_lowland_share_per_major"]),
        "max_active_highland_or_plateau_fraction": float(
            metrics["max_active_highland_or_plateau_fraction"]),
        "max_unparented_highland_fraction": float(
            metrics["max_unparented_highland_fraction"]),
        "failing_major_component_count": int(
            metrics["failing_major_component_count"]),
        "p104a_detail_reclassified_area_fraction": float(
            engine.world.g("terrain.last_p104a_detail_reclassified_area_fraction", 0.0)),
        "p104a_surface_adjusted_area_fraction": float(
            engine.world.g("terrain.last_p104a_surface_adjusted_area_fraction", 0.0)),
        "p104a_platform_split_area_fraction": float(
            engine.world.g("terrain.last_p104a_platform_split_area_fraction", 0.0)),
        "p104a_mean_abs_surface_delta_m": float(
            engine.world.g("terrain.last_p104a_mean_abs_surface_delta_m", 0.0)),
        "p104a_detail_class_count_exposed_continental": int(
            engine.world.g("terrain.last_p104a_detail_class_count_exposed_continental", 0.0)),
        "p104a_province_class_count_exposed_continental": int(
            engine.world.g("terrain.last_p104a_province_class_count_exposed_continental", 0.0)),
        "p104a_exposed_continental_area_fraction": float(
            engine.world.g("terrain.last_p104a_exposed_continental_area_fraction", 0.0)),
        "major_component_brief": major_components,
    }
    row["p104a_interior_mosaic_pass"] = bool(
        row["exposed_continental_land_fraction_of_world"] >= 0.20
        and row["major_component_count"] >= 1
        and row["failing_major_component_count"] == 0
        and row["min_province_class_count_per_major"] >= 3
        and row["max_largest_internal_province_fraction"] <= 0.74
        and row["min_basin_or_lowland_share_per_major"] >= 0.18
        and row["max_active_highland_or_plateau_fraction"] <= 0.45
        and row["max_unparented_highland_fraction"] <= 0.15
        and row["detail_class_count_global_gt2pct"] >= 5
        and row["p104a_detail_class_count_exposed_continental"] >= 5
        and row["p104a_province_class_count_exposed_continental"] >= 6
        and row["p104a_detail_reclassified_area_fraction"] >= 0.05
        and row["p104a_surface_adjusted_area_fraction"] >= 0.10
        and 50.0 <= row["p104a_mean_abs_surface_delta_m"] <= 450.0
    )
    return row


def _p104a_generated_world_mosaic_rows() -> tuple[dict[str, Any], ...]:
    return tuple(
        _p104a_current_mosaic_row(seed, cells=900)
        for seed in P104A_GENERATED_WORLD_SEEDS
    )


def _bench_p104a_generated_world_continental_mosaic_gate(
    rows: tuple[dict[str, Any], ...],
) -> dict[str, Any]:
    metrics = {
        "seed_count": int(len(rows)),
        "seeds_checked": tuple(int(row["seed"]) for row in rows),
        "cells_checked": tuple(sorted({int(row["cells"]) for row in rows})),
        "all_rows_p104a_interior_mosaic_pass": bool(
            all(row["p104a_interior_mosaic_pass"] for row in rows)),
        "min_major_component_count": int(
            min(row["major_component_count"] for row in rows)),
        "min_detail_class_count_global_gt2pct": int(
            min(row["detail_class_count_global_gt2pct"] for row in rows)),
        "min_p104a_detail_class_count_exposed_continental": int(
            min(row["p104a_detail_class_count_exposed_continental"] for row in rows)),
        "min_p104a_province_class_count_exposed_continental": int(
            min(row["p104a_province_class_count_exposed_continental"] for row in rows)),
        "min_province_class_count_per_major": int(
            min(row["min_province_class_count_per_major"] for row in rows)),
        "max_largest_internal_province_fraction": float(
            max(row["max_largest_internal_province_fraction"] for row in rows)),
        "min_basin_or_lowland_share_per_major": float(
            min(row["min_basin_or_lowland_share_per_major"] for row in rows)),
        "max_active_highland_or_plateau_fraction": float(
            max(row["max_active_highland_or_plateau_fraction"] for row in rows)),
        "max_unparented_highland_fraction": float(
            max(row["max_unparented_highland_fraction"] for row in rows)),
        "max_failing_major_component_count": int(
            max(row["failing_major_component_count"] for row in rows)),
        "min_p104a_detail_reclassified_area_fraction": float(
            min(row["p104a_detail_reclassified_area_fraction"] for row in rows)),
        "min_p104a_surface_adjusted_area_fraction": float(
            min(row["p104a_surface_adjusted_area_fraction"] for row in rows)),
        "max_p104a_mean_abs_surface_delta_m": float(
            max(row["p104a_mean_abs_surface_delta_m"] for row in rows)),
        "legacy_statuses": tuple(
            str(row["legacy_province_diversity_status"]) for row in rows),
    }
    passed = bool(
        metrics["seed_count"] >= 3
        and set(metrics["seeds_checked"]) == set(P104A_GENERATED_WORLD_SEEDS)
        and metrics["cells_checked"] == (900,)
        and metrics["all_rows_p104a_interior_mosaic_pass"]
        and metrics["min_major_component_count"] >= 1
        and metrics["min_detail_class_count_global_gt2pct"] >= 5
        and metrics["min_p104a_detail_class_count_exposed_continental"] >= 5
        and metrics["min_p104a_province_class_count_exposed_continental"] >= 6
        and metrics["min_province_class_count_per_major"] >= 3
        and metrics["max_largest_internal_province_fraction"] <= 0.74
        and metrics["min_basin_or_lowland_share_per_major"] >= 0.18
        and metrics["max_active_highland_or_plateau_fraction"] <= 0.45
        and metrics["max_unparented_highland_fraction"] <= 0.15
        and metrics["max_failing_major_component_count"] == 0
        and metrics["min_p104a_detail_reclassified_area_fraction"] >= 0.05
        and metrics["min_p104a_surface_adjusted_area_fraction"] >= 0.10
        and metrics["max_p104a_mean_abs_surface_delta_m"] <= 450.0
    )
    return _result(
        "P104A.generated_world_continental_mosaic_gate",
        passed,
        metrics,
        "P104A failed to express multiple process-parented internal province classes on generated Earth-like continents",
    )


def _bench_p104a_legacy_gate_separation(
    rows: tuple[dict[str, Any], ...],
) -> dict[str, Any]:
    p104a_passes = tuple(bool(row["p104a_interior_mosaic_pass"]) for row in rows)
    legacy_ready = tuple(
        row["legacy_province_diversity_status"] == "generated_world_gate_ready"
        for row in rows
    )
    metrics = {
        "seeds_checked": tuple(int(row["seed"]) for row in rows),
        "p104a_pass_count": int(sum(p104a_passes)),
        "legacy_ready_count": int(sum(legacy_ready)),
        "legacy_passive_margin_lowland_present_count": int(sum(
            bool(row["legacy_passive_margin_lowland_object_layer_present"])
            for row in rows
        )),
        "legacy_generated_world_province_signal_present_count": int(sum(
            bool(row["legacy_generated_world_province_signal_present"])
            for row in rows
        )),
    }
    passed = bool(
        metrics["p104a_pass_count"] == len(rows)
        and metrics["legacy_generated_world_province_signal_present_count"] == len(rows)
    )
    return _result(
        "P104A.legacy_gate_separation",
        passed,
        metrics,
        "P104A failed to separate internal continental mosaic acceptance from older passive-margin object acceptance",
    )


def run_p104a_bench(root: Path = PROJECT_ROOT,
                    outdir: Path | None = None) -> dict[str, Any]:
    del root, outdir
    rows = _p104a_generated_world_mosaic_rows()
    benchmarks = [
        _bench_p104a_generated_world_continental_mosaic_gate(rows),
        _bench_p104a_legacy_gate_separation(rows),
    ]
    passed = all(b["passed"] for b in benchmarks)
    digest = _canonical_digest({
        "benchmarks": benchmarks,
        "mosaic_rows": rows,
    })
    return {
        "schema": "aevum.tectonics_bench.p104a.v1",
        "suite": "P104A",
        "status": "pass" if passed else "fail",
        "phase": "Phase 3. Continental Province Object Expression",
        "benchmarks": benchmarks,
        "generated_world_continental_mosaic_rows": rows,
        "determinism": {
            "summary_digest": digest,
            "passed": passed,
        },
        "acceptance": {
            "all_microbenchmarks_pass": passed,
            "generated_world_continental_mosaic_gate": benchmarks[0]["passed"],
            "legacy_gate_separation": benchmarks[1]["passed"],
            "multi_seed_generated_world_audit_recorded": bool(
                {int(row["seed"]) for row in rows} == set(P104A_GENERATED_WORLD_SEEDS)),
            "per_major_component_internal_mosaic_pass": bool(
                all(row["p104a_interior_mosaic_pass"] for row in rows)),
            "legacy_passive_margin_object_gate_not_required_for_p104a": True,
            "p104b_crust_sediment_interior_elevation_repair_pending": False,
            "p104c_internal_geographic_block_initialization_pending": False,
        },
    }


