def main(argv: list[str] | None = None) -> None:
    parser = argparse.ArgumentParser(
        prog="python -m aevum.diagnostics.tectonics_bench",
        description="Run tectonics refactor microbenchmarks.",
    )
    parser.add_argument("--suite", default="R0", help="benchmark suite to run")
    parser.add_argument("--out", default=None, help="output directory")
    args = parser.parse_args(argv)
    outdir = None if args.out is None else Path(args.out)
    summary = run_suite(args.suite, outdir)
    print("== aevum :: tectonics bench ==")
    print(f"   suite: {summary['suite']}")
    print(f"   status: {summary['status']}")
    if summary["suite"] == "R0":
        inv = summary["randomness_inventory"]
